        $translatePartialLoader.useStaticFilesLoader({
            prefix: 'static/assets/validation-json/',
            suffix: '.json'
        });

        // load English ('en') table on startup
        $translatePartialLoader.preferredLanguage('en').fallbackLanguage('en');
