    App.run(['$rootScope', '$state', '$stateParams', function ($rootScope, $state, $stateParams) {
        $rootScope.$state = $state;
        $rootScope.$stateParams = $stateParams;

        function redirectUser(fromState, fromParams) {
            if (!fromState || !fromState.name) {
                // get default landing page and redirect to it
                var state = $rootScope.Auth.principal.userStates.values();
                return $state.go(state.next().value);
            }
            return $state.go(fromState.name, fromParams); // check from state and redirect to it
        }

        function checkIfUserHasAccess(toState) {
            if (!$rootScope.Auth.principal || !$rootScope.Auth.principal.userStates) {
                return true;
            }
            // checks whether the user's role has access to state
            return $rootScope.Auth.principal.userStates.has(toState.name);
        }

        $rootScope.$on('$stateChangeStart', function (event, toState, toParams, fromState, fromParams) {
            if (!checkIfUserHasAccess(toState)) {
                event.preventDefault();
                redirectUser(fromState, fromParams);
            }
        });

    }])

    // Tooltips and Popovers configuration
