(function () {
    'use strict';
    var App = angular.module('app');

    App.controller('exemptionsCtrl', exemptionsCtrl);
    exemptionsCtrl.$inject = ['$scope', '$timeout', '$rootScope', 'studentService', 'remoteServices', 'ValidationService', 'commonService'];

    function exemptionsCtrl($scope, $timeout, $rootScope, studentService, remoteServices, ValidationService, commonService) {
        $scope.search = {};

        var rollNumber = $rootScope.Auth.tokenParsed.preferred_username.toUpperCase();
        if (!rollNumber) {
            showFailureNotification("State Failed To Load !")
        }

        $scope.$validationOptions = {
            debounce: 1500,
            preValidateFormElements: false,
            isolatedScope: $scope,
        };

        let statusEnum = {
            NV: "Not Verified",
            PV: "Partially Verified",
            V: "Verified",
            R: "Rejected",
            W: "Withdrawn"
        };

        getExemptions(rollNumber);

        function getExemptions(rollNumber) {
            $scope.showLoader = true;
            remoteServices.getExemptions(rollNumber, function (error, data) {
                if (error) {
                    $scope.showLoader = false;
                    $scope.showFailureNotification("Failed to fetch exemptions");
                    return;
                }
                data.map(function (exemption) {
                    exemption.displayStatus = statusEnum[exemption.status] || exemption.status;
                    exemption.displaySessions = exemption.sessions ? exemption.sessions.join(" , ") : null;
                });
                $scope.exemptions = data;
                $scope.showLoader = false;
            });
        }

        $scope.triggerDropzoneUpload = function (certificate) {
            var dropZone = $('.dropzone-click' + certificate).get(0).dropzone;
            dropZone.hiddenFileInput.click();
        };

        $scope.removeFile = function (section) {
            $scope.exemptionForm.$dirty = true;
            delete $scope.recordToUpdate.trainingProgram[section];
        }

        $scope.certificate = {
            dzOptions: {
                url: "#",
                method: "get",
                parallelUploads: 1,
                acceptedFiles: 'application/pdf',
                autoProcessQueue: true,
                maxFilesize: 10,
                maxFiles: 1,
                uploadMultiple: false,
                paramName: function () {
                    return "certificate";
                },
                maxfilesexceeded: function (file) {
                    this.removeAllFiles();
                    this.addFile(file);
                },
                init: function () {
                    $scope.myDropzone = this;
                    this.on("addedfile", function (file) {
                    });
                },
                params: $scope.studentRecord,
                renameFile: function (file) {
                    file.upload.filename = file.name;
                },
                headers: {
                    Authorization: "Bearer " + $rootScope.Auth.token
                },
                accept: function (file) {
                    $('.dropzone-clickcertificate').parent().parent().parent().find('.upload-image-custom-error').hide();
                    $scope.certificateUploadLoader = true;
                    $scope.uploadFileToS3(file, "certificate", function (uploadErr, uploadRes) {
                        $scope.certificateUploadLoader = false;
                        if (!uploadErr) {
                            $scope.setCertificateQuery(uploadRes, "certificate");
                            $scope.getCertUrl($scope.uploadedDetails, "certificate");
                            $scope.exemptionForm.$dirty = true;

                        } else {
                            $('.dropzone-clickcertificate').parent().parent().parent().find('.upload-image-custom-error').show();
                        }
                    });
                }
            },
            dzCallbacks: {
                init: function () {
                    this.on("addedfile", function (file) {
                        alert('Added file.');
                    });
                },
                "error": function (file, response) {  // and then can you have your error callback
                    $('.dropzone-clickcertificate').parent().parent().parent().find('.upload-image-custom-error').show();
                    $timeout(function () {
                        $('.dropzone-clickcertificate').parent().parent().parent().find('.upload-image-custom-error').hide();
                    }, 5000);
                },
                "success": function (file, xhr) {
                    $('.dropzone-clickcertificate').parent().parent().parent().find('.upload-image-custom-error').hide();
                },
            },
            dzMethods: {}
        };

        $scope.uploadFileToS3 = function (file, type, callback) {
            var query = {
                batchYear: $scope.studentRecord.batchYear,
                fileName: file.name,
                type: type
            }

            studentService.getUploadUrl(query, function (err, res) {
                if (res && res.signedUrl) {
                    studentService.uploadFilesToS3(res.signedUrl, file, function (error, result) {
                        $scope.marksheetUploadLoader = false;
                        if (!error) {
                            file.signedRequest = res;
                            callback(null, file);
                            return;
                        } else {
                            callback(error, null);
                            return;
                        }
                    });
                } else {
                    callback("Not able to upload", null);
                    return;
                }
            });
        };

        $scope.setCertificateQuery = function (uploadRes, section) {
            $scope.uploadedDetails = {
                id: uploadRes.signedRequest.filePath,
                contentType: uploadRes.type,
                filename: uploadRes.signedRequest.fileName,
                originalname: uploadRes.name,
                size: uploadRes.size
            };

            if (!$scope.recordToUpdate) {
                $scope.recordToUpdate = {}
            }

            if (!$scope.recordToUpdate.trainingProgram) {
                $scope.recordToUpdate.trainingProgram = {}
            }

            if (!$scope.recordToUpdate.trainingProgram[section]) {
                $scope.recordToUpdate.trainingProgram[section] = $scope.uploadedDetails;
            }
        };

        $scope.getCertUrl = function (certificate, section) {
            var query = certificate;
            studentService.getDownloadUrl(query, function (err, res) {
                if (res && res.signedUrl) {
                    if (section == "certificate") {
                        $scope.certificateURL = new URL(res.signedUrl);
                    }
                }
            });
        };

        $scope.getFileFromS3 = function (file) {
            var query = file || {};

            studentService.getDownloadUrl(query, function (err, res) {
                if (res && res.signedUrl) {
                    studentService.getFileObjFromS3(res.signedUrl, function (err, res) {
                        if (res) {
                            const blob = new Blob([res], {
                                type: 'application/pdf'
                            });
                            var url = URL.createObjectURL(blob);
                            var newWindow = window.open(url, '_blank');
                            newWindow.document.title = file.originalname;
                        }
                    });
                } else {
                    return;
                }
            });
        }

        $scope.cancelExemption = function (id) {
            $scope.showLoader = true;
            remoteServices.cancelExemption(id, $rootScope.Auth.tokenParsed.preferred_username.toUpperCase(), function (error, response) {
                if (error) {
                    $scope.showLoader = false;
                    $scope.showFailureNotification(error.data.message);
                    return;
                }
                $scope.showLoader = false;
                $scope.showSuccessNotification("Exemption Withdrawn Successfully");
                getExemptions($rootScope.Auth.tokenParsed.preferred_username.toUpperCase());
            });
        }

        $scope.applyExemptionModal = function () {
            $('#exemptionModal').modal('show');
            remoteServices.getExemptionTypes(rollNumber, function (error, response) {
                if (error) {
                    $('#exemptionModal').modal('hide');
                    $scope.showFailureNotification(error.data.message);
                }
                $scope.exemptionTypes = response.map(function (exemption) {
                    return {
                        id: exemption._id,
                        exemptionType: exemption.exemptionType,
                        category: exemption.category
                    }
                })
            })
        }

        $scope.fromDateOpts = {
            dateFormat: 'd-m-Y',
            onChange: function (selectedDates, dateStr, instance) {
                new flatpickr('#toDate', {
                    dateFormat: 'd-m-Y',
                    minDate: dateStr,
                    maxDate: 'today'
                });
            }
        };

        $scope.toDateOpts = {
            dateFormat: 'd-m-Y',
            onChange: function (selectedDates, dateStr, instance) {
                new flatpickr('#fromDate', {
                    dateFormat: 'd-m-Y',
                    maxDate: dateStr,
                });
            }
        };


        $scope.showFailureNotification = function (message) {
            $scope.showMessage = message;
            $scope.saveFailure = true;
            $timeout(function () {
                $scope.saveFailure = false;
            }, 5000);
            $('#exemptionModal').modal('hide');
        };

        $scope.showSuccessNotification = function (message) {
            $scope.showMessage = message;
            $scope.saveSuccess = true;
            $timeout(function () {
                $scope.saveSuccess = false;
            }, 5000);
            $('#exemptionModal').modal('hide');
        };

        $scope.unsetFilters = function (fieldsToUnset) {
            fieldsToUnset.forEach(function (field) {
                delete $scope.search[field];
            });
            $timeout(function () {
                new ValidationService().resetForm($scope['exemptionForm']);
            }, 100)
        }

        $scope.createExemption = function () {
            if (new ValidationService().checkFormValidity($scope.exemptionForm)) {
                $scope.showLoader = true;
                var data = {
                    "exemption": {
                        "category": $scope.search.exemptionCategory,
                        "type": $scope.search.exemptionType.exemptionType,
                        "id": $scope.search.exemptionType.id
                    },
                    "date": {
                        "from": moment($scope.search.fromDate, 'DD-MM-YYYY').toDate(),
                        "to": moment($scope.search.toDate, 'DD-MM-YYYY').toDate()
                    },
                    "sessions": $scope.search.sessions,
                    "reason": $scope.search.reason,
                    "rollNumber": rollNumber
                }
                if ($scope.recordToUpdate) {
                    data.attachment = {
                        "url": $scope.recordToUpdate.trainingProgram.certificate.id,
                        "contentType": $scope.recordToUpdate.trainingProgram.certificate.contentType,
                        "originalName": $scope.recordToUpdate.trainingProgram.certificate.originalname
                    }
                }
                remoteServices.createExemption(data, function (error, response) {
                    if (error) {
                        $scope.showLoader = false;
                        $scope.showFailureNotification(error.data.message);
                        return;
                    }
                    $scope.showLoader = false;
                    getExemptions(rollNumber);
                    $scope.showSuccessNotification("Exemption Applied Successfully");
                })
            }
        }
        $scope.formatTo12Hour = function (time) {
            var [hour, minute] = time.split(':');
            var hourInt = parseInt(hour, 10);
            var ampm = hourInt >= 12 ? 'PM' : 'AM';
            var hour12 = hourInt % 12 || 12; // Convert 0 to 12 for 12 AM and 12 PM
            return `${hour12}:${minute} ${ampm}`;
        };

        $scope.disableToDate = false;

        $scope.onCategoryChange = function () {
            if ($scope.search.exemptionCategory == 'Session') {
                $scope.search.toDate = $scope.search.fromDate;
                $scope.disableToDate = true;

                remoteServices.getExemptionTypeSessions(rollNumber, function (error, response) {
                    if (error) {
                        commonService.showErrorMessage($scope, "errorMsg", "errorMessage", error);
                    }
                    $scope.sessions = response.map(function (session) {
                        var startFormatted = $scope.formatTo12Hour(session.start);
                        var endFormatted = $scope.formatTo12Hour(session.end);
                        var timeRange = `${startFormatted} - ${endFormatted}`;

                        return {timeRange, session: session.session};
                    });
                });
            } else {
                $scope.disableToDate = false;
            }
        };

    }
})();;
(function () {
    'use strict';
    var App = angular.module('app');
    App.controller('enrollmentCtrl', enrollmentCtrl);
    enrollmentCtrl.$inject = ['$scope', '$state', '$stateParams', '$window', '$timeout', '$rootScope', 'ValidationService', 'remoteServices', 'studentService']
    function enrollmentCtrl($scope, $state, $stateParams, $window, $timeout, $rootScope, ValidationService, remoteServices, studentService) {

        $scope.showLoader = false;
        $scope.saveFailure = false;
        var rollNumber = $rootScope.Auth.principal.preferred_username.toUpperCase();
        $scope.enrollment = {};

        if ($rootScope.failureMessage) {
            showFailureNotification($rootScope.failureMessage);
            delete $rootScope.failureMessage;
        }

        function setUpEnrollment() {
            studentService.getStudentById(rollNumber, function (err, res) {
                $scope.showLoader = true;
                if (!err && res) {
                    $scope.studentDetails = res;
                    remoteServices.getEnrollments($scope.studentDetails._id, $scope.studentDetails.nodeId, function (err, res) {

                        if (!err && res) {
                            $scope.enrollments = res;
                            $scope.semesters = res.allSemesters;
                            $scope.showLoader = false;
                        } else if (!err && res == "") {
                            showFailureNotification("Can't get student enrollments!");
                            $scope.showLoader = false;
                        } else {
                            showFailureNotification("Can't get student enrollments!");
                            $scope.showLoader = false;
                        }
                    })
                } else {
                    showFailureNotification("Failed to get student Enrollments!");
                    $scope.showLoader = false;
                }
            })
        }

        setUpEnrollment();

        $scope.getSemesters = function () {
            var selectedSemester = $scope.enrollment.semesters;

            if (!selectedSemester) return;

            var enrolledCourseData = $scope.enrollments.enrolledCourses[0].enrolledCourse;

            var semesterData = enrolledCourseData.find(function (item) {
                return item.semester === selectedSemester;
            });

            if (semesterData && semesterData.courses) {
                $scope.filteredCourses = semesterData.courses;
            }
        };

        $scope.goToCoursePlan = function (course, faculty) {
            var prgmId = $scope.enrollments.enrolledCourses[0].prgmId;
            var sectionId = $scope.enrollments.enrolledCourses[0].sectionId;
            var batchId = $scope.enrollments.enrolledCourses[0].batchId;

            $state.go('viewCoursePlan', {
                courseId: course.courseId,
                prgmId: prgmId,
                sectionId: sectionId,
                batchId: batchId,
                courseTitle: course.courseTitle,
                courseCode: course.courseCode,
                facultyId: faculty.id,
                facultyName: faculty.name
            });
        };

        function showFailureNotification(message) {
            $scope.failureMessage = message;
            $scope.saveFailure = true;
            $timeout(function () {
                $scope.saveFailure = false;
            }, 5000);
        };
    }
})();;
