(function () {
    'use strict';
    var App = angular.module('app');

    App.controller('studentHallTicketController', studentHallTicketController);
    studentHallTicketController.$inject = ['$scope', '$rootScope', 'hallTicketServices', '$timeout', '$sce', 'studentService'];

    function studentHallTicketController($scope, $rootScope, hallTicketServices, $timeout, $sce, studentService) {

        $scope.studentRecord = {};
        $scope.showHallTicket = false;
        var rollNumber = ($rootScope.Auth.principal.preferred_username).toUpperCase();

        function getActiveExams() {
            $scope.pageLoader = true;
            $scope.examNames = [];
            hallTicketServices.getActiveExams(rollNumber, function (err, examNames) {
                $scope.pageLoader = false;
                if (!err && examNames) {
                    $scope.examNames = examNames;
                } else if (err && err.data && err.data.message) {
                    showFailureNotification(err.data.message);
                } else {
                    showFailureNotification("Failed to fetch hall ticket released exams");
                }
            });
        }

        getActiveExams();

        function clearNotification() {
            $scope.saveFailure = false;
            $scope.saveSuccess = false;
        }

        //get student detail
        function getStudentRecord() {
            $scope.studentRecord = {};
            studentService.getStudentById(rollNumber, function (err, response) {
                if (!err) {
                    $scope.studentRecord = response;
                }
            });
        }

        getStudentRecord();

        $scope.getHallTicketDetails = function () {
            $scope.pageLoader = true;
            $scope.showHallTicket = false;
            $scope.examStudent = {};
            hallTicketServices.getHallTicketDetails($scope.examName, rollNumber, function (err, sres) {
                $scope.pageLoader = false;
                if (!err && sres && sres.enrollments) {
                    if (Array.isArray(sres.enrollments) && sres.enrollments.length) {
                        $scope.examStudent = sres;
                        $scope.showHallTicket = true;
                    }
                } else if (err && err.data && err.data.message) {
                    showFailureNotification(err.data.message);
                } else {
                    showFailureNotification("Failed to fetch hall ticket details or no enrollments found.");
                }
            });
        }

        $scope.downloadHallTicket = function (rollNumber) {
            clearNotification();
            $scope.pageLoader = true;
            hallTicketServices.downloadHallTicket($scope.examName, rollNumber, function (err, res) {
                if (res && res.signedUrl) {
                    studentService.getFileObjFromS3(res.signedUrl, function (err, data) {
                        $scope.pageLoader = false;
                        if (data) {
                            const blob = new Blob([data], {
                                type: 'application/pdf'
                            });
                            $rootScope.saveBlob(blob, res.fileName || `${rollNumber}_hallticket.pdf`);
                            showSuccessNotification("Successfully downloaded the hall ticket.");
                        } else {
                            showFailureNotification("Failed to download hall ticket. Try again later");
                        }
                    });
                } else if (res && typeof res === 'string' && res.includes('<')) {
                    var printWindow = window.open('', '_blank', 'width=1280,height=786,scrollbars=no,menubar=no,toolbar=no,location=no,status=no,titlebar=no');
                    printWindow.document.open();
                    printWindow.document.write(res);
                    printWindow.document.close();

                    $timeout(function () {
                        printWindow.print();
                        $scope.pageLoader = false;
                    }, 5000);
                } else {
                    $scope.pageLoader = false;
                    if (err && err.data && err.data.message) {
                        showFailureNotification(err.data.message);
                    } else {
                        showFailureNotification("Failed to fetch hall ticket data. Try again later");
                    }
                }
            });
        }

        function showFailureNotification(message) {
            $scope.saveFailure = true;
            $scope.failureMessage = $sce.trustAsHtml(message);
            setTimeout(function () {
                $scope.saveFailure = false;
            }, 10000);
        }

        function showSuccessNotification(message) {
            $scope.successMessage = $sce.trustAsHtml(message);
            $scope.saveSuccess = true;
            $timeout(function () {
                $scope.saveSuccess = false;
            }, 5000);
        };

    }
})();
;
