(function () {
    "use strict"
    var App = angular.module('app');
    App.controller("feedbackListCtrl", feedbackListCtrl)

    feedbackListCtrl.$inject = ["$scope", "feedbackServices", "$timeout", "$rootScope", "$state"];

    function feedbackListCtrl($scope, feedbackServices, $timeout, $rootScope, $state) {

        function getEnums() {
            $scope.pageLoader = true;
            feedbackServices.getEnums(function (error, response) {
                $scope.pageLoader = false;
                if (!error && response) {
                    $scope.enum = response;
                    getFeedbackList();
                } else if (error && error.data && error.data.message) {
                    showFailureNotification(error.data.message);
                } else {
                    showFailureNotification("Failed to fetch feedback enums.Try again");
                }
            })
        }

        getEnums();

        function getFeedbackList() {
            $scope.pageLoader = true;
            feedbackServices.getFeedbackList(function (error, response) {
                $scope.pageLoader = false;
                if (!error && response) {
                    initDataTableWithValues(response);
                } else if (error && error.data && error.data.message) {
                    showFailureNotification(error.data.message);
                } else {
                    showFailureNotification("Failed to fetch feedback list.Try again");
                }
            })
        }

        var initDataTableWithValues = function (dataSet) {
            jQuery('.js-dataTable-full').DataTable({
                order: [],
                columnDefs: [
                    { orderable: false, targets: [3] }],
                destroy: true,
                data: dataSet,
                columns: [
                    { data: "feedbackName" },
                    { data: "about" },
                    { data: "course" },
                    {
                        data: "status", "render": function (data, type, row) {
                            if (type === "display") {
                                data = $scope.enum.SUBMISSIONS_DISPLAY_STATUS.descriptions[row.status]
                            }
                            return data;
                        }
                    },
                    { data:"closingDate" },
                    {
                        data: "action", "render": function (data, type, row) {
                            if (type === "display") {
                                if (row.status === $scope.enum.SUBMISSIONS_DISPLAY_STATUS.PENDING) {
                                    data = "<a class='proceedToFill btn btn-primary btn-sm mr-2 text-white'>Proceed To Fill</a>"
                                } else if (row.status === $scope.enum.SUBMISSIONS_DISPLAY_STATUS.EXPIRED) {
                                    data = "<span class='viewResponse btn btn-secondary btn-sm mr-2 text-white'>Expired</span>"
                                } else if (row.status === $scope.enum.SUBMISSIONS_DISPLAY_STATUS.SUBMITTED) {
                                    data = "<span class='viewResponse btn btn-success btn-sm mr-2 text-white'>Submitted</span>"
                                }
                            }
                            return data;
                        }
                    }
                ],
                pageLength: 15,
                lengthMenu: [[15, 25, 50, 100], [15, 25, 50, 100]]
            })
        }

        $('.js-dataTable-full').on('click', 'a.proceedToFill', function () {
            var data = $('.js-dataTable-full').DataTable().row($(this).parents('tr')).data();
            $state.go("proceedToFill", { "id": data._id });
        });

        function showFailureNotification(message) {
            $scope.saveFailure = true;
            $scope.failureMessage = message;
            $timeout(function () {
                $scope.saveFailure = false;
            }, 5000);
        }
    }

})()
;
(function () {
    "use strict"
    var App = angular.module('app');
    App.controller("proceedToFill", proceedToFill)

    proceedToFill.$inject = ["$scope", "feedbackServices", "$timeout", "$rootScope", "$stateParams", "$state"];
    function proceedToFill($scope, feedbackServices, $timeout, $rootScope, $stateParams, $state) {

        $scope.questionsAnswered = 0;

        function getFormToFill() {
            $scope.pageLoader = true;
            feedbackServices.getFormToFill($stateParams.id, function (error, response) {
                $scope.pageLoader = false;
                if (!error && response) {
                    $scope.form = response;
                } else if (error && error.data && error.data.message) {
                    $state.go("feedbackList");
                    showFetchFailureNotification(error.data.message);
                } else {
                    $state.go("feedbackList");
                    showFetchFailureNotification("Can't display your form.Kindly try again");
                }
            })
        }

        getEnums()

        function getEnums() {
            $scope.pageLoader = true;
            feedbackServices.getEnums(function (error, response) {
                $scope.pageLoader = false;
                if (!error && response) {
                    $scope.enum = response;
                    getFormToFill();
                } else if (error && error.data && error.data.message) {
                    showFailureNotification(error.data.message);
                } else {
                    showFailureNotification("Failed to fetch feedback list.Try again");
                }
            })
        }

        $scope.noOfCharacters = function (question) {
            question.answerLength = question.answer.replace(/[^a-zA-Z0-9]/g, " ").replace(/\s/g, "").length
        }

        $scope.validateResponse = function () {
            $scope.questionsAnswered = 0;
            $scope.response = { rating: {}, comments: {}, customOption: {} };
            $scope.unansweredRatingQuestions = [];
            $scope.unansweredCommentsQuestions = [];

            $scope.form.questions.forEach(function (question, index) {
                if (question.type == $scope.enum.QUESTION_TYPES.COMMENTS) {

                    if (!question.answer || question.answer.replace(/[^a-zA-Z0-9]/g, " ").replace(/\s/g, "").length < 30) {

                        $scope.unansweredCommentsQuestions.push(index + 1);

                    } else if (question.answer && question.answer.replace(/[^a-zA-Z0-9]/g, " ").replace(/\s/g, "").length >= 30) {
                        $scope.questionsAnswered++
                        $scope.response["comments"][question.no] = question.answer
                    };
                }
                if ((question.type === $scope.enum.QUESTION_TYPES.RATING || question.type === $scope.enum.QUESTION_TYPES.CUSTOM_OPTIONS)) {
                    if (!question.answer) {
                        $scope.unansweredRatingQuestions.push(index + 1);
                    } else {
                        $scope.questionsAnswered++;

                        if (question.type === $scope.enum.QUESTION_TYPES.RATING) {
                            $scope.response["rating"][question.no] = question.answer;
                        } else {
                            $scope.response["customOption"][question.no] = question.answer;
                        }
                    }
                }

            })
        }

        $scope.submit = function () {

            $scope.validateResponse()
            if ($scope.unansweredRatingQuestions.length && !$scope.unansweredCommentsQuestions.length) {
                showFailureNotification("Please  provide your rating for question(s) " + $scope.unansweredRatingQuestions);
                $("html, body").animate({
                    scrollTop: 0
                }, 500);
                return
            }

            if ($scope.unansweredCommentsQuestions.length && !$scope.unansweredRatingQuestions.length) {
                showFailureNotification("Please provide your comments for question(s) " + $scope.unansweredCommentsQuestions + " with minimum 30 characters");
                $("html, body").animate({
                    scrollTop: 0
                }, 500);
                return
            }

            if ($scope.unansweredRatingQuestions.length && $scope.unansweredCommentsQuestions.length) {
                showFailureNotification("Please  provide your rating for question(s) " + $scope.unansweredRatingQuestions + " and " + "comments for question(s) " + $scope.unansweredCommentsQuestions + " with minimum 30 characters");
                $("html, body").animate({
                    scrollTop: 0
                }, 500);
                return
            }

            $scope.pageLoader = true;
            feedbackServices.submit($scope.form._id, $scope.response, function (error, response) {
                $scope.pageLoader = false;
                if (!error && response) {
                    showSuccessNotification("Your response has been received successfully.");
                    $state.go("feedbackList");
                } else if (error && error.data && error.data.message) {
                    showFailureNotification(error.data.message);
                } else {
                    showFailureNotification("Can't submit feedback.Kindly try again.");
                }
                $("html, body").animate({
                    scrollTop: 0
                }, 500);
            });
        }

        function showFailureNotification(message) {
            $scope.saveFailure = true;
            $scope.failureMessage = message;
            $timeout(function () {
                $scope.saveFailure = false;
            }, 10000);
        }

        function showFetchFailureNotification(message) {
            $rootScope.fetchFailure = true;
            $rootScope.fetchFailureMsg = message;
            $timeout(function () {
                $rootScope.fetchFailure = false;
            }, 5000);
        }

        function showSuccessNotification(message) {
            $rootScope.submitSuccess = true
            $rootScope.submitSuccessMessage = message;
            $timeout(function () {
                $rootScope.submitSuccess = false;
            }, 5000);
        }
    }
})();
(function () {
    'use strict';
    var App = angular.module('app');

    App.controller('payMoreController', payMoreController);
    payMoreController.$inject = ['$scope', '$rootScope', '$state', '$stateParams', '$http', 'studentInvoiceService', '$timeout', '$window', 'breakdownPenality'];

    function payMoreController($scope, $rootScope, $state, $stateParams, $http, studentInvoiceService, $timeout, $window, breakdownPenality) {

        if (($rootScope.Auth.principal.preferred_username.toUpperCase() !== $stateParams.rollNumber)) {
            $state.go("newInvoiceList");
        }

        var feeId = $stateParams.feeId;
        var rollNumber = $stateParams.rollNumber;
        $scope.containerLoader = true;
        $scope.InvoiceData = {}

        // Defining ExamFee UI Model
        $scope.ExamFeeModel = {}
        $scope.ExamFeeModel.rollNumber;
        $scope.ExamFeeModel.UserChoice = {}
        $scope.ExamFeeModel.invoiceAppliedAtStudent = []
        $scope.ExamFeeModel.invoiceAppliedAtStudentOthers = []
        $scope.ExamFeeModel.invoiceAppliedAtEnrollment = {}
        $scope.ExamFeeModel.Penalty = []
        $scope.ExamFeeModel.choicesList = {}
        $scope.ExamFeeModel.CourseCodeTofeeHeadMap = {}
        $scope.ExamFeeModel.feeSummary = {}
        $scope.ExamFeeModel.paymentDetails = {}
        $scope.ExamFeeModel.dependentFeeHeadMap = {}
        $scope.ExamFeeModel.dependentFeeHeadEnabled = {}
        $scope.ExamFeeModel.paidDependentFeeHead = {}
        $scope.ExamFeeModel.totalFee = 0
        $scope.ExamFeeModel.generalFeeStatus = false
        $scope.ExamFeeModel.displayFeeSummary = false
        $scope.waiverField = "Waiver";

        $timeout(function () {
            if (rollNumber != $rootScope.Auth.principal.preferred_username.toUpperCase()) {
                rollNumber = $rootScope.Auth.principal.preferred_username.toUpperCase();
            }

            $scope.containerLoader = true;
            studentInvoiceService.getInvoiceToPayMore(rollNumber, feeId, function (err, response) {
                $scope.containerLoader = false;
                if (!err && response) {
                    $scope.InvoiceData = response;
                    if ($scope.getInvoiceRollNumber() != $rootScope.Auth.principal.preferred_username.toUpperCase()) {
                        $state.go("newInvoiceList")
                    }
                    if ($scope.InvoiceData.paymentInvoice) {
                        $scope.ExamFeeModel.displayFeeSummary = true
                        $scope.ExamFeeModel.rollNumber = $scope.InvoiceData.paymentInvoice.rollNumber
                        var penaltyFeeHeadIndex = $scope.InvoiceData.paymentInvoice.feeHeads.findIndex(function (item) {
                            return (item.type == "penalty");
                        });
                        if (penaltyFeeHeadIndex != -1) {
                            var breakdownFeeheads = breakdownPenality.transformPenaltyFeeheadToDisplay($scope.InvoiceData.paymentInvoice);
                            var waiverFeeheads = breakdownPenality.transformWaiverFeeheadToDisplay($scope.InvoiceData.paymentInvoice);

                            breakdownFeeheads = breakdownFeeheads.concat(waiverFeeheads);
                            $scope.ExamFeeModel.Penalty = breakdownFeeheads;

                        }
                    }
                    else {
                        $scope.ExamFeeModel.rollNumber = $scope.InvoiceData.paidInvoices[0].rollNumber
                    }
                    if (!$scope.InvoiceData.paymentInvoice || Object.keys($scope.InvoiceData.availableChoiceOptions).length == 0) {
                        if ($scope.InvoiceData.paidInvoices.length) { // already
                            $scope.noChoiceAvailable = "You have already paid for all applicable papers.";
                        }
                        else {
                            $scope.noChoiceAvailable = "No more papers to add. Please proceed to pay with the current fees."
                        }
                    }
                }
                else {
                    $scope.serverError = err.data.message;
                }
                ExamFeeUIModel();
            });
        }, 50);

        // To initialize UI Model with Invoice Data
        function ExamFeeUIModel() {

            // Checks whether the invoice has Already Paid FeeHeads and Enrollments
            if ('paidInvoices' in $scope.InvoiceData) {
                var paidCourseCodeList = []
                $scope.InvoiceData.paidInvoices.forEach(function (paidInvoice) {
                    paidInvoice.feeHeads.forEach(function (obj) {
                        // Checks whether a Paid FeeHead is applied to student
                        if (obj.applyPaymentTo == "student" && !obj.userChoiceEnabled && !obj.groupName) {
                            obj.paid = true
                            if (!$scope.ExamFeeModel.feeSummary["General Fees"]) {
                                $scope.ExamFeeModel.feeSummary["General Fees"] = 0
                                $scope.ExamFeeModel.generalFeeStatus = true
                            }
                            $scope.ExamFeeModel.invoiceAppliedAtStudent.push(obj);
                        } else if (obj.applyPaymentTo == "student" && !obj.userChoiceEnabled && obj.groupName) {
                            obj.paid = true
                            if (!$scope.ExamFeeModel.feeSummary["Other Fees"]) {
                                $scope.ExamFeeModel.feeSummary["Other Fees"] = 0
                            }
                            $scope.ExamFeeModel.invoiceAppliedAtStudentOthers.push(obj);
                        }
                        // Checks whether a Paid FeeHead is applied to enrollment
                        if (obj.applyPaymentTo == "enrollment") {
                            if (obj.enrollments) {
                                obj.paidEnrollments = obj.enrollments
                                obj.payable = 0
                                delete obj.enrollments
                            }
                            if (!$scope.ExamFeeModel.feeSummary[obj.groupName]) {
                                $scope.ExamFeeModel.feeSummary[obj.groupName] = 0
                            }
                            if (!$scope.ExamFeeModel.invoiceAppliedAtEnrollment[obj.groupName]) {
                                $scope.ExamFeeModel.invoiceAppliedAtEnrollment[obj.groupName] = []
                            }

                            $scope.ExamFeeModel.invoiceAppliedAtEnrollment[obj.groupName].forEach(function (parentItem, index) {
                                if (this[index].paidEnrollments) {
                                    this[index].paidEnrollments.forEach(function (newPaid) {
                                        if (!paidCourseCodeList.includes(newPaid.courseCode)) {
                                            paidCourseCodeList.push(newPaid.courseCode)
                                        }
                                    })
                                }
                            }, $scope.ExamFeeModel.invoiceAppliedAtEnrollment[obj.groupName])



                            var feeHeadExist = false
                            $scope.ExamFeeModel.invoiceAppliedAtEnrollment[obj.groupName].forEach(function (parentItem, index) {
                                if (parentItem.paidEnrollments && parentItem.name == obj.name) {
                                    feeHeadExist = true
                                    obj.paidEnrollments.forEach(function (item) {
                                        if (!paidCourseCodeList.includes(item.courseCode)) {
                                            $scope.ExamFeeModel.invoiceAppliedAtEnrollment[obj.groupName][index].paidEnrollments.push(item)
                                        }
                                    })
                                }
                            })

                            if (!feeHeadExist) {
                                $scope.ExamFeeModel.invoiceAppliedAtEnrollment[obj.groupName].push(obj)
                            }

                        }
                        if (obj.applyPaymentTo == "student" && obj.userChoiceEnabled) {
                            obj.paid = true
                            if (!$scope.ExamFeeModel.paidDependentFeeHead[obj.groupName]) {
                                $scope.ExamFeeModel.paidDependentFeeHead[obj.groupName] = []
                            }
                            $scope.ExamFeeModel.paidDependentFeeHead[obj.groupName].push(obj)
                        }
                    })
                })
            }
            if ('paymentInvoice' in $scope.InvoiceData) {
                $scope.InvoiceData.paymentInvoice.feeHeads.forEach(function (obj) {
                    // Checks whether a FeeHead is applied to student
                    if (obj.applyPaymentTo == "student" && !obj.userChoiceEnabled && !obj.groupName) {
                        obj.paid = false
                        $scope.ExamFeeModel.invoiceAppliedAtStudent.push(obj)
                        if (!$scope.ExamFeeModel.feeSummary["General Fees"]) {
                            $scope.ExamFeeModel.feeSummary["General Fees"] = 0
                            $scope.ExamFeeModel.generalFeeStatus = true
                        }
                        $scope.ExamFeeModel.feeSummary["General Fees"] += obj.payable
                    } else if (obj.applyPaymentTo == "student" && !obj.userChoiceEnabled && obj.groupName) {
                        obj.paid = false
                        $scope.ExamFeeModel.invoiceAppliedAtStudentOthers.push(obj)
                        if (!$scope.ExamFeeModel.feeSummary["Other Fees"]) {
                            $scope.ExamFeeModel.feeSummary["Other Fees"] = 0
                        }
                        $scope.ExamFeeModel.feeSummary["Other Fees"] += obj.payable
                    }
                    // Checks whether a FeeHead is applied to enrollment
                    if (obj.applyPaymentTo == "enrollment") {
                        var feeHeadStatus = false
                        if ($scope.ExamFeeModel.invoiceAppliedAtEnrollment[obj.groupName]) {
                            $scope.ExamFeeModel.invoiceAppliedAtEnrollment[obj.groupName].forEach(function (enrollmentFeeHead, parentIndex) {
                                if (obj.name == enrollmentFeeHead.name) {
                                    feeHeadStatus = true
                                    this[parentIndex].enrollments = obj.enrollments

                                    if (enrollmentFeeHead.dependentFeeHead) {
                                        if (enrollmentFeeHead.enrollments.length > 0) {
                                            addDependentFeeHeadIntoInvoice(obj.groupName, enrollmentFeeHead.dependentFeeHead, true)
                                            $scope.ExamFeeModel.feeSummary[obj.groupName] = $scope.getPayable(this, true)
                                        }
                                        else {
                                            addDependentFeeHeadIntoInvoice(obj.groupName, enrollmentFeeHead.dependentFeeHead)
                                            if ($scope.ExamFeeModel.dependentFeeHeadMap[obj.groupName] && $scope.ExamFeeModel.dependentFeeHeadMap[obj.groupName][enrollmentFeeHead.dependentFeeHead]) {
                                                $scope.ExamFeeModel.feeSummary[obj.groupName] = $scope.getPayable($scope.ExamFeeModel.invoiceAppliedAtEnrollment[obj.groupName], true)
                                            }
                                            else {
                                                $scope.ExamFeeModel.feeSummary[obj.groupName] = $scope.getPayable($scope.ExamFeeModel.invoiceAppliedAtEnrollment[obj.groupName], false)
                                            }
                                        }
                                    }
                                    else {
                                        $scope.ExamFeeModel.feeSummary[obj.groupName] = $scope.getPayable(this, false)
                                    }
                                }
                            }, $scope.ExamFeeModel.invoiceAppliedAtEnrollment[obj.groupName])

                            if (!feeHeadStatus) {

                                if (obj.dependentFeeHead) {
                                    if (obj.enrollments.length > 0) {
                                        addDependentFeeHeadIntoInvoice(obj.groupName, obj.dependentFeeHead, true)
                                        $scope.ExamFeeModel.invoiceAppliedAtEnrollment[obj.groupName].push(obj)
                                        $scope.ExamFeeModel.feeSummary[obj.groupName] = $scope.getPayable($scope.ExamFeeModel.invoiceAppliedAtEnrollment[obj.groupName], true)
                                    }
                                    else {
                                        addDependentFeeHeadIntoInvoice(obj.groupName, obj.dependentFeeHead)
                                        $scope.ExamFeeModel.invoiceAppliedAtEnrollment[obj.groupName].push(obj)
                                        if ($scope.ExamFeeModel.dependentFeeHeadMap[obj.groupName] && $scope.ExamFeeModel.dependentFeeHeadMap[obj.groupName][obj.dependentFeeHead]) {
                                            $scope.ExamFeeModel.feeSummary[obj.groupName] = $scope.getPayable($scope.ExamFeeModel.invoiceAppliedAtEnrollment[obj.groupName], true)
                                        }
                                        else {
                                            $scope.ExamFeeModel.feeSummary[obj.groupName] = $scope.getPayable($scope.ExamFeeModel.invoiceAppliedAtEnrollment[obj.groupName], false)
                                        }
                                    }
                                }
                                else {
                                    $scope.ExamFeeModel.invoiceAppliedAtEnrollment[obj.groupName].push(obj)
                                    $scope.ExamFeeModel.feeSummary[obj.groupName] = $scope.getPayable($scope.ExamFeeModel.invoiceAppliedAtEnrollment[obj.groupName], false)
                                }
                            }
                            addUserChoiceSelectReference(obj.groupName)
                        }
                        else {
                            $scope.ExamFeeModel.invoiceAppliedAtEnrollment[obj.groupName] = []
                            if (!$scope.ExamFeeModel.dependentFeeHeadMap[obj.groupName]) {
                                $scope.ExamFeeModel.dependentFeeHeadMap[obj.groupName] = {}
                            }
                            if (obj.dependentFeeHead) {
                                if (obj.enrollments.length > 0) {
                                    addDependentFeeHeadIntoInvoice(obj.groupName, obj.dependentFeeHead, true)
                                    $scope.ExamFeeModel.invoiceAppliedAtEnrollment[obj.groupName].push(obj)
                                    $scope.ExamFeeModel.feeSummary[obj.groupName] = $scope.getPayable($scope.ExamFeeModel.invoiceAppliedAtEnrollment[obj.groupName], true)
                                }
                                else {
                                    addDependentFeeHeadIntoInvoice(obj.groupName, obj.dependentFeeHead)
                                    $scope.ExamFeeModel.invoiceAppliedAtEnrollment[obj.groupName].push(obj)
                                    if ($scope.ExamFeeModel.dependentFeeHeadMap[obj.groupName] && $scope.ExamFeeModel.dependentFeeHeadMap[obj.groupName][obj.dependentFeeHead]) {
                                        $scope.ExamFeeModel.feeSummary[obj.groupName] = $scope.getPayable($scope.ExamFeeModel.invoiceAppliedAtEnrollment[obj.groupName], true)
                                    }
                                    else {
                                        $scope.ExamFeeModel.feeSummary[obj.groupName] = $scope.getPayable($scope.ExamFeeModel.invoiceAppliedAtEnrollment[obj.groupName], false)
                                    }
                                }

                            }
                            else {
                                $scope.ExamFeeModel.invoiceAppliedAtEnrollment[obj.groupName].push(obj)
                                $scope.ExamFeeModel.feeSummary[obj.groupName] = $scope.getPayable($scope.ExamFeeModel.invoiceAppliedAtEnrollment[obj.groupName], false)
                            }
                            addUserChoiceSelectReference(obj.groupName)
                        }
                    }
                })
            }

            if ($scope.ExamFeeModel.Penalty.length > 0) {
                if (!$scope.ExamFeeModel.feeSummary["Penalty"]) {
                    $scope.ExamFeeModel.feeSummary["Penalty"] = 0
                }
                $scope.ExamFeeModel.Penalty.forEach(function (item) {
                    if (item.isPenaltyFeeHead) {
                        $scope.ExamFeeModel.feeSummary.Penalty += item.amount;
                    } else {
                        $scope.ExamFeeModel.feeSummary[$scope.waiverField] = item.amount;
                    }
                })
            }

            // Checks whether the invoice has FeeHeads and Enrollments with UserChoice Options
            if ('availableChoiceOptions' in $scope.InvoiceData) {
                $scope.InvoiceData.paymentInvoice.feeHeads.forEach(function (obj) {
                    for (var feeHeadName in $scope.InvoiceData.availableChoiceOptions) {
                        if (obj.name == feeHeadName) {
                            if ($scope.InvoiceData.availableChoiceOptions[feeHeadName].choices && $scope.InvoiceData.availableChoiceOptions[feeHeadName].choices.length) {
                                $scope.InvoiceData.availableChoiceOptions[feeHeadName].choices.forEach(function (courseItem) {
                                    if (!$scope.ExamFeeModel.choicesList[obj.groupName]) {
                                        $scope.ExamFeeModel.choicesList[obj.groupName] = {
                                            "choices": []
                                        }
                                    }
                                    $scope.ExamFeeModel.choicesList[obj.groupName]["choices"].push(courseItem)
                                    $scope.ExamFeeModel.CourseCodeTofeeHeadMap[courseItem.courseCode] = feeHeadName
                                })
                            }
                            else if ($scope.InvoiceData.availableChoiceOptions[feeHeadName].apiEndpoint) {
                                if (!$scope.ExamFeeModel.choicesList[obj.groupName]) {
                                    $scope.ExamFeeModel.choicesList[obj.groupName] = {
                                        "choices": [],
                                        "apiEndpoint": $scope.InvoiceData.availableChoiceOptions[feeHeadName].apiEndpoint
                                    }
                                }
                            }
                        }
                    }
                })

            }
            $scope.computeTotal()
        }


        function addUserChoiceSelectReference(groupName) {
            $scope.ExamFeeModel.invoiceAppliedAtEnrollment[groupName].forEach(function (parentItem) {
                if (parentItem.enrollments && parentItem.userChoiceEnabled) {
                    parentItem.enrollments.forEach(function (childItem) {

                        if (!$scope.ExamFeeModel.UserChoice[groupName]) {
                            $scope.ExamFeeModel.UserChoice[groupName] = {}
                        }
                        if (!$scope.ExamFeeModel.UserChoice[groupName].selectRef) {
                            $scope.ExamFeeModel.UserChoice[groupName].selectRef = {}
                        }
                        if (!$scope.ExamFeeModel.UserChoice[groupName].selectRef[childItem.courseCode]) {
                            $scope.ExamFeeModel.UserChoice[groupName].selectRef[childItem.courseCode] = {}
                        }
                        $scope.ExamFeeModel.UserChoice[groupName].selectRef[childItem.courseCode].disabled = true
                    })
                }
            })
        }

        function addDependentFeeHeadIntoInvoice(groupName, dependentFeeHeadName, displayCondition) {
            $scope.InvoiceData.paymentInvoice.feeHeads.forEach(function (feeHead, index) {
                if (this[index].applyPaymentTo == "student" && dependentFeeHeadName == this[index].name && this[index].userChoiceEnabled) {
                    if (!(dependentFeeHeadName in $scope.ExamFeeModel.dependentFeeHeadMap[groupName])) {
                        if (!$scope.ExamFeeModel.dependentFeeHeadMap[groupName][dependentFeeHeadName]) {
                            $scope.ExamFeeModel.dependentFeeHeadMap[groupName][dependentFeeHeadName] = false
                        }
                    }
                    if (!$scope.ExamFeeModel.invoiceAppliedAtEnrollment[groupName].includes(feeHead)) {
                        $scope.ExamFeeModel.invoiceAppliedAtEnrollment[groupName].push(feeHead)
                    }
                    if (displayCondition) {
                        $scope.ExamFeeModel.dependentFeeHeadMap[groupName][dependentFeeHeadName] = true
                        if (!$scope.ExamFeeModel.dependentFeeHeadEnabled[groupName]) {
                            $scope.ExamFeeModel.dependentFeeHeadEnabled[groupName] = []
                        }
                        $scope.ExamFeeModel.invoiceAppliedAtEnrollment[groupName].forEach(function (item, childIndex) {
                            if (item.applyPaymentTo == "student" && dependentFeeHeadName == item.name && item.userChoiceEnabled) {
                                if (!$scope.ExamFeeModel.dependentFeeHeadEnabled[groupName].includes(item)) {
                                    $scope.ExamFeeModel.dependentFeeHeadEnabled[groupName].push(item)
                                }
                            }
                        }, $scope.ExamFeeModel.invoiceAppliedAtEnrollment[groupName])
                    }
                }
            }, $scope.InvoiceData.paymentInvoice.feeHeads)
        }

        $scope.getInvoiceRollNumber = function () {
            if ($scope.InvoiceData.paymentInvoice) {
                return $scope.InvoiceData.paymentInvoice.rollNumber
            }
            else if ($scope.InvoiceData.paidInvoices.length > 0) {
                return $scope.InvoiceData.paidInvoices[0].rollNumber
            }
        }

        $scope.backToInvoice = function (id) {
            $state.go("newInvoiceDetails", { "invoiceId": id })
        }

        // To Calculate Payable based on Enrollments
        $scope.getPayable = function (arr, dependentCondition) {
            var total = 0
            arr.forEach(function (item, index) {
                if (arr[index].enrollments) {
                    arr[index].payable = arr[index].enrollments.length * arr[index].amount
                    total += arr[index].payable
                }
                else {
                    // To Add DependentFeeHead Payable Only when Condition is passed
                    if (dependentCondition && arr[index].applyPaymentTo == "student") {
                        arr[index].payable = arr[index].amount
                        total += arr[index].payable
                    }
                }
                $scope.InvoiceData.paymentInvoice.feeHeads.forEach(function (feeHead, childIndex) {
                    if (arr[index].name == this[childIndex].name) {
                        this[childIndex].payable = arr[index].payable
                    }
                }, $scope.InvoiceData.paymentInvoice.feeHeads)
            })
            return total
        }

        // To Calculate TotalFee amount to be Paid based on available Feeheads and UserChoice Enrollments
        $scope.computeTotal = function () {
            $scope.ExamFeeModel.totalFee = 0
            for (var payable in $scope.ExamFeeModel.feeSummary) {
                if (payable === $scope.waiverField) {
                    $scope.ExamFeeModel.totalFee -= $scope.ExamFeeModel.feeSummary[payable];
                } else {
                    $scope.ExamFeeModel.totalFee += $scope.ExamFeeModel.feeSummary[payable]
                }
            }
        }

        // To Enable a programme (in UserChoice DropDown) from Disabled State when removed
        $scope.enableRemovedProgramme = function (programmeItem) {
            programmeItem.disabled = false;
        }

        // To Disable a programme (in UserChoice DropDown) when Selected
        $scope.disableSelectedProgramme = function (programmeItem) {
            programmeItem.disabled = true;
        }

        // To know the current Disable status of a UserChoice Enrollment for a FeeHead
        $scope.checkDisable = function (groupName, courseCode) {
            if (!$scope.ExamFeeModel.UserChoice[groupName]) {
                return false
            }
            if (!$scope.ExamFeeModel.UserChoice[groupName].selectRef) {
                return false
            }
            if (!$scope.ExamFeeModel.UserChoice[groupName].selectRef[courseCode]) {
                return false
            }
            return $scope.ExamFeeModel.UserChoice[groupName].selectRef[courseCode].disabled
        }

        // To check whether to display a DropDown for a particular feeHead
        $scope.checkDropDownDisplayStatus = function (groupName) {
            if ($scope.ExamFeeModel.choicesList) {
                if (!$scope.ExamFeeModel.choicesList[groupName]) {
                    return false
                }
                if (("apiEndpoint" in $scope.ExamFeeModel.choicesList[groupName]) || $scope.ExamFeeModel.choicesList[groupName]["choices"].length > 0) {
                    return true
                }
                else {
                    return false
                }
            }
        }

        // To add UserChoice Enrollments in the InvoiceDoc
        $scope.addUserChoiceIntoFee = function (groupName) {
            $scope.ExamFeeModel.UserChoice[groupName].selected.forEach(function (obj) {
                var feeHeadName = $scope.ExamFeeModel.CourseCodeTofeeHeadMap[obj.courseCode]
                $scope.ExamFeeModel.invoiceAppliedAtEnrollment[groupName].forEach(function (feeHead, parentIndex) {
                    if (feeHeadName == feeHead.name) {
                        $scope.ExamFeeModel.invoiceAppliedAtEnrollment[groupName][parentIndex].enrollments.push(obj)
                        addUserChoiceSelectReference(groupName)
                    }
                })

                $scope.ExamFeeModel.invoiceAppliedAtEnrollment[groupName].forEach(function (feeHead, parentIndex) {
                    if (feeHeadName == feeHead.name) {
                        if ($scope.ExamFeeModel.invoiceAppliedAtEnrollment[groupName][parentIndex].dependentFeeHead) {
                            if ($scope.ExamFeeModel.dependentFeeHeadMap[groupName]) {
                                $scope.ExamFeeModel.dependentFeeHeadMap[groupName][$scope.ExamFeeModel.invoiceAppliedAtEnrollment[groupName][parentIndex].dependentFeeHead] = true
                            }
                            if (!$scope.ExamFeeModel.dependentFeeHeadEnabled[groupName]) {
                                $scope.ExamFeeModel.dependentFeeHeadEnabled[groupName] = []
                            }
                            $scope.ExamFeeModel.invoiceAppliedAtEnrollment[groupName].forEach(function (item, index) {
                                if (item.applyPaymentTo == "student" && this[parentIndex].dependentFeeHead == item.name && item.userChoiceEnabled) {
                                    if (!$scope.ExamFeeModel.dependentFeeHeadEnabled[groupName].includes(item)) {
                                        $scope.ExamFeeModel.dependentFeeHeadEnabled[groupName].push(item)
                                    }
                                }
                            }, $scope.ExamFeeModel.invoiceAppliedAtEnrollment[groupName])
                        }
                    }
                })
            })
            if (!$scope.ExamFeeModel.feeSummary[groupName]) {
                $scope.ExamFeeModel.feeSummary[groupName] = 0
            }
            $scope.ExamFeeModel.feeSummary[groupName] = $scope.getPayable($scope.ExamFeeModel.invoiceAppliedAtEnrollment[groupName], true)
            $scope.computeTotal()
            $scope.ExamFeeModel.UserChoice[groupName].selected = []
        }

        // To remove UserChoice Enrollment from the InvoiceDoc
        $scope.RemoveUserChoiceFromFee = function (groupName, parentIndex, childIndex, courseCode) {
            var enrollment_length = 0
            $scope.ExamFeeModel.UserChoice[groupName].selectRef[courseCode].disabled = false
            $scope.ExamFeeModel.invoiceAppliedAtEnrollment[groupName][parentIndex].enrollments.splice(childIndex, 1)
            if ($scope.ExamFeeModel.invoiceAppliedAtEnrollment[groupName][parentIndex].dependentFeeHead) {
                var dependentFeeHeadName = $scope.ExamFeeModel.invoiceAppliedAtEnrollment[groupName][parentIndex].dependentFeeHead
                $scope.ExamFeeModel.invoiceAppliedAtEnrollment[groupName].forEach(function (obj, index) {
                    if (this[index].enrollments && this[index].dependentFeeHead == dependentFeeHeadName) {
                        enrollment_length += this[index].enrollments.length
                    }
                }, $scope.ExamFeeModel.invoiceAppliedAtEnrollment[groupName])
                if (enrollment_length == 0 && $scope.ExamFeeModel.dependentFeeHeadEnabled[groupName]) {
                    var dependentFeeHeadIndex = $scope.ExamFeeModel.dependentFeeHeadEnabled[groupName].findIndex(function (item) {
                        return (item.name == dependentFeeHeadName);
                    });
                    $scope.ExamFeeModel.dependentFeeHeadEnabled[groupName].splice(dependentFeeHeadIndex, 1)
                    dependentFeeHeadIndex = $scope.ExamFeeModel.invoiceAppliedAtEnrollment[groupName].findIndex(function (item) {
                        return (item.name == dependentFeeHeadName);
                    });
                    $scope.ExamFeeModel.invoiceAppliedAtEnrollment[groupName][dependentFeeHeadIndex].payable = 0
                    $scope.ExamFeeModel.feeSummary[groupName] = $scope.getPayable($scope.ExamFeeModel.invoiceAppliedAtEnrollment[groupName], false)
                }
                else {
                    $scope.ExamFeeModel.feeSummary[groupName] = $scope.getPayable($scope.ExamFeeModel.invoiceAppliedAtEnrollment[groupName], true)
                }
            }
            else {
                $scope.ExamFeeModel.feeSummary[groupName] = $scope.getPayable($scope.ExamFeeModel.invoiceAppliedAtEnrollment[groupName], false)
            }

            $scope.computeTotal()
            $scope.ExamFeeModel.UserChoice[groupName].selected = []
        }

        // To do a final validation for Dependent feeHead Amount
        $scope.feeHeadAmountValidation = function (feeHeads) {
            feeHeads.forEach(function (feeHead) {
                var enrollment_length = 0
                if (feeHead.dependentFeeHead && feeHead.enrollments && feeHead.enrollments.length == 0) {
                    var dependentFeeHeadIndex = $scope.InvoiceData.paymentInvoice.feeHeads.findIndex(function (item) {
                        return (item.name == feeHead.dependentFeeHead);
                    });
                    if (dependentFeeHeadIndex !== -1 && $scope.InvoiceData.paymentInvoice.feeHeads[dependentFeeHeadIndex].payable) {
                        $scope.InvoiceData.paymentInvoice.feeHeads.forEach(function (obj, index) {
                            if (this[index].enrollments && this[index].dependentFeeHead == feeHead.dependentFeeHead) {
                                enrollment_length += this[index].enrollments.length
                            }
                        }, $scope.InvoiceData.paymentInvoice.feeHeads)
                        if (enrollment_length == 0) {
                            $scope.InvoiceData.paymentInvoice.feeHeads[dependentFeeHeadIndex].payable = 0
                        }
                    }
                }
            })
        }


        // To Make Payment on the InvoiceDoc
        $scope.updateInvoiceWithFeeHeadChoices = function (id, feeId, rollNumber) {
            $scope.feeHeadAmountValidation($scope.InvoiceData.paymentInvoice.feeHeads);
            $scope.pageLoader = true;
            $scope.saveButton = true;
            $scope.ExamFeeModel.paymentDetails["_id"] = id
            $scope.ExamFeeModel.paymentDetails["paymentMode"] = "O"
            $scope.ExamFeeModel.paymentDetails["feeType"] = $scope.InvoiceData.paymentInvoice.feeType
            $scope.ExamFeeModel.paymentDetails["total"] = $scope.ExamFeeModel.totalFee

            $scope.InvoiceData.paymentInvoice.feeHeads.forEach(function (obj, parentIndex) {
                delete this[parentIndex].paid

                if (this[parentIndex].userChoiceEnabled && this[parentIndex].enrollments && this[parentIndex].enrollments.length > 0) {
                    this[parentIndex].enrollments.forEach(function (enrollment, childIndex) {
                        delete this[childIndex].disabled
                    }, this[parentIndex].enrollments)
                }
            }, $scope.InvoiceData.paymentInvoice.feeHeads)

            $scope.ExamFeeModel.paymentDetails["feeHeads"] = $scope.InvoiceData.paymentInvoice.feeHeads

            $scope.containerLoader = true;
            studentInvoiceService.updateInvoiceWithFeeHeadChoices(feeId, rollNumber, $scope.ExamFeeModel.paymentDetails, function (err, redirectUrl) {
                $scope.containerLoader = false;
                $scope.pageLoader = false;
                if (!err) {
                    $window.location.href = redirectUrl;
                } else {
                    $scope.saveButton = false;
                    $scope.serverError = err.data.message;
                }
            });
        }

        $scope.checkToLoadChoicesFromAPI = function (groupName) {
            if ($scope.ExamFeeModel.choicesList[groupName]) {
                if (!$scope.ExamFeeModel.choicesList[groupName]["choices"].length && $scope.ExamFeeModel.choicesList[groupName]["apiEndpoint"]) {
                    $scope.pageLoader = true;

                    var apiDetails = $scope.ExamFeeModel.choicesList[groupName]["apiEndpoint"];
                    var body = {};

                    if (apiDetails.body) {
                        Object.keys(apiDetails.body).forEach(function (key) {
                            if (apiDetails.body[key] == "$" + key) {
                                body[key] = $scope.InvoiceData.paymentInvoice[key]
                            }
                            else {
                                body[key] = apiDetails.body[key];
                            }
                        });

                        body["examId"] = $scope.InvoiceData.paymentInvoice["examId"];
                    }

                    $http[apiDetails.method.toLowerCase()](apiDetails.url, body).then(function (response) {
                        if (response && response.data) {
                            var enrollments = response.data[0].enrollments;
                            $scope.pageLoader = false;
                            if (groupName && $scope.ExamFeeModel.invoiceAppliedAtEnrollment[groupName]) {
                                $scope.ExamFeeModel.invoiceAppliedAtEnrollment[groupName].forEach(function (currentFeehead) {
                                    var paidEnrollmentsSet = new Set();
                                    if (currentFeehead.paidEnrollments) {
                                        currentFeehead.paidEnrollments.forEach(function (course) {
                                            paidEnrollmentsSet.add(course.courseCode)
                                        });
                                    }

                                    enrollments = enrollments.filter(function (course) {
                                        if (!paidEnrollmentsSet.has(course.courseCode)) {
                                            $scope.ExamFeeModel.CourseCodeTofeeHeadMap[course.courseCode] = currentFeehead.name;
                                            return true;
                                        }
                                    });
                                });

                            }
                        }
                        $scope.ExamFeeModel.choicesList[groupName].choices = enrollments;
                    }).catch(function (error) {
                        $scope.serverError = error.data.message;
                    });
                }
            }
        }
    }

})();
;
(function () {
    'use strict';
    var App = angular.module('app');

    App.filter('amountSplit', function () {
        return function (value) {
            if (!value) {
                return "0";
            }

            return value.toString().replace(/\B(?=(?:(\d\d)+(\d)(?!\d))+(?!\d))/g, ",");
        }
    });

    App.filter('statusName', function () {
        var filterValue;
        var invoice = {
            "D": "Draft",
            "P": "Pending",
            "PD": "Paid",
            "CL": "Cancelled",
            "L": "Locked",
            "O": "Overdue",
            "IP": "In-Progress",
        };
        return function (val) {
            angular.forEach(invoice, function (value, key) {
                if (key == val)
                    filterValue = invoice[val];
            })
            return filterValue;
        };
    })

    App.filter('paymentMode', function () {
        var filterValue;
        var paymentMode = {
            'O': "ONLINE",
            'C': "CASH",
            'DD': "DD"
        };
        return function (val) {
            angular.forEach(paymentMode, function (value, key) {
                if (key == val)
                    filterValue = paymentMode[val];
            })
            return filterValue;
        };
    });

    App.filter('refundStatusName', function () {
        var filterValue;
        var refundStatus = {
            "RR": 'Refund Requested',
            "RC": 'Refund Rejected',
            "RA": 'Refund Approved',
            "RI": 'Refund Initiated',
            "RD": 'Refunded'
        };
        return function (val) {
            angular.forEach(refundStatus, function (value, key) {
                if (key == val)
                    filterValue = refundStatus[val];
            })
            return filterValue;
        };
    });

    App.controller('manageInvoicesController', manageInvoicesController);
    manageInvoicesController.$inject = ['$scope', '$rootScope', '$state', 'studentInvoiceService', '$timeout', '$filter', 'numberToWords', 'breakdownPenality', 'previewInvoiceService', 'commonService', 'getRefundedFeeHeads', 'examFeeService'];

    function manageInvoicesController($scope, $rootScope, $state, studentInvoiceService, $timeout, $filter, numberToWords, breakdownPenality, previewInvoiceService, commonService, getRefundedFeeHeads, examFeeService) {
        $scope.rollNumber = $rootScope.Auth.principal.preferred_username.toUpperCase() || sessionStorage.rollNumber;
        $scope.invoices = [];
        $scope.transactions = [];
        $scope.headConcession = {};

        $scope.getInvoices = function (isConstructPaginationBar, search) {
            var option = $rootScope.calcSkipLimitValueForPagination(isConstructPaginationBar);
            option.skip = option.skipValue;
            option.limit = option.limitValue;
            option.sort = $scope.sorting;
            delete option.skipValue;
            delete option.limitValue;

            var criteria = {
                rollNumber: $scope.studentDetails.rollNumber,
                dummyRollNumber: $scope.studentDetails.dummyRollNumber
            };

            $scope.showLoader = true;
            studentInvoiceService.getAllInvoices(criteria, search, option, function (error, response) {
                $scope.showLoader = false;

                if (error) {
                    return commonService.showErrorMessage($scope, "errorMsg", "errorMsgContent", error);
                }

                $rootScope.paginationOptions.recordCountForFilter = '';
                $rootScope.paginationOptions.recordsTotal = '';

                var records = (response && response.records) ? response.records : [];

                $scope.invoices = records;

                $rootScope.paginationOptions.recordsTotal = response.recordLength;
                $rootScope.paginationOptions.recordCountForFilter = response.totalRecords;
                $scope.getPenaltyDetails($scope.invoices);

                if (isConstructPaginationBar) {
                    $rootScope.constructPaginationBar();
                }
            });
        }

        commonService.setDefaultSorting('invoiceNumber', -1);
        commonService.search();
        commonService.sorting();
        commonService.filters();
        commonService.pagination();
        commonService.checkbox();

        $timeout(function () {
            $rootScope.getData(true, $rootScope.filter, "");
        }, 100);

        $scope.searchFieldForm = function () {
            $timeout(function () {
                if ($rootScope.searchParams.searchField && $rootScope.searchParams.searchField.length > 1) {
                    $rootScope.getData(true, $rootScope.filter, $rootScope.searchParams.searchField);
                } else if (!$rootScope.searchParams.searchField || $rootScope.searchParams.searchField.length == 0) {
                    $rootScope.getData(true, $rootScope.filter, "");
                }
            }, 250)
        }

        $scope.gotoInvoicePaymentPage = function (id) {
            $state.go("newInvoiceDetails", { "invoiceId": id });
        }

        $scope.gotoInvoicePayMorePage = function (rollNumber, id) {
            $state.go("editInvoiceToPayMore", { "rollNumber": rollNumber, "feeId": id })
        }

        $scope.getInvoiceDetails = function (id) {
            $scope.showLoader = true;
            studentInvoiceService.allowAction(id, "printInvoice", function (error, response) {
                if (!error && !response) {
                    error = new Error("Print Invoice action is blocked");
                }

                if (error) {
                    $scope.showLoader = false;
                    return commonService.showErrorMessage($scope, "errorMsg", "errorMsgContent", error);
                }

                var criteria = {
                    rollNumber: $scope.studentDetails.rollNumber,
                    dummyRollNumber: $scope.studentDetails.dummyRollNumber
                };

                studentInvoiceService.getInvoice(id, criteria, function (error, response) {
                    $scope.showLoader = false;

                    if (!error && (!response || !response.invoiceDoc)) {
                        error = new Error("Invoice details not found");
                    }

                    if (!error) {
                        setupInvoiceForPrint(response);
                        printInvoice();
                    } else {
                        commonService.showErrorMessage($scope, "errorMsg", "errorMsgContent", error);
                    }
                });
            });
        };

        $scope.viewInvoice = function (id) {
            $scope.showLoader = true;
            studentInvoiceService.allowAction(id, "showInvoice", function (error, response) {
                $scope.showLoader = false;

                if (!error && !response) {
                    error = new Error("View Invoice action is blocked");
                }

                if (error) {
                    return commonService.showErrorMessage($scope, "errorMsg", "errorMsgContent", error);
                }

                $state.go("newInvoiceDetails", { "invoiceId": id });
            })
        };

        $scope.hoverPenaltyDetails = [];
        $scope.getPenaltyDetails = function (invoices) {
            for (var index = 0; index < invoices.length; index++) {
                var invoice = invoices[index];
                if (!invoice.penalties || !invoice.penalties.length) {
                    $scope.hoverPenaltyDetails[index] = "No Penalties";
                }

                var description = "";
                var fromDate = moment(invoice.dueDate).format("DD-MMM-YYYY");
                for (var penalty of invoice.penalties) {
                    var prefix = "";

                    switch (penalty.rule) {
                        case "PD":
                            prefix = "Daily fine of Rs.";
                            break;
                        case "PW":
                            prefix = "Weekly fine of Rs.";
                            break;
                        case "O":
                            prefix = "Fine of Rs.";
                            break;
                    }

                    const toDate = moment(penalty.till).format("DD-MMM-YYYY");
                    description += prefix + penalty.value + " from " + fromDate + " till " + toDate + "\n";
                    fromDate = moment(penalty.till).add(1, 'day').format("DD-MMM-YYYY");
                }

                $scope.hoverPenaltyDetails[index] = description;
            }
        }

        $rootScope.getData = function (isConstructPaginationBar, filter, search) {
            search = search ? search : $rootScope.searchParams.searchField;
            $scope.getInvoices(isConstructPaginationBar, search);
        };

        $scope.invoiceTemplateSetup = function (callback) {
            if ($scope.invoiceConfig && Object.keys($scope.invoiceConfig).length) {
                callback ? callback() : null;
                return;
            }

            $scope.invoiceConfig = {};

            studentInvoiceService.getInvoiceSettings(function (error, res) {
                if (error) {
                    return commonService.showErrorMessage($scope, 'errorMsg', 'errorMsgContent', error);
                }

                $scope.invoiceConfig = res.layout.body;

                callback ? callback() : null;
            }, true);
        };

        function setupInvoiceForPrint(response) {
            $scope.invoiceTemplateSetup(function () {
                $scope.printInvoiceList = response.invoiceDoc;
                $scope.invoiceFeeType = $scope.printInvoiceList.feeType;

                $scope.concessionMap = {};
                $scope.feeHeadView = $scope.invoiceConfig.feeHeads.options;
                $scope.concessionView = $scope.invoiceConfig.concessions.options;
                $scope.penaltiesView = $scope.invoiceConfig.penalty.options;

                $scope.totalFeeAmt = $scope.printInvoiceList.total;
                $scope.totalPenaltyAmt = 0;
                $scope.totalWaiveredAmt = 0;

                if ($scope.printInvoiceList.refund) {
                    $scope.invoiceRefundStatus = previewInvoiceService.isFullyRefunded($scope, $scope.printInvoiceList);
                    $scope.refunded = $scope.invoiceRefundStatus == "Partially Refunded" ? getRefundedFeeHeads.getApprovedRefundFeeHeads($scope.printInvoiceList) : {};
                }

                var penaltyFeeHeadIndex = $scope.printInvoiceList.feeHeads.findIndex(function (item) {
                    return (item.type == "penalty");
                });

                if (penaltyFeeHeadIndex != -1) {
                    var breakdownFeeheads = breakdownPenality.transformPenaltyFeeheadToDisplay($scope.printInvoiceList);
                    var waiverFeeheads = breakdownPenality.transformWaiverFeeheadToDisplay($scope.printInvoiceList);
                    $scope.printInvoiceList.feeHeads.splice(penaltyFeeHeadIndex, 1);
                    $scope.printInvoiceList.feeHeads = $scope.printInvoiceList.feeHeads.concat(breakdownFeeheads);
                    $scope.printInvoiceList.feeHeads = $scope.printInvoiceList.feeHeads.concat(waiverFeeheads);
                    $scope.penaltyView = true;

                    $scope.totalPenaltyAmt = breakdownFeeheads.reduce(function (total, feeHead) {
                        return total + feeHead.amount;
                    }, 0);

                    $scope.totalWaiveredAmt = waiverFeeheads.reduce(function (total, feeHead) {
                        return total + feeHead.amount;
                    }, 0);
                }

                if ($scope.invoiceConfig.concessions.enabled && ($scope.feeHeadView.FEE_NAME || $scope.feeHeadView.CUSTOM)) {
                    if ($scope.printInvoiceList.concessionValue) {
                        $scope.totalFeeAmt += $scope.printInvoiceList.concessionValue;
                    }
                }

                if ($scope.invoiceConfig.penalty.enabled && ($scope.feeHeadView.FEE_NAME || $scope.feeHeadView.CUSTOM)) {
                    $scope.totalFeeAmt -= ($scope.totalPenaltyAmt - $scope.totalWaiveredAmt);
                }

                if ($scope.invoiceFeeType == 'EXAM FEES') {
                    examFeeService.InvoiceUIModel($scope, $scope.printInvoiceList);
                } else if ($scope.invoiceFeeType != 'EXAM FEES') {
                    previewInvoiceService.setupConcessionForDisplay($scope, $scope.printInvoiceList.feeHeads);
                }

                $scope.printInvoiceList.feeHeads.forEach(function (feeHead) {
                    if (Array.isArray(feeHead.concessions) && feeHead.concessions.length) {
                        feeHead.concessions.forEach(function (concession) {
                            if (!$scope.concessionMap[concession.name]) {
                                $scope.concessionMap[concession.name] = 0;
                            }
                            $scope.concessionMap[concession.name] += concession.value || 0;
                        });
                    }
                });
            });
        }

        function printInvoice() {
            $timeout(function () {
                var innerContents = document.getElementById('printInvoiceForViewInvoice').innerHTML;
                var popupWinindow = window.open('', '_blank', 'width=600,height=700,scrollbars=no,menubar=no,toolbar=no,location=no,status=no,titlebar=no');
                popupWinindow.document.open();
                popupWinindow.document.write('<html><head><link rel="stylesheet" id="css-main" href="css/w2/components.css"><link rel="stylesheet" id="css-main" href="css/sis.css"><link rel="stylesheet" id="css-main" href="css/printReceipt.css"><link rel="stylesheet" id="css-bootstrap" href="bower_components/bootstrap/dist/css/bootstrap.min.css" /></head>');
                popupWinindow.document.write('<body onload="window.print()">');
                popupWinindow.document.write(innerContents);
                popupWinindow.document.write('</html>');
                popupWinindow.document.close();
            }, 50);
        }

        var a = ['', 'one ', 'two ', 'three ', 'four ', 'five ', 'six ', 'seven ', 'eight ', 'nine ', 'ten ', 'eleven ', 'twelve ', 'thirteen ', 'fourteen ', 'fifteen ', 'sixteen ', 'seventeen ', 'eighteen ', 'nineteen '];
        var b = ['', '', 'twenty', 'thirty', 'forty', 'fifty', 'sixty', 'seventy', 'eighty', 'ninety'];

        $scope.inWords = function (num) {
            num = Math.abs(num);
            if (num) {
                if ((num = num.toString()).length > 9) return 'overflow';
                var n = ('000000000' + num).substr(-9).match(/^(\d{2})(\d{2})(\d{2})(\d{1})(\d{2})$/);
                if (!n) return; var str = '';
                str += (n[1] != 0) ? (a[Number(n[1])] || b[n[1][0]] + ' ' + a[n[1][1]]) + 'crore ' : '';
                str += (n[2] != 0) ? (a[Number(n[2])] || b[n[2][0]] + ' ' + a[n[2][1]]) + 'lakh ' : '';
                str += (n[3] != 0) ? (a[Number(n[3])] || b[n[3][0]] + ' ' + a[n[3][1]]) + 'thousand ' : '';
                str += (n[4] != 0) ? (a[Number(n[4])] || b[n[4][0]] + ' ' + a[n[4][1]]) + 'hundred ' : '';
                str += (n[5] != 0) ? ((str != '') ? 'and ' : '') + (a[Number(n[5])] || b[n[5][0]] + ' ' + a[n[5][1]]) : '';
                return str;
            }
        }

        $scope.viewTransactionHistory = function (id) {
            var filter = {
                invoiceId: id
            };

            $scope.txnHistory = [];
            $scope.showLoader = true;
            studentInvoiceService.getTransactionsOfStudentInvoice(filter, function (error, response) {
                $scope.showLoader = false;
                if (!error) {
                    $scope.txnHistory = response || [];
                } else {
                    commonService.showErrorMessage($scope, "errorMsg", "errorMsgContent", error);
                }

                $("#transactionModal").modal('show');
            });
        }

        $scope.checkPayMoreCondition = function (currentRowInvoice) {
            if (currentRowInvoice.feeType != "EXAM FEES") {
                return false;
            }

            if (!currentRowInvoice.paymentModes.includes('O')) {
                return false;
            }

            if (currentRowInvoice.amount == 0 && !currentRowInvoice.isDeltaInvoice) {
                return true;
            }

            var latestInvoice = true, eligibleToPay = true;

            var currentFeeUnPaidInvoices = $scope.invoices.filter(function (invoice) {
                if (!eligibleToPay || (invoice.feeId != currentRowInvoice.feeId)) {
                    return false;
                }

                eligibleToPay = (invoice.status != "L");

                if (new Date(invoice.createdDate) > new Date(currentRowInvoice.createdDate)) {
                    latestInvoice = false;
                }

                return ["P", "IP"].includes(invoice.status);
            });

            return (!currentFeeUnPaidInvoices.length && latestInvoice && eligibleToPay);
        }

        $rootScope.convertNumberToWords = function (amount) {
            return numberToWords.convertNumberToWords(amount);
        }

        // Default to card view
        if (!sessionStorage.isCardView) {
            sessionStorage.isCardView = true;
        }

        $scope.isCardView = JSON.parse(sessionStorage.isCardView);

        // Function to toggle between views
        $scope.toggleView = function (view) {
            $scope.isCardView = (view === 'card');
            sessionStorage.isCardView = (view === 'card');
        }
    }

    App.controller('invoiceDetailsController', invoiceDetailsController);
    invoiceDetailsController.$inject = ['$scope', '$rootScope', '$state', '$stateParams', 'studentInvoiceService', '$timeout', '$filter', '$window', 'numberToWords', 'breakdownPenality', 'previewInvoiceService', 'getRefundedFeeHeads', 'commonService', 'examFeeService', 'ValidationService'];

    function invoiceDetailsController($scope, $rootScope, $state, $stateParams, studentInvoiceService, $timeout, $filter, $window, numberToWords, breakdownPenality, previewInvoiceService, getRefundedFeeHeads, commonService, examFeeService, ValidationService) {
        if ($rootScope.Auth.principal.userRoles && $rootScope.Auth.principal.userRoles['ADMIN'] && !$rootScope.Auth.principal.userRoles['STUDENT']) {
            $state.go('manageStudent');
            return;
        }

        $scope.paymentPageLoader = true;
        $scope.headConcession = {};
        $scope.previewInvoiceList = {};
        $scope.confirmDeclaration = 0;
        $scope.totalPenaltyFees = 0;

        $scope.partialPayDetails = {};

        var invoiceId = $stateParams.invoiceId;
        $scope.paymentType = {
            partial: false
        };

        $scope.$validationOptions = {
            debounce: 500,
            preValidateFormElements: false,
            isolatedScope: $scope
        };

        if ([undefined, null, ""].includes(invoiceId)) {
            return $state.go("newInvoiceList");
        }

        $rootScope.prePaymentStatus = {};
        function getPrePaymentStatus() {
            studentInvoiceService.getPrePaymentStatus($scope.previewInvoiceList._id, function (error, response) {
                if (error) {
                    return commonService.showErrorMessage($scope, "errorMsg", "errorMsgContent", error);
                }

                $rootScope.prePaymentStatus = response || {};

                if ($rootScope.prePaymentStatus.hasPaid) {
                    $state.go("newInvoiceDetails", {
                        "invoiceId": $scope.previewInvoiceList._id, "txnResponseStatus": "success"
                    })
                }
            })
        }

        $scope.invoiceTemplateSetup = function (callback) {
            if ($scope.invoiceConfig && Object.keys($scope.invoiceConfig).length) {
                callback ? callback() : null;
                return;
            }

            $scope.invoiceConfig = {};

            studentInvoiceService.getInvoiceSettings(function (error, res) {
                if (error) {
                    return commonService.showErrorMessage($scope, 'errorMsg', 'errorMsgContent', error);
                }

                $scope.invoiceConfig = res.layout.body;

                callback ? callback() : null;
            }, true);
        };

        function getInvoice() {
            var criteria = {
                rollNumber: $scope.studentDetails.rollNumber,
                dummyRollNumber: $scope.studentDetails.dummyRollNumber
            };

            studentInvoiceService.getInvoice(invoiceId, criteria, function (error, response) {
                $scope.paymentPageLoader = false;
                if (error) {
                    console.log('error => ', error);
                    return $state.go("newInvoiceList");
                }

                $scope.invoiceTemplateSetup(function () {

                    $scope.previewInvoiceList = response.invoiceDoc;

                    $scope.concessionMap = {};
                    $scope.feeHeadView = $scope.invoiceConfig.feeHeads.options;
                    $scope.concessionView = $scope.invoiceConfig.concessions.options;
                    $scope.penaltiesView = $scope.invoiceConfig.penalty.options;

                    $scope.totalFeeAmt = $scope.previewInvoiceList.total;
                    $scope.totalPenaltyAmt = 0;
                    $scope.totalWaiveredAmt = 0;

                    if (($scope.previewInvoiceList.rollNumber !== $rootScope.studentRecord.rollNumber)) {
                        $state.go("newInvoiceList");
                    }

                    $scope.invoiceFeeType = $scope.previewInvoiceList.feeType;

                    if (response.invoiceRestrictions && response.invoiceRestrictions.length) {
                        $scope.paymentButton = true;
                        $scope.addMoreButton = true;

                        response.invoiceRestrictions.forEach(function (constraintDetails) {
                            if (constraintDetails.unPaidAcademicInvoices) {
                                $scope.infoMsg = "You are not permitted to pay exam fee. until you pay the Academic fee";
                            }
                        })
                    }

                    if ($scope.previewInvoiceList.amount == 0) {
                        $state.go("newInvoiceList");
                    }

                    if ($scope.previewInvoiceList.refund) {
                        $scope.invoiceRefundStatus = previewInvoiceService.isFullyRefunded($scope, $scope.previewInvoiceList);
                        $scope.refunded = $scope.invoiceRefundStatus == "Partially Refunded" ? getRefundedFeeHeads.getApprovedRefundFeeHeads($scope.previewInvoiceList) : {};
                    }

                    var penaltyFeeHeadIndex = $scope.previewInvoiceList.feeHeads.findIndex(function (item) {
                        return (item.type == "penalty");
                    });

                    if (penaltyFeeHeadIndex != -1) {
                        var breakdownFeeheads = breakdownPenality.transformPenaltyFeeheadToDisplay($scope.previewInvoiceList);
                        var waiverFeeheads = breakdownPenality.transformWaiverFeeheadToDisplay($scope.previewInvoiceList);
                        $scope.previewInvoiceList.feeHeads.splice(penaltyFeeHeadIndex, 1);
                        $scope.previewInvoiceList.feeHeads = $scope.previewInvoiceList.feeHeads.concat(breakdownFeeheads);
                        $scope.previewInvoiceList.feeHeads = $scope.previewInvoiceList.feeHeads.concat(waiverFeeheads);
                        $scope.penaltyView = true;
                        if ($scope.invoiceFeeType == 'MISCELLANEOUS FEES') {
                            breakdownFeeheads.forEach(function (value) {
                                $scope.totalPenaltyFees += value.amount;
                            });
                        }

                        $scope.totalPenaltyAmt = breakdownFeeheads.reduce(function (total, feeHead) {
                            return total + feeHead.amount;
                        }, 0);

                        $scope.totalWaiveredAmt = waiverFeeheads.reduce(function (total, feeHead) {
                            return total + feeHead.amount;
                        }, 0);
                    }

                    if ($scope.invoiceConfig.concessions.enabled && ($scope.feeHeadView.FEE_NAME || $scope.feeHeadView.CUSTOM)) {
                        if ($scope.previewInvoiceList.concessionValue) {
                            $scope.totalFeeAmt += $scope.previewInvoiceList.concessionValue;
                        }
                    }

                    if ($scope.invoiceConfig.penalty.enabled && ($scope.feeHeadView.FEE_NAME || $scope.feeHeadView.CUSTOM)) {
                        $scope.totalFeeAmt -= ($scope.totalPenaltyAmt - $scope.totalWaiveredAmt);
                    }

                    $scope.previewInvoiceList.feeHeads.forEach(function (feeHead) {
                        if (Array.isArray(feeHead.concessions) && feeHead.concessions.length) {
                            feeHead.concessions.forEach(function (concession) {
                                if (!$scope.concessionMap[concession.name]) {
                                    $scope.concessionMap[concession.name] = 0;
                                }
                                $scope.concessionMap[concession.name] += concession.value || 0;
                            });
                        }
                    });

                    if ($scope.totalPenaltyFees == $scope.previewInvoiceList.total) {
                        $scope.paymentButton = true;
                        $scope.addMoreButton = true;
                    }

                    if ($scope.invoiceFeeType == 'EXAM FEES') {
                        examFeeService.InvoiceUIModel($scope, $scope.previewInvoiceList);
                    } else if ($scope.invoiceFeeType != 'EXAM FEES') {
                        previewInvoiceService.setupConcessionForDisplay($scope, $scope.previewInvoiceList.feeHeads);
                    }

                    showAlertForTxn();

                    if ($scope.previewInvoiceList.status != "PD" && !$stateParams.txnResponseStatus) {
                        getPrePaymentStatus();
                    }
                });
            });
        }

        $timeout(function () {
            getInvoice();
        }, 50);

        $scope.addMorePapers = function (rollNumber, feeId) {
            if ($scope.previewInvoiceList.status == "IP") {
                $scope.serverError = "Add more paper is not allowed in invoice In-Progress state";
            } else {
                $state.go("editInvoiceToPayMore", { "rollNumber": rollNumber, "feeId": feeId });
            }
        }

        $scope.resetPaymentType = function () {
            if (!$scope.paymentType.partial) {
                $scope.partialPayDetails.payableAmount = $scope.previewInvoiceList.total;
            }
        }

        $scope.getMinimumAmount = function () {
            if (!$scope.previewInvoiceList.settings.partialPay) {
                return $scope.previewInvoiceList.total;
            }

            var minAmount = ($scope.previewInvoiceList.total > $scope.previewInvoiceList.settings.installAmount)
                ? $scope.previewInvoiceList.settings.installAmount
                : $scope.previewInvoiceList.total;

            return minAmount;
        }

        $scope.getPartialAlert = function (boundary) {
            var alertMsg = null;

            switch (boundary) {
                case "min":
                    alertMsg = "Not able to proceed with partial amount, as the payable amount is less than the minimum amount &#8377; " + $filter("amountSplit")($scope.getMinimumAmount());
                    break;

                case "max":
                    alertMsg = "Not able to proceed with partial amount, as the payable amount is greater than or equal to the amount &#8377; " + $filter("amountSplit")($scope.previewInvoiceList.total);
                    break;

                default:
                    alertMsg = "";
            }

            return alertMsg;
        }

        $scope.payPartially = function (invoiceId) {
            studentInvoiceService.payPartially(invoiceId, $scope.partialPayDetails.payableAmount, function (error, response) {
                if (!error && !response.invoiceId) {
                    error = "System Error";
                }

                if (error) {
                    $scope.paymentPageLoader = false
                    $scope.paymentButton = false;
                    $rootScope.preloader = false;
                    return commonService.showErrorMessage($scope, 'errorMsg', 'errorMsgContent', error);
                }

                $state.go("payAgreement", { invoiceId: response.invoiceId });
            });
        }

        function showAlertForTxn() {
            if (!$stateParams.txnResponseStatus) {
                return;
            }

            $scope.serverError = false;
            $scope.serverSuccess = false;

            switch ($stateParams.txnResponseStatus) {
                case "success":
                    if ($scope.previewInvoiceList.status == "PD") {
                        $scope.serverSuccess = "Your payment is successful.";
                    }
                    break;
                case "failure":
                    if ($scope.previewInvoiceList.status != "PD") {
                        $scope.serverError = "Your payment is unsuccessful.";
                    }
                    break;
                case "errored":
                    $scope.serverError = "Errored. Please retry.";
                    break;
                default:
                    $scope.serverError = "Errored. Please retry.";
            }

            $state.go("newInvoiceDetails", { "invoiceId": invoiceId, "txnResponseStatus": undefined }, { notify: false })
        }


        $scope.proceedToPayment = function () {
            if ($scope.paymentType.partial && !new ValidationService().checkFormValidity($scope.paymentDetailsForm)) {
                return;
            }

            $scope.paymentButton = true;
            $scope.addMoreButton = true;
            $scope.paymentPageLoader = true;
            $scope.paymentInprogress = true;
            if (!(($scope.previewInvoiceList) && ($scope.previewInvoiceList.total > 0))) {
                $scope.error = "There is nothing selected to pay";
                $scope.paymentButton = false;
                $scope.addMoreButton = false;
                $scope.paymentPageLoader = false;
                return;
            }

            $rootScope.updatedStatus = "";

            if (!$scope.paymentType.partial) {
                $state.go("payAgreement", { invoiceId: $scope.previewInvoiceList._id });
                return;
            }

            $scope.payPartially($scope.previewInvoiceList._id);
        }

        $scope.convertNumberToWords = function (amount) {
            return numberToWords.convertNumberToWords(amount)
        };

        $scope.syncStatus = function () {
            if (!$rootScope.prePaymentStatus.hasInprogressStatus) {
                return;
            }

            $scope.syncInvoiceDisableButton = true;
            $scope.paymentPageLoader = true;
            studentInvoiceService.syncStatus($rootScope.prePaymentStatus.invoiceId, function (error, response) {
                $scope.paymentPageLoader = false;
                $scope.syncInvoiceDisableButton = false;
                if (error) {
                    return commonService.showErrorMessage($scope, "errorMsg", "errorMsgContent", error);
                }

                $rootScope.updatedStatus = response.laudeaTxnStatus;
                commonService.showSuccessMessage($rootScope, "syncInvoiceSuccess");
                getPrePaymentStatus();
            })
        }
    }

    App.controller('payAggregementController', payAggregementController);
    payAggregementController.$inject = ['$scope', '$rootScope', '$state', '$stateParams', '$timeout', 'commonService', 'numberToWords', 'studentInvoiceService', '$window'];

    function payAggregementController($scope, $rootScope, $state, $stateParams, $timeout, commonService, numberToWords, studentInvoiceService, $window) {
        $scope.invoiceId = $stateParams.invoiceId;

        if (!$scope.invoiceId) {
            return $state.go("newInvoiceList");
        }

        function verifyLogin() {
            var criteria = {
                rollNumber: $scope.studentDetails.rollNumber,
                dummyRollNumber: $scope.studentDetails.dummyRollNumber
            };

            studentInvoiceService.getInvoice($scope.invoiceId, criteria, function (error, response) {
                if (error) {
                    commonService.showErrorMessage($scope, "errorMsg", "errorMsgContent", error);
                    return $state.go("newInvoiceList");
                }

            });
        }

        verifyLogin();

        $rootScope.gatewayDetails = [];
        function getGatewayDetails() {
            studentInvoiceService.getGatewayDetails(function (error, response) {
                if (error) {
                    return commonService.showErrorMessage($scope, "errorMsg", "errorMsgContent", error);
                }

                if (!response.enabled || !response.enabled.length) {
                    return showNoActivePG();
                }

                $rootScope.gatewayDetails = response.enabled;
            })
        }
        getGatewayDetails();

        function showNoActivePG() {
            $scope.errorMsgContent = "Payment blocked. Due to no active payment gateways";
            return commonService.showErrorMessage($scope, "errorMsg", "errorMsgContent");
        }

        $scope.confirmDeclaration = 0;
        $scope.paymentInprogress = false;
        $scope.declarationError = false;

        $rootScope.prePaymentStatus = {};
        function getPrePaymentStatus(callback) {
            studentInvoiceService.getPrePaymentStatus($scope.invoiceId, function (error, response) {
                if (error) {
                    return commonService.showErrorMessage($scope, "errorMsg", "errorMsgContent", error);
                }

                $rootScope.prePaymentStatus = response || {};

                if ($rootScope.prePaymentStatus.hasPaid) {
                    $state.go("newInvoiceDetails", {
                        "invoiceId": $scope.invoiceId, "txnResponseStatus": "success"
                    })
                } else {
                    $scope.paymentInprogress = false;
                }

                if (callback) {
                    callback();
                }
            })
        }

        getPrePaymentStatus();

        $scope.makePayment = function () {
            if ($scope.confirmDeclaration != "1") {
                $scope.error = "Accept the payment agreement";
                return commonService.showErrorMessage($scope, "declarationError", "error");
            }

            if (!$rootScope.gatewayDetails.length) {
                return showNoActivePG();
            }

            $scope.paymentInprogress = true;
            $scope.declarationError = false;
            $scope.paymentPageLoader = true;

            var paymentInfo = {
                "paymentMode": "O",
                "_id": $scope.invoiceId,
                "gateway": $rootScope.gatewayDetails[0],
                "rollNumber": $scope.studentDetails.rollNumber,
                "dummyRollNumber": $scope.studentDetails.dummyRollNumber
            };

            studentInvoiceService.makePayment(paymentInfo, function (error, response) {
                $scope.paymentPageLoader = false;
                if (error) {
                    $scope.paymentInprogress = false;
                    commonService.showErrorMessage($scope, "errorMsg", "errorMsgContent", error);
                    getPrePaymentStatus();
                    return;
                }

                if (response.redirectUrl) {
                    $window.location.href = response.redirectUrl;
                    return;
                }

                $scope.proceedToCheckOut(response);
            })
        }

        $scope.proceedToCheckOut = function (response) {
            const gatewayMap = {
                "paytm": paytmCheckout,
                "billdesk": billdeskCheckout
            };

            const gateway = $rootScope.gatewayDetails[0];
            if (gateway && gatewayMap[gateway]) {
                gatewayMap[gateway](response);
            } else {
                console.error('Unsupported or missing payment gateway:', gateway);
            }
        };

        function paytmCheckout(response) {
            var checkoutConfig = Object.assign({}, response.checkoutConfig.config, {
                "handler": {
                    "notifyMerchant": function (eventName, data) {
                        console.log("notifyMerchant handler function called");
                        console.log("eventName => ", eventName);
                        console.log("data => ", data);

                        if (eventName == "APP_CLOSED") {
                            forceFailTransaction(response.txnId, data.message);
                        }
                    },
                    "transactionStatus": function (data) {
                        console.log("payment status ", data);
                    }
                }
            });

            loadScript(response.checkoutConfig.url, checkoutConfig, {}, function (config) {
                if (window.Paytm && window.Paytm.CheckoutJS) {
                    window.Paytm.CheckoutJS.onLoad(function excecuteAfterCompleteLoad() {
                        window.Paytm.CheckoutJS.init(config).then(function onSuccess() {
                            window.Paytm.CheckoutJS.invoke();
                        }).catch(function onError(error) {
                            console.log('error => ', error);
                        });
                    });
                }
            });
        }

        function billdeskCheckout(response) {
            const { scriptList = [], styleList = [] } = response.scriptConfig || {};
            const checkoutConfig = Object.assign({}, response.checkoutConfig, {
                responseHandler: function (data) {
                    console.log("responseHandler data => ", data);
                    getPrePaymentStatus(function () {
                        $scope.syncStatus();
                    });
                }
            });

            styleList.forEach(loadStyle);

            loadScriptList(scriptList).then(function () {
                window.loadBillDeskSdk(checkoutConfig);
            });
        }

        function loadScriptList(scriptList) {
            return Promise.all(scriptList.map(script => {
                return new Promise(resolve => {
                    loadScript(script.url, {}, script.options, resolve);
                });
            }));
        }

        function loadScript(url, data, options = {}, callback) {
            const script = document.createElement('script');
            script.src = url;
            Object.entries(options).forEach(([key, value]) => {
                script[key] = value;
            });
            script.onload = () => callback(data);
            document.body.appendChild(script);
        }

        function loadStyle(url) {
            const link = document.createElement('link');
            link.href = url;
            link.rel = 'stylesheet';
            document.head.appendChild(link);
        }

        function forceFailTransaction(txnId, message) {
            console.log("Force fail reason", message);
            studentInvoiceService.forceFail(txnId, function (error, redirectUrl) {
                if (error) {
                    return commonService.showErrorMessage($scope, "errorMsg", "errorMsgContent", error);
                }

                $window.location.href = redirectUrl;
            });
        }

        $scope.cancelPayment = function () {
            $state.go("newInvoiceDetails", { invoiceId: $scope.invoiceId });
        }

        $scope.syncStatus = function () {
            if (!$rootScope.prePaymentStatus.hasInprogressStatus) {
                return;
            }

            $scope.syncInvoiceDisableButton = true;
            $scope.paymentPageLoader = true;
            studentInvoiceService.syncStatus($rootScope.prePaymentStatus.invoiceId, function (error, response) {
                $scope.paymentPageLoader = false;
                $scope.syncInvoiceDisableButton = false;
                if (error) {
                    return commonService.showErrorMessage($scope, "errorMsg", "errorMsgContent", error);
                }

                $rootScope.updatedStatus = response.laudeaTxnStatus;
                commonService.showSuccessMessage($rootScope, "syncInvoiceSuccess");
                getPrePaymentStatus();
            })
        }
    }

    App.service('breakdownPenality', breakdownPenality)
    function breakdownPenality() {
        this.transformPenaltyFeeheadToDisplay = function (previewInvoiceList) {
            var penaltyFeeHeadIndex = previewInvoiceList.feeHeads.findIndex(function (item) {
                return (item.type == "penalty");
            });

            if (penaltyFeeHeadIndex !== -1) {
                var breakdownFeeheads = [];
                var penaltyFeeHead = previewInvoiceList.feeHeads[penaltyFeeHeadIndex];
                if (penaltyFeeHead.breakdown) {
                    penaltyFeeHead.breakdown.forEach(function (breakdownItem) {
                        breakdownFeeheads.push({
                            "description": getPenaltyDescription(breakdownItem),
                            "amount": breakdownItem.amount,
                            "isPenaltyFeeHead": true
                        })
                    });
                }
                return breakdownFeeheads
            }

            function getPenaltyDescription(breakdownItem) {
                var description = "";
                var breakdownAmount = breakdownItem.amount / breakdownItem.iteration;
                var part2 = breakdownAmount
                    + " from " + moment(breakdownItem.from).format("DD-MMM-YYYY")
                    + " to " + moment(breakdownItem.to).format("DD-MMM-YYYY") + "."
                switch (breakdownItem.rule) {
                    case "PD":
                        description = "Daily fine of Rs. " + part2;
                        break;
                    case "PW":
                        description = "Weekly fine of Rs. " + part2;
                        break;
                    case "O":
                        description = "Fine of Rs. " + part2;
                        break;
                }

                return description;
            }
        }

        this.transformWaiverFeeheadToDisplay = function (invoice) {
            var waiverPenaltyFeeHeadIndex = invoice.feeHeads.findIndex(function (feeHead) {
                return (feeHead.waiverHistory);
            });

            if (waiverPenaltyFeeHeadIndex == -1) {
                return [];
            }

            var penaltyFeeHead = invoice.feeHeads[waiverPenaltyFeeHeadIndex];
            var waiverFeeheads = penaltyFeeHead.waiverHistory.map(function (waiverItem) {
                return {
                    "description": getPenaltyDescription(waiverItem),
                    "amount": waiverItem.amount
                }
            });

            return waiverFeeheads;

            function getPenaltyDescription(waiverItem) {
                return "Deducted fine amount on " + moment(waiverItem.waiveredOn).format("DD-MMM-YYYY") + ".";
            }
        }
    }

    App.service('getRefundedFeeHeads', getRefundedFeeHeads)
    function getRefundedFeeHeads() {
        this.getApprovedRefundFeeHeads = function (invoice) {
            var refunded = {};
            var refundStatus = invoice.refund[0].status;
            var existingRefundLength = invoice.refund.length;
            if (!['RI', 'RC', 'RD', 'RR'].includes(refundStatus)) {
                return {};
            }
            if (['RI', 'RD'].includes(refundStatus)) {
                var approvedRefundFeeHeads = JSON.parse(JSON.stringify(invoice.refund[0].feeHeads));
                var approvedDate = getRefundDate(invoice.refund[0]);
                if (invoice.refund.length == 1 && invoice.refund[0].type == '00') { // for Double Debit
                    return {};
                }
                addFeeHeadToExistingFeeHeadMap(approvedRefundFeeHeads, approvedDate);
            } else {
                var approvedRefundFeeHeads = [];
            }
            function feeHeadExist(feeHeadName) {
                return approvedRefundFeeHeads.some(function (feeHead) {
                    return feeHead.name == feeHeadName;
                });
            }
            function getRefundDate(refundObj) {
                var dateField = (refundObj.mode == '00') ? "refundInititedTimestamp" : "refundDate";
                return new Date(refundObj[dateField]);
            }
            for (var refund = 1; refund <= existingRefundLength; refund++) {
                if (!['RI', 'RD'].includes(refundStatus)) {
                    continue;
                }
                var currentRefund = JSON.parse(JSON.stringify(invoice.refund[refund].feeHeads));
                var approvedDate = getRefundDate(invoice.refund[refund]);
                if (invoice.refund[refund].type == '00') {
                    addFeeHeadToExistingFeeHeadMap(invoice.feeHeads, approvedDate);
                    approvedRefundFeeHeads = JSON.parse(JSON.stringify(invoice.feeHeads));
                    break;
                }
                currentRefund.forEach(function (feeHead) {
                    if (feeHeadExist(feeHead.name)) {
                        var approvedFeeHeadIndex = approvedRefundFeeHeads.findIndex(function (approvedRefundFeeHead) {
                            return approvedRefundFeeHead.name == feeHead.name;
                        })
                        if (approvedRefundFeeHeads[approvedFeeHeadIndex].enrollments && feeHead.enrollments) {
                            feeHead.enrollments.forEach(function (enrollment) {
                                approvedRefundFeeHeads[approvedFeeHeadIndex].enrollments.push({ courseName: enrollment.courseName, courseCode: enrollment.courseCode })
                            })
                        }
                    } else {
                        approvedRefundFeeHeads.push(feeHead);
                    }
                });
                addFeeHeadToExistingFeeHeadMap(approvedRefundFeeHeads, approvedDate);
            }

            function addFeeHeadToExistingFeeHeadMap(feeHeads, approvedDate) {
                feeHeads.forEach(function (feeHead) {
                    var invoiceFeeHead = invoice.feeHeads.find(function (invoiceFeeHead) {
                        return invoiceFeeHead.name == feeHead.name;
                    })
                    if (!invoiceFeeHead.enrollments) {
                        if (!refunded[feeHead.name]) {
                            refunded[feeHead.name] = approvedDate;
                        }
                    } else {
                        if (!feeHead.enrollments && feeHead.amount == invoiceFeeHead.payable) {
                            feeHead.enrollments = JSON.parse(JSON.stringify(invoiceFeeHead.enrollments));
                        }
                        if (!refunded[feeHead.name]) {
                            refunded[feeHead.name] = {};
                        }
                        feeHead.enrollments.forEach(function (enrollment) {
                            if (!refunded[feeHead.name][enrollment.courseCode]) {
                                refunded[feeHead.name][enrollment.courseCode] = approvedDate;
                            }
                        })
                    }
                })
            }
            return refunded;
        }
    }

    App.service('previewInvoiceService', previewInvoiceService)
    previewInvoiceService.$inject = ['$rootScope', '$filter'];

    function previewInvoiceService($rootScope, $filter) {
        $rootScope.hoverConcessionDetails = [];
        $rootScope.getconcessionDetails = function (concessionDetails, index) {
            var feeHeadDetails = "";
            concessionDetails.feeHeads.forEach(function (feeHead) {
                feeHeadDetails = feeHeadDetails + feeHead.name + " - ₹ " + $filter('amountSplit')(feeHead.value) + "\n";
            });
            $rootScope.hoverConcessionDetails[index] = feeHeadDetails;
        }

        this.setupConcessionForDisplay = function (scopeObj, feeHeads) {
            scopeObj.concessionsList = {};
            feeHeads.forEach(function (feeHead) {
                if (!feeHead.concessions) {
                    return;
                }

                for (var concession of feeHead.concessions) {
                    if (!concession.isTotal) {
                        continue;
                    }

                    if (!scopeObj.concessionsList[concession.name]) {
                        scopeObj.concessionsList[concession.name] = {
                            value: 0,
                            feeHeads: []
                        };
                    };

                    scopeObj.concessionsList[concession.name].value += concession.value;
                    var feeDetails = {
                        name: feeHead.name,
                        value: concession.value
                    }
                    scopeObj.concessionsList[concession.name].feeHeads.push(feeDetails);
                }
            });
        }

        this.isFullyRefunded = function (scopeObj, invoice) {
            var refundTotal = 0;
            var isDoubleDebit = (invoice.refund.length == 1 && invoice.total == invoice.refund[0].total && !['RI', 'RD'].includes(invoice.refund[0].status));

            if (invoice.refund && !isDoubleDebit) {
                invoice.refund.forEach(function (refund) {
                    if (['RI', 'RD'].includes(refund.status)) {
                        refundTotal += refund.total;
                    }
                })
            }

            scopeObj.refundedAmount = refundTotal;
            scopeObj.refundStatus = invoice.refund[invoice.refund.length - 1].status;
            if (refundTotal == invoice.total) return "Fully Refunded";
            if (refundTotal > 0) return "Partially Refunded";
            else return "No Refund Initiated";
        }

        $rootScope.isEmptyObject = function (objectData) {
            return Boolean(objectData && Object.keys(objectData).length);
        }
    }

    App.service('examFeeService', examFeeService);
    examFeeService.$inject = ['$rootScope'];

    function examFeeService($rootScope) {
        this.InvoiceUIModel = function (scopeObj, invoice) {
            if (invoice.feeType != 'EXAM FEES') {
                return;
            }

            scopeObj.groupedFeeHeads = {};
            scopeObj.feeHeadsAppliedToStudent = [];
            scopeObj.feeHeadsAppliedToStudentOthers = [];
            scopeObj.feeHeadsAppliedToEnrollment = [];
            scopeObj.dependentFeeHeads = [];
            scopeObj.examFeeSummary = {};

            var feeHeads = invoice.feeHeads;
            feeHeads.forEach(function (feeHead) {
                if (!scopeObj.groupedFeeHeads[feeHead.groupName]) {
                    scopeObj.groupedFeeHeads[feeHead.groupName] = []
                    scopeObj.examFeeSummary[feeHead.groupName] = 0
                }
                scopeObj.groupedFeeHeads[feeHead.groupName].push(feeHead);
            });

            for (var groupName in scopeObj.groupedFeeHeads) {
                scopeObj.groupedFeeHeads[groupName].forEach(function (feeHead) {
                    if (feeHead.applyPaymentTo == "student"
                        && !feeHead.groupName && !feeHead.userChoiceEnabled) {
                        scopeObj.feeHeadsAppliedToStudent.push(feeHead);

                        calcGroupWiseAmt(scopeObj, feeHead, 'General Fees');
                    }
                    else if (feeHead.applyPaymentTo == "student"
                        && feeHead.groupName && !feeHead.userChoiceEnabled) {
                        scopeObj.feeHeadsAppliedToStudentOthers.push(feeHead);

                        calcGroupWiseAmt(scopeObj, feeHead, 'Other Fees');
                    }
                    else if (feeHead.applyPaymentTo == "student"
                        && feeHead.userChoiceEnabled) {
                        scopeObj.dependentFeeHeads.push(feeHead);

                        calcGroupWiseAmt(scopeObj, feeHead, feeHead.groupName);
                    } else {
                        scopeObj.feeHeadsAppliedToEnrollment.push(feeHead);
                        calcGroupWiseAmt(scopeObj, feeHead, feeHead.groupName);
                    }

                    if (!feeHead.concessions) {
                        return;
                    }

                    normalizeConcessions(scopeObj, feeHead);
                });
            }
        }

        function calcGroupWiseAmt(scopeObj, feeHead, groupName) {
            if (!scopeObj.examFeeSummary[groupName]) {
                scopeObj.examFeeSummary[groupName] = 0;
            }

            scopeObj.examFeeSummary[groupName] += feeHead.payable;
            if (feeHead.concessionValue) {
                scopeObj.examFeeSummary[groupName] += feeHead.concessionValue;
            }
        }

        function normalizeConcessions(scopeObj, feeHead) {
            if (!scopeObj.concessionsList) {
                scopeObj.concessionsList = {};
            }

            for (var concession of feeHead.concessions) {
                if (!scopeObj.concessionsList[concession.name]) {
                    scopeObj.concessionsList[concession.name] = {
                        value: 0,
                        groups: {}
                    };
                }

                scopeObj.concessionsList[concession.name].value += concession.value;

                var groupName = feeHead.groupName || "General";
                if (!scopeObj.concessionsList[concession.name].groups[groupName]) {
                    scopeObj.concessionsList[concession.name].groups[groupName] = {
                        value: 0,
                        feeHeads: []
                    };
                }

                scopeObj.concessionsList[concession.name].groups[groupName].value += concession.value;

                var feeDetails = {
                    name: feeHead.name,
                    enrollments: feeHead.enrollments ? feeHead.enrollments.map(function (enrollment) {
                        return enrollment.courseCode
                    }).join(", ") : "",
                    value: concession.value
                };
                scopeObj.concessionsList[concession.name].groups[groupName].feeHeads.push(feeDetails);
            }
        }

        this.getGeneralFeeAmount = function (invoice) {
            return invoice.feeHeads.reduce(function (totalGeneralFees, currentHead) {
                var isPenaltyHead = (currentHead.type == "penalty");
                var hasEnrollments = Boolean(feeHead.enrollments && feeHead.enrollments.length);

                if (isPenaltyHead || currentHead.userChoiceEnabled || hasEnrollments) {
                    return totalGeneralFees;
                }

                totalGeneralFees += value.payable;
                return totalGeneralFees;
            }, 0);
        }

        $rootScope.isGroupNameFirstTime = function (feeHeadIndex, feeHeads) {
            if (!feeHeads || !feeHeads.length || !feeHeads[feeHeadIndex].groupName) {
                return false;
            }

            return !(feeHeads.some(function (feeHead, currentIndex) {
                var hasEnrollments = Boolean(feeHead.enrollments && feeHead.enrollments.length);
                var isSameGroup = (feeHeads[feeHeadIndex].groupName == feeHead.groupName);

                return (currentIndex < feeHeadIndex && isSameGroup && hasEnrollments);
            }));
        }

        $rootScope.isDependentFeeHeadFirstTime = function (dependentIndex, dependentHeads, feeHeadIndex, feeHeads) {
            if (!dependentHeads || !dependentHeads.length || !dependentHeads[dependentIndex].groupName) {
                return false;
            }

            return !(feeHeads.some(function (feeHead, currentIndex) {
                var hasEnrollments = Boolean(feeHead.enrollments && feeHead.enrollments.length);
                var isSameGroup = (dependentHeads[dependentIndex].groupName == feeHead.groupName);
                var isSameFeeHead = (feeHead.dependentFeeHead == dependentHeads[dependentIndex].name);

                return (currentIndex < feeHeadIndex && isSameGroup && isSameFeeHead && hasEnrollments);
            }));
        }

        $rootScope.isDependentFeeHeadPayable = function (dependentFeeHeadName, groupName, feeHeads) {
            return !(feeHeads.some(function (feeHead) {
                var hasEnrollments = Boolean(feeHead.enrollments && feeHead.enrollments.length);
                var isSameGroup = (feeHead.groupName == groupName);
                var isSameFeeHead = (feeHead.dependentFeeHead == dependentFeeHeadName);

                return (isSameGroup && hasEnrollments && isSameFeeHead);
            }));
        }
    }
})();;
(function () {
    'use strict';
    var App = angular.module('app');

    App.filter('camelCaseFilter', function () {
        var camelCaseFilter = function (input) {
            if (!input) {
                return input;
            }

            //convert every part of input separated by space to camel case - first char in upper and rest in lower
            let normalCase = "";
            for (let i = 0; i < input.length; i++) {
                let char = input[i];
                // Check if the character is uppercase
                if (char.toUpperCase() === char) {
                    // If it's uppercase, add a space and convert to lowercase
                    normalCase += " " + char.toLowerCase();
                } else {
                    // If it's lowercase or not a letter, just add it to the result
                    normalCase += char;
                }
            }
            // Capitalize the first character if it's not already
            return normalCase.trim().charAt(0).toUpperCase() + normalCase.slice(1);
        };
        return camelCaseFilter;
    });

    App.filter('camelCase', function () {
        var camelCaseFilter = function (input) {
            if (!input) {
                return input;
            }

            //convert every part of input separated by space to camel case - first char in upper and rest in lower
            var words = input.split(' ');
            for (var i = 0, len = words.length; i < len; i++) {
                if (words[i].length > 0) {
                    var camelCase = words[i].charAt(0).toUpperCase();

                    if (words[i].length > 1) {
                        camelCase += words[i].slice(1).toLowerCase();
                    }
                    words[i] = camelCase;
                }
            }

            return words.join(' ');
        };
        return camelCaseFilter;
    });

})();;
(function () {
    'use strict';
    var App = angular.module('app');

    App.controller('HeaderController', HeaderController);
    HeaderController.$inject = ['$scope', '$rootScope', '$state', '$stateParams', 'studentService'];

    function HeaderController($scope, $rootScope, $state, $stateParams, studentService) {
        $scope.$on('$includeContentLoaded', function () {
            // Transparent header functionality
            $scope.helpers.uiHandleHeader();
        });


        var rollNumber = $rootScope.Auth.tokenParsed.preferred_username.toUpperCase();
        $scope.rolesDetails = $rootScope.Auth.tokenParsed.resource_access[window.keycloakConfig.clientId]
        if ($scope.rolesDetails && $scope.rolesDetails.roles.includes('STUDENT') && (!$scope.rolesDetails.roles.includes('ADMIN'))) {
            studentService.getStudentById(rollNumber, function (err, response) {
                if (!err) {
                    $rootScope.studentRecord = response;
                    if ($rootScope.studentRecord.displayPicture) {
                        $scope.setDisplayPicture($scope.studentRecord.displayPicture);
                    } else {
                        $rootScope.dpSource = "img/avatars/noimage-later.png";
                    }
                };
            });
        }

        $scope.setDisplayPicture = function (displayPicture) {
            var query = displayPicture;
            studentService.getDownloadUrl(query, function (err, res) {
                if (res && res.signedUrl) {
                    $scope.displayPictureUrl = new URL(res.signedUrl);
                } else {
                    $scope.displayPictureUrl = "img/avatars/noimage-later.png";
                    return;
                }
            });
        }
    }
})();;
