        $scope.getFacultyDetails = function (data) {
            $scope.facultyDetails = {};
            $scope.facultyName.forEach(faculty => {
                if (faculty.facultyId.toUpperCase() == data.facultyId.toUpperCase()) {
                    facultyData();

                    if (faculty && faculty.facultyContactNo) {
                        $scope.studentRecord.contactNo = faculty.facultyContactNo;
                    }
                    if (faculty && faculty.facultyEmail) {
                        $scope.studentRecord.email = faculty.facultyEmail;
                    }
                    if (faculty.basic && faculty.basic.firstName) {
                        $scope.studentRecord.basic.firstName = faculty.basic.firstName;
                    }
                    if (faculty.basic && faculty.basic.lastName) {
                        $scope.studentRecord.basic.lastName = faculty.basic.lastName;
                    }
                    if (faculty.basic && faculty.basic.gender) {
                        $scope.studentRecord.basic.gender = faculty.basic.gender;
                    }
                    if (faculty.basic && faculty.basic.dobStr) {
                        $scope.studentRecord.basic.dob = moment(faculty.basic.dobStr, 'YYYY-MM-DD').format('DD-MM-YYYY');
                    }
                    if (faculty.basic && faculty.basic.religion) {
                        $scope.studentRecord.basic.religion = faculty.basic.religion;
                    }
                    if (faculty.basic && faculty.basic.caste) {
                        $scope.studentRecord.basic.caste = faculty.basic.caste;
                    }
                    if (faculty.basic && faculty.basic.community) {
                        $scope.studentRecord.basic.community = faculty.basic.community;
                    }
                    if (faculty.basic && faculty.basic.motherTongue) {
                        $scope.studentRecord.admissions.motherTongue = faculty.basic.motherTongue;
                    }
                    if (faculty.basic && faculty.basic.nationality) {
                        $scope.studentRecord.contact.permanentCountry = faculty.basic.nationality;
                    }
                    if (faculty.basic && faculty.basic.state) {
                        $scope.studentRecord.contact.permanentState = faculty.basic.state;
                    }
                    if (faculty && faculty.identity.facultyAadhaarNumber) {
                        $scope.studentRecord.identity.aadharNo = faculty.identity.facultyAadhaarNumber;
                    }
                    if (faculty && faculty.identity.residentStatus) {
                        $scope.studentRecord.basic.nationality = faculty.identity.residentStatus;
                    }
                }
            })
        }

