        function getYears(iteration) {
            var yearIteration = new Date().getFullYear() - 1;
            var batchYear = [];
            for (var i = 0; i < iteration; i++) {
                batchYear.push(yearIteration);
                yearIteration -= 1;
            }
            return batchYear;
        };

