        function buildDistinctQuery(field) {
            var newQuery = {};
            Object.keys($scope.search).forEach(function (key) {
                if (!$scope.search[key] || key == field)
                    return;

                newQuery[key] = $scope.search[key];
            });
            return newQuery;
        }

