        $scope.bulkDueSelections = function (studentDetails, isChecked) {
            studentDetails.isShow = isChecked;
            if (isChecked == true) {
                $scope.showDueButton = true;
            }
            studentDetails.dueList.forEach(function (dueList, index) {
                dueList.dueItems.forEach(function (due, index) {
                    var value = isChecked;
                    due.isChecked = value;
                });
            });
        };

        $scope.singleDueSelection = function (studentList, dueDetails, dueStatus) {
            var value = "";
            var show = false;
            var length = 0;
            var count = 0;
            if (!dueStatus) {
                studentList.bulkDue = false;
            }
            dueDetails.isChecked = dueStatus;
            studentList.dueList.forEach(function (dueList, index) {
                length = dueList.dueItems.length;
                dueList.dueItems.forEach(function (due, index) {
                    if (due.isChecked) {
                        count++;
                        value = true;
                        show = true;
                        $scope.showDueButton = true;
                    } else {
                        value = false;
                    }
                });
            });
            if (length == count && value) {
                studentList.bulkDue = true;
            }
            studentList.isShow = show;
            //studentList.bulkDue = value;
        };

