        $scope.updateDueStatus = function (studentDueList) {
            var query = { dueList: studentDueList };

            if ($scope.studentDue.status) {
                query.dueStatus = $scope.studentDue;
            }

            if ($scope.studentDue.remark) {
                query["remark"] = $scope.studentDue.remark;
            }
            noDueJobService.updateSingleStudentDue(query, function (err, res) {
                if (!err) {
                    $scope.getStudentRecords(true);
                    $scope.studentDue = {};
                    $scope.dueUpdateCurrentStep = 0;
                    $('#noDueApproveModel').modal('hide');
                    $scope.showSuccessNotification("SuccessFully updated the Student dues.");
                } else {
                    $scope.getStudentRecords(true);
                    $scope.studentDue = {};
                    $scope.dueUpdateCurrentStep = 0;
                    $('#noDueApproveModel').modal('hide');
                    $scope.showErrorNotification("Failed to update Student Dues.Try Again.");
                }
            });
        };

