        $scope.getStudentRecords = function (isConstructPaginationBar, filters, search) {
            $scope.showLoader = true;
            var searchQuery = {
                filter: {},
                view: {},
            };

            var options = $rootScope.calcSkipLimitValueForPagination(isConstructPaginationBar);
            searchQuery.length = options.limitValue;
            searchQuery.start = options.skipValue;
            searchQuery.order = $scope.sorting;

            if (search) {
                searchQuery.search = {
                    value: search,
                };
            }

            if ($scope.search.programType) {
                searchQuery.filter["programType"] = $scope.search.programType;
            }

            if ($scope.search.programCategory) {
                searchQuery.filter["programCategory"] =
                    $scope.search.programCategory;
            }

            if ($scope.search.batchYear && $scope.search.batchYear.length) {
                searchQuery.filter["batchYear"] = { $in: $scope.search.batchYear, };
            }

            if ($scope.search.programmeName && $scope.search.programmeName.length) {
                searchQuery.filter["programmeName"] = {
                    $in: $scope.search.programmeName,
                };
            }

            if ($scope.search.section) {
                searchQuery.filter["section"] = $scope.search.section;
            }

            if ($scope.search.status) {
                searchQuery.filter["status"] = $rootScope.status[$scope.search.status];
            }

            if ($scope.search.statusReason) {
                searchQuery.filter["statusReason"] = $scope.search.statusReason;
            }

            if ($scope.search.tcIssued) {
                searchQuery.filter["tcIssued"] = $scope.search.tcIssued;
            }

            if (![null, undefined, ''].includes($scope.search.registrationFormStatus)) {
                searchQuery.filter["registrationFormStatus"] = $scope.search.registrationFormStatus;
            }

            if (![null, undefined, ''].includes($scope.search.isKeycloakEnabled)) {
                searchQuery.filter["isKeycloakEnabled"] = $scope.search.isKeycloakEnabled;
            }

            if ($scope.search.exitFormStatus) {
                searchQuery.filter["exitFormStatus"] = $rootScope.exitFormStatus[$scope.search.exitFormStatus]
            }

            if ($scope.search.programMode && $scope.search.programMode.length) {
                searchQuery.filter["programMode"] = { $in: $scope.search.programMode };
            }

            if ($scope.search.programCode) {
                searchQuery.filter["programCode"] = $scope.search.programCode;
            }

            if ($scope.isCardView) {
                searchQuery.view["isCardView"] = $scope.isCardView;
            }


            if (!checkRoleForFilters()) {
                if (Object.keys($rootScope.rolesInGroups).includes("HEAD")) {
                    searchQuery.filter["nodeId"] = $rootScope.rolesInGroups["HEAD"];
                }

                if (Object.keys($rootScope.rolesInGroups).includes("HEAD-INCHARGE")) {
                    searchQuery.filter["nodeId"] = $rootScope.rolesInGroups["HEAD-INCHARGE"];
                }

                if (Object.keys($rootScope.rolesInGroups).includes("CLASS-TUTOR")) {
                    searchQuery.filter["tutorId"] = $rootScope.Auth.principal.preferred_username.toUpperCase();
                }
            }

            // if ($scope.isCardView) {
            //     searchQuery.filter["isCardView"] = $scope.isCardView;
            // }

            $scope.searchQuery = searchQuery;
            getStudentsByFilter(isConstructPaginationBar);
        };

        function getStudentsByFilter(isConstructPaginationBar) {
            studentService.getFilterStudents($scope.searchQuery, function (err, resp) {
                $scope.showLoader = false;
                if (err) {
                    $scope.showFailureNotification("Failed to get student details");
                    $timeout(function () {
                        $rootScope.restoreBulkView();
                    }, 100);
                    return;
                } else {
                    $("html, body").animate({
                        scrollTop: 0
                    }, 500);

                    $scope.studentLists = [];
                    $rootScope.paginationOptions.recordCountForFilter = '';
                    $rootScope.paginationOptions.recordsTotal = '';

                    if (resp.data.length) {
                        $rootScope.paginationOptions.recordCountForFilter = resp.recordsFiltered;
                        $scope.studentLists = resp.data;
                        $rootScope.paginationOptions.recordsTotal = resp.recordsTotal;
                        commonService.checkbox($scope.studentLists, 'rollNumber');
                    }
                    resetBulkViewOptions(isConstructPaginationBar);
                    disableBulkOps();
                }
            });
        };

        $scope.triggerDropzoneUpload = function (photoStatus) {
            var dropZone = $('.dropzone-click' + photoStatus).get(0).dropzone;
            dropZone.hiddenFileInput.click();
        };

        function disableBulkOps() {
            $rootScope.viewModal.bulkOpContext = {
                'checkboxCounter': 0
            };
            $rootScope.viewModal.enableBulkOps = false;
            $rootScope.viewModal.bulkCheckBox = false;
        };

        function resetBulkViewOptions(isConstructPaginationBar) {
            if (isConstructPaginationBar) {
                // reset bulk operation context....
                if (!$scope.loadWithFilters()) {
                    disableBulkOps();
                }
                $rootScope.constructPaginationBar()
            }
            $timeout(function () {
                $rootScope.restoreBulkView();
            }, 100);
        };

        $rootScope.getData = function (isConstructPaginationBar, filters, search) {
            search = search ? search : $rootScope.searchParams.searchField;
            filters = filters ? filters : $rootScope.filter;
            $scope.getStudentRecords(isConstructPaginationBar, filters, search);
        };

        function getDistinctRollNumbers() {
            studentService.getDistinctValuesFromStudents("rollNumber", {}, function (err, res) {
                if (!err && res) {
                    res.sort(function (prevRollNo, nextRollNo) {
                        return prevRollNo - nextRollNo;
                    });
                    $scope.rollNumberList = res;
                }
            });
        };

        function getDistinctDummyRollNumbers() {
            studentService.getDistinctValuesFromStudents("dummyRollNumber", {}, function (err, res) {
                if (!err && res) {
                    res.sort(function (prevRollNo, nextRollNo) {
                        return prevRollNo - nextRollNo;
                    });
                    $scope.dummyRollNumberList = res;
                }
            });
        };

