        $scope.uploadFileToS3 = function (file, type, callback) {
            var query = {
                batchYear: $scope.batchYearTosetPath,
                fileName: file.name,
                type: type
            }

            studentService.getUploadUrl(query, function (err, res) {
                if (res && res.signedUrl) {
                    studentService.uploadFilesToS3(res.signedUrl, file, function (error, result) {
                        if (!error) {
                            file.signedRequest = res;
                            callback(null, file);
                            return;
                        } else {
                            callback(error, null);
                            return;
                        }
                    });
                } else {
                    callback("Photo cannot be uploaded as there is a server error", null);
                    return;
                }
            });
        };

        $scope.setDisplayPictureQuery = function (uploadRes) {
            $scope.uploadedDetails = {
                id: uploadRes.signedRequest.filePath,
                contentType: uploadRes.type,
                filename: uploadRes.signedRequest.fileName,
                originalname: uploadRes.name,
                size: uploadRes.size
            };
        };

        $scope.setDisplayPicture = function (displayPicture) {
            var query = displayPicture;
            studentService.getDownloadUrl(query, function (err, res) {
                if (res && res.signedUrl) {
                    $scope.displayPictureUrl = new URL(res.signedUrl);
                } else {
                    $scope.displayPictureUrl = "img/avatars/blank-photo.jpg";
                    //$scope.showFailureNotification("Failed to load the display picture (or) display picture not found.");
                    return;
                }
            });
        };

