        $scope.getFileFromS3 = function (file) {
            var query = file || {};
            if (file.filePath) {
                query.id = file.filePath
                delete query.filePath
            }
            studentService.getDownloadUrl(query, function (err, res) {
                if (res && res.signedUrl) {
                    studentService.getFileObjFromS3(res.signedUrl, function (err, res) {
                        if (res) {
                            const blob = new Blob([res], {
                                type: "image/jpg"
                            });
                            var url = URL.createObjectURL(blob);
                            var newWindow = window.open(url, '_blank');
                            newWindow.document.title = file.originalname;
                        }
                    });
                } else {
                    return;
                }
            });
        }

        $scope.signedUrls = {};

        $scope.validateExistingRollNumber = function () {
            if (!$scope.studentRecord.rollNumber) {
                $scope.isRollNumberEmpty = true;
                $scope.existingFlag = false;
                return { isValid: false, message: "Field is Required" };
            }

            $scope.isRollNumberEmpty = false;
            var rollNumber = $scope.studentRecord.rollNumber.toUpperCase();
            $scope.existingFlag = $scope.rollNumberList.includes(rollNumber) || $scope.dummyRollNumberList.includes(rollNumber);

            if ($scope.existingFlag) {
                return { isValid: false, message: "Roll number already is assigned to another as Roll number / Dummy Roll number" };
            }

            return true;
        }

        $scope.validateExistingDummyRollNumber = function () {
            if (!$scope.studentRecord.dummyRollNumber) {
                $scope.isDummyRollNumberEmpty = true;
                $scope.dummyRollNumberExistingFlag = false;
                return { isValid: false, message: "Field is Required" };
            }

            $scope.isDummyRollNumberEmpty = false;
            var dummyRollNumber = $scope.studentRecord.dummyRollNumber.toUpperCase();
            $scope.dummyRollNumberExistingFlag = $scope.dummyRollNumberList.includes(dummyRollNumber) || $scope.rollNumberList.includes(dummyRollNumber);

            if ($scope.dummyRollNumberExistingFlag) {
                return { isValid: false, message: "Dummy Roll number already is assigned to another as Roll number / Dummy Roll number" };
            }

            return true;
        };

