        function removeFieldFromSummary(summary, fieldName) {
            const index = summary.findIndex(e => e.field === fieldName);
            if (index !== -1) summary.splice(index, 1);
        }

        $scope.validateTheStartingDummyRollNo = function () {

            $scope.startingRollNoErrMsg = "";
            if ($scope.studentRecord.basic && !$scope.studentRecord.basic.startingRollNumber) {

                if (!$scope.addStudentInfo.$validationSummary) {
                    $scope.addStudentInfo.$validationSummary = [];
                }

                const summary = $scope.addStudentInfo.$validationSummary;

                if (!summary.some(e => e.field === "startingRollNumber")) {
                    summary.push({ field: "startingRollNumber", message: "Field is Required", formName: "addStudentInfo", friendlyName: "" });
                }

                $scope.startingRollNoErrMsg = "Field is Required";
                // return { isValid: false, message: "Field is Required" };
                trackCreateStudentForm();
                return "Field is Required"; // translation key
            }

            if ($scope.studentRecord.basic && $scope.studentRecord.basic.startingRollNumber) {
                if (!$scope.validateStartingRollNo($scope.studentRecord.basic.startingRollNumber)) {

                    if (!$scope.addStudentInfo.$validationSummary) {
                        $scope.addStudentInfo.$validationSummary = [];
                    }

                    const summary = $scope.addStudentInfo.$validationSummary;

                    if (!summary.some(e => e.field === "startingRollNumber")) {
                        summary.push({ field: "startingRollNumber", message: "Last two digits must be a number", formName: "addStudentInfo", friendlyName: "" });
                    }

                    $scope.startingRollNoErrMsg = "Last two digits must be a number";
                    // return { isValid: false, message: "Last two digits must be a number" };
                    trackCreateStudentForm();
                    return "Last two digits must be a number";
                }

                if (!$scope.isUniqueStartingRollNo($scope.studentRecord.basic.startingRollNumber)) {

                    if (!$scope.addStudentInfo.$validationSummary) {
                        $scope.addStudentInfo.$validationSummary = [];
                    }

                    const summary = $scope.addStudentInfo.$validationSummary;

                    if (!summary.some(e => e.field === "startingRollNumber")) {
                        summary.push({ field: "startingRollNumber", message: "Roll number already is assigned to another as Roll number / Dummy Roll number", formName: "addStudentInfo", friendlyName: "" });
                    }

                    $scope.startingRollNoErrMsg = "Roll number already is assigned to another as Roll number / Dummy Roll number";
                    // return { isValid: false, message: "Roll number already is assigned to another as Roll number / Dummy Roll number" };
                    trackCreateStudentForm();
                    return "Roll number already is assigned to another as Roll number / Dummy Roll number";
                }
            }

            removeFieldFromSummary($scope.addStudentInfo.$validationSummary, "startingRollNumber");
            trackCreateStudentForm();

            return true;
        }

        $scope.addStudentRecord = function () {
            if (new ValidationService().checkFormValidity($scope.addStudentInfo)) {
                if ($scope.uploadedDetails) {
                    $scope.studentRecord.displayPicture = $scope.uploadedDetails;
                }

                if ($scope.studentRecord.admissions?.guideDetails?.['$$hashKey']) {
                    delete $scope.studentRecord.admissions.guideDetails['$$hashKey']
                }

                $scope.studentRecord.certificate = $scope.certificate;
                $scope.showLoader = true;
                createStudent();
            };
        };

        function createStudent() {
            var user = $rootScope.Auth.principal.preferred_username;
            $scope.studentRecord.user = user;
            studentService.createStudentRecord($scope.studentRecord, function (err, response) {
                $scope.showLoader = false;
                $rootScope.getData(true, $rootScope.filter, $rootScope.searchParams.searchField);
                disableBulkOps();

                if (!err && response.length) {
                    $('#addStudentInfoModal').modal('hide');
                    $scope.clearFields();
                    $scope.clearValidation('addStudentInfo');
                    $scope.loadFilters();
                    $scope.showSuccessNotification("Successfully added the student with the Roll Number - " + ($scope.studentRecord.rollNumber || response[0].rollNumber));
                    document.body.scrollTop = document.documentElement.scrollTop = 0;
                    $scope.isMandatoryStartingRollNo = false;
                }
                else if (err.data && err.data.message && err.data.message == "No Student Found In This Semester & Batch !") {
                    $scope.isMandatoryStartingRollNo = true;
                    $('#addStudentModal').scrollTop(0);
                    $scope.showFailureNotificationInModal("No Student Found In This Semester & Batch!,Kindly enter starting roll number.");
                    document.body.scrollTop = document.documentElement.scrollTop = 0;
                } else if (err.data && err.data.message) {
                    $('#addStudentModal').scrollTop(0);
                    $scope.showFailureNotificationInModal("Error Found " + err.data.message);
                    document.body.scrollTop = document.documentElement.scrollTop = 0;
                }
                else {
                    $('#addStudentModal').scrollTop(0);
                    //$scope.clearFields();
                    //$scope.clearValidation('addStudentInfo');
                    $scope.showFailureNotificationInModal("Failed To Add Student");
                    document.body.scrollTop = document.documentElement.scrollTop = 0;
                }
            });
        };

