        $scope.updateSemester = function (formName) {
            if (new ValidationService().checkFormValidity($scope[formName])) {

                var query = {}, rollNumbers = {};
                $scope.showLoader = true;

                if ($scope.multipleSelection) {
                    $scope.semToUpdate = $scope.bulkSemester;
                    if (Object.keys($scope.searchQuery.filter).length) {
                        query.filter = JSON.parse(JSON.stringify($scope.searchQuery.filter));
                    }

                    if ($scope.searchQuery.search) {
                        query.search = $scope.searchQuery.search;
                    }

                    if ($rootScope.viewModal.bulkOpContext.selectedItems.length) {
                        rollNumbers["selectedIds"] = $rootScope.viewModal.bulkOpContext.selectedItems;
                    } else if ($rootScope.viewModal.bulkOpContext.uncheckedSelectedItems.length) {
                        rollNumbers["unSelectedIds"] = $rootScope.viewModal.bulkOpContext.uncheckedSelectedItems;
                    }
                } else {
                    $scope.semToUpdate = $scope.student.currentSem;
                    rollNumbers["selectedIds"] = [$scope.student.rollNumber];
                }

                studentService.updateCurrentSemester(rollNumbers, query, $scope.semToUpdate, $rootScope.Auth.principal.preferred_username, function (err, response) {
                    $scope.showLoader = false;
                    if (!err && response) {
                        if (response.modifiedCount > 0) {
                            $scope.showSuccessNotification(
                                "Successfully updated the current semester to " + $scope.semToUpdate +
                                " for " + response.modifiedCount + " students."
                            );
                        }
                        // else if (response.modifiedCount === 1) {
                        //     $scope.showSuccessNotification(
                        //         "Successfully updated the current semester to " + $scope.semToUpdate +
                        //         " for student with roll number " + $scope.student.rollNumber + "."
                        //     );
                        // }
                        else if (response.modifiedCount === 0) {
                            $scope.showSuccessNotification(
                                "All students are already up to date with entered current semester."
                            );
                        }
                        $rootScope.getData(true, $rootScope.filter, $rootScope.searchParams.searchField);
                    } else {
                        $scope.showFailureNotification("Failed to update the current semester. Please try again.");
                    }
                    $('#updateCurrentSemModal, #updateBulkCurrentSemModal').modal('hide');
                    $scope.clearValidation($scope[formName]);
                });
            }
        }

