        function getBranchName(student) {
            if (student.tcDetails && student.tcIssued == "YES") {
                return student.tcDetails.programmeName;
            } else if (student.programmeName) {
                return (getYear($scope.brandingInfo.details.tcStudentYearToCompute, student.batchYear) + " - " + student.programmeName);
            } else {
                return "";
            }
        };

        function getYear(passOutYear, batchYear) {
            var year = "";
            switch (passOutYear - batchYear) {
                case 1:
                    year = "I";
                    break;
                case 2:
                    year = "II";
                    break;
                case 3:
                    year = "III";
                    break;
                case 4:
                    year = "IV";
                    break;
                case 5:
                    year = "V";
                    break;
                default:
                    year = "I";
                    break;
            }
            return year;
        };

        var communityMap = {};
        communityMap["OC"] = "OC";
        communityMap["BC-OTHERS"] = "BC";
        communityMap["BC-MUSLIM"] = "BCM";
        communityMap["MBC-V"] = "MBC-V";
        communityMap["MBC-DNC"] = "MBC-DNC";
        communityMap["MBC_DNC"] = "MBC-DNC";
        communityMap["MBC-O"] = "MBC-O";
        communityMap["DNC"] = "DNC";
        communityMap["SC"] = "SC";
        communityMap["SCA"] = "SCA";
        communityMap["ST"] = "ST";
        communityMap["BC"] = "BC";
        communityMap["BCM"] = "BCM";
        communityMap["MBC"] = "MBC";
        communityMap["--"] = "--";
        communityMap["DNC/DNT"] = "DNC/DNT";

        function getCommunity(community) {
            return (communityMap[community]) ? communityMap[community] : community.toUpperCase();
        };

        function getFirstLang(student) {
            if (student.admissions && student.admissions.preferredLanguage) {
                return student.admissions.preferredLanguage;
            } else {
                return "NOT APPLICABLE";
            }
        };

        var religionMap = {};
        religionMap["HINDUISM"] = "HINDU";
        religionMap["CHRISTIANITY"] = "CHRISTIAN";
        religionMap["JAINISM"] = "JAIN";

        function getReligion(religion) {
            return (religionMap[religion]) ? religionMap[religion].toUpperCase() : religion.toUpperCase();
        };

        function setTcDetails(studentDetails) {

            $scope.studentDetails = studentDetails;

            $scope.detailsToEditTC.rollNumber = (studentDetails.tcDetails && studentDetails.tcDetails.rollNumber) ? studentDetails.tcDetails.rollNumber : studentDetails.rollNumber;

            $scope.detailsToEditTC.name = (studentDetails.tcDetails && studentDetails.tcDetails.name) ? studentDetails.tcDetails.name : studentDetails.name;

            $scope.detailsToEditTC.department = (studentDetails.tcDetails && studentDetails.tcDetails.department) ? studentDetails.tcDetails.department : studentDetails.department;

            $scope.detailsToEditTC.programmeName = (studentDetails.tcDetails && studentDetails.tcDetails.programmeName) ? studentDetails.tcDetails.programmeName : getBranchName(studentDetails);

            $scope.detailsToEditTC.fatherName = (studentDetails.tcDetails && studentDetails.tcDetails.fatherName) ? studentDetails.tcDetails.fatherName : mapFatherOrGuardian(studentDetails);

            $scope.detailsToEditTC.dob = (studentDetails.tcDetails && studentDetails.tcDetails.dob) ? moment(studentDetails.tcDetails.dob, "YYYY-MM-DD").format("DD-MM-YYYY") : moment(studentDetails.basic.dob, ["DD-MMM-YYYY", "YYYY-MM-DD",]).format("DD-MM-YYYY");

            $scope.detailsToEditTC.country = (studentDetails.tcDetails && studentDetails.tcDetails.country) ? studentDetails.tcDetails.country : (studentDetails.basic && studentDetails.basic.nationality) ? studentDetails.basic.nationality : null;

            // $scope.detailsToEditTC.religion = (studentDetails.tcDetails && studentDetails.tcDetails.religion) ? studentDetails.tcDetails.religion : (studentDetails.basic && studentDetails.basic.religion) ? getReligion(studentDetails.basic.religion) : null;

            $scope.detailsToEditTC.religion = (studentDetails.tcDetails && studentDetails.tcDetails.religion) ? studentDetails.tcDetails.religion : "REFER COMMUNITY CERTIFICATE";

            // $scope.detailsToEditTC.caste = (studentDetails.tcDetails && studentDetails.tcDetails.caste) ? studentDetails.tcDetails.caste : (studentDetails.basic && studentDetails.basic.caste) ? studentDetails.basic.caste : null;

            $scope.detailsToEditTC.caste = (studentDetails.tcDetails && studentDetails.tcDetails.caste) ? studentDetails.tcDetails.caste : "REFER COMMUNITY CERTIFICATE";

            // $scope.detailsToEditTC.community = (studentDetails.tcDetails && studentDetails.tcDetails.community) ? studentDetails.tcDetails.community : (studentDetails.basic && studentDetails.basic.community) ? getCommunity(studentDetails.basic.community) : null;

            $scope.detailsToEditTC.community = (studentDetails.tcDetails && studentDetails.tcDetails.community) ? studentDetails.tcDetails.community : "REFER COMMUNITY CERTIFICATE";

            $scope.detailsToEditTC.firstLang = (studentDetails.tcDetails && studentDetails.tcDetails.firstLang) ? studentDetails.tcDetails.firstLang : ((['PG', 'PGD'].includes(studentDetails.programType)) ? "NA" : getFirstLang(studentDetails));

            $scope.detailsToEditTC.medium = (studentDetails.tcDetails && studentDetails.tcDetails.medium) ? studentDetails.tcDetails.medium : "ENGLISH";

            $scope.detailsToEditTC.tcDate = (studentDetails.tcDetails && studentDetails.tcDetails.tcDate) ?
                moment(studentDetails.tcDetails.tcDate, "YYYY-MM-DD").format("DD-MM-YYYY") : null;

            $scope.detailsToEditTC.lastAttendedDate = (studentDetails.tcDetails && studentDetails.tcDetails.lastAttendedDate) ?
                moment(studentDetails.tcDetails.lastAttendedDate, "YYYY-MM-DD").format("DD-MM-YYYY") : null;

            $scope.detailsToEditTC.conduct = (studentDetails.tcDetails && studentDetails.tcDetails.conduct) ? studentDetails.tcDetails.conduct : null;

            $scope.detailsToEditTC.tcReason = (studentDetails.tcDetails && studentDetails.tcDetails.tcReason) ? studentDetails.tcDetails.tcReason : null;

            $scope.detailsToEditTC.tcIssued = (studentDetails.tcIssued) ? studentDetails.tcIssued : "NO";

        }

        function mapFatherOrGuardian(student) {
            var name = '';

            if (!student.family || !student.family.members || !student.family.members.length) {
                return name;
            }

            for (var i = 0; i < student.family.members.length; i++) {
                if (student.family.members[i].type === 'FATHER') {
                    name = student.family.members[i].name;
                    if (name) return name;
                }
            }

            for (var i = 0; i < student.family.members.length; i++) {
                if (student.family.members[i].type === 'MOTHER') {
                    name = student.family.members[i].name;
                    if (name) return name;
                }
            }

            for (var i = 0; i < student.family.members.length; i++) {
                if (student.family.members[i].type === 'GUARDIAN') {
                    name = student.family.members[i].name;
                    if (name) return name;
                }
            }
            return name;
        };

        function findNameBy(type, familyInfo) {
            var name = "";

            if (Array.isArray(familyInfo) && familyInfo.length) {
                familyInfo.forEach(function (data) {
                    if (data.type == type) {
                        name = data.name;
                    }
                })
            }

            return name;
        }

