        $scope.revokeTC = function () {
            if (new ValidationService().checkFormValidity($scope.revokeTcForm)) {
                $scope.showLoader = true;
                var rollNumbers = {};
                var query = {};

                if ($scope.multipleSelection) {
                    if (Object.keys($scope.searchQuery).length) {
                        query = JSON.parse(JSON.stringify($scope.searchQuery));
                    }

                    $rootScope.searchParams.searchField = "";
                    if ($rootScope.viewModal.bulkOpContext.selectedItems.length) {
                        rollNumbers["selectedIds"] = $rootScope.viewModal.bulkOpContext.selectedItems;
                    } else if ($rootScope.viewModal.bulkOpContext.uncheckedSelectedItems.length) {
                        rollNumbers["unSelectedIds"] = $rootScope.viewModal.bulkOpContext.uncheckedSelectedItems;
                    }

                } else {
                    rollNumbers["selectedIds"] = [$scope.rollNumber];
                }

                var user = $rootScope.Auth.principal.preferred_username;
                $scope.record.user = user;
                $scope.record.status = $rootScope.status["Active"];

                studentService.revokeTC(rollNumbers, query, $scope.record, function (err, response) {
                    $rootScope.getData(true, $rootScope.filter, $rootScope.searchParams.searchField);
                    disableBulkOps();
                    $scope.showLoader = false;
                    $('#revokeTCModal').modal('hide');

                    if (!err && response && response.modifiedCount) {
                        if (rollNumbers && rollNumbers.selectedIds && rollNumbers.selectedIds.length == 1) {
                            $scope.showSuccessNotification("Successfully revoked TC for student " + rollNumbers.selectedIds[0]);
                            $scope.clearFields();
                            $scope.clearValidation('revokeTcForm');
                            return;
                        }
                        $scope.showSuccessNotification("Successfully revoked TC for " + response.modifiedCount + " student(s)");
                    } else if (err && err.data && err.data.message == "Cannot create property 'enabled' on boolean 'false'") {
                        $scope.showFailureNotification("TC Revoked,But Keycloak account not found.So can't enable account.");
                    } else {
                        $scope.showFailureNotification("Failed to update the status : IN-Active to Active student(s)");

                    }
                    $scope.clearFields();
                    $scope.clearValidation('revokeTcForm');
                });
            }
        }

