        $scope.resetFlatpicker = function (list) {
            for (var i = 0; i < list.length; i++) {
                new flatpickr('#' + list[i], {
                    dateFormat: 'd/M/Y',
                    // maxDate: 'today',
                    defaultDate: 'null',
                    wrap: true,
                    closeOnSelect: true
                })
            }
        }

