        $scope.studentList = function () {
            var query = {};

            if ($scope.search.programType) {
                query["programType"] = $scope.search.programType;
            }

            if ($scope.search.programCategory) {
                query["programCategory"] = $scope.search.programCategory;
            }

            if ($scope.search.programmeName && $scope.search.programmeName.length) {
                query["programmeName"] = { $in: $scope.search.programmeName }
            }

            if ($scope.search.programMode && $scope.search.programMode.length) {
                query["programMode"] = { $in: $scope.search.programMode };
            }

            if ($scope.search.degreeName && $scope.search.degreeName.length) {
                query["degreeName"] = { $in: $scope.search.degreeName };
            }

            if ($scope.search.batchYear && $scope.search.batchYear.length) {
                query["batchYear"] = { $in: $scope.search.batchYear }
            }

            if ($scope.search.section) {
                query["section"] = $scope.search.section;
            }

            if ($scope.search.status) {
                query["status"] = $rootScope.status[$scope.search.status];
            }

            if ($scope.search.statusReason) {
                query["statusReason"] = $scope.search.statusReason;
            }

            if ($scope.search.tcIssued) {
                query["tcIssued"] = $scope.search.tcIssued;
            }

            if (![null, undefined, ''].includes($scope.search.registrationFormStatus)) {
                query["registrationFormStatus"] = $scope.search.registrationFormStatus;
            }

            if (![null, undefined, ''].includes($scope.search.isKeycloakEnabled)) {
                query["isKeycloakEnabled"] = $scope.search.isKeycloakEnabled;
            }

            if ($scope.search.exitFormStatus) {
                query["exitFormStatus"] = $scope.enumsList.exitFormStatus[$scope.search.exitFormStatus];
            }

            if ($scope.search.programCode) {
                query["programCode"] = $scope.search.programCode
            }

            if ($rootScope.Auth.principal.userRoles && ($rootScope.Auth.principal.userRoles['DEPUTY_WARDEN'] || $rootScope.Auth.principal.userRoles['STUDENTS_SECTION'] || $rootScope.Auth.principal.userRoles['ADMISSION_ADMIN'] || $rootScope.Auth.principal.userRoles['ADMIN'])) {

            } else if (!checkRoleForFilters()) {
                if (Object.keys($rootScope.rolesInGroups).includes("HEAD")) {
                    query["nodeIds"] = $rootScope.rolesInGroups["HEAD"];
                }

                if (Object.keys($rootScope.rolesInGroups).includes("HEAD-INCHARGE")) {
                    query["nodeIds"] = $rootScope.rolesInGroups["HEAD-INCHARGE"];
                }

                if (Object.keys($rootScope.rolesInGroups).includes("CLASS-TUTOR")) {
                    query["tutorId"] = $rootScope.Auth.principal.preferred_username.toUpperCase();
                }
            }

            $scope.showLoader = true;
            studentService.studentList(query, function (err, response) {
                if (!err && response) {
                    const blob = new Blob([response], {
                        type: "application/xlsx",
                    });
                    const dateAndTime = moment().format("DD-MM-YYYY-HH-mm-ss");
                    const excelFileName = "Students List" + dateAndTime + ".xlsx";
                    $rootScope.saveBlob(blob, excelFileName);
                } else if (err && err.message) {
                    $scope.showFailureNotification(err.message);
                }
                else {
                    $scope.showFailureNotification("Kindly refresh & try again");
                }
                $scope.showLoader = false;
            });

        };

