        $scope.isValidPercentage = function () {
            if ($scope.studentRecord &&
                $scope.studentRecord.admissions &&
                $scope.studentRecord.admissions.percentage &&
                ($scope.studentRecord.admissions.percentage > 100 || $scope.studentRecord.admissions.percentage < 0)) {
                $("#percentageAlert").css('display', 'block');
                return false;
            } else {
                $("#percentageAlert").css('display', 'none');
                return true;
            }
        }

        $scope.deActivateKeycloakAccount = function (index, multiple) {
            var { rollNumbers, query } = multipleSelector(index, multiple);
            var title = "Are you sure ?"
            var students
            if (!multiple) {
                students = $scope.studentLists[index].rollNumber;
            } else {
                students = $rootScope.viewModal.bulkOpContext.checkboxCounter;
            }

            var message = $sce.trustAsHtml("Do you want to De-activate account for " + '<strong>' + students + '</strong>' + " Student(s) ?")

            $scope.confirmationModelCallback(title, message, "DE-ACTIVATE", function (res) {
                if (res) {
                    $scope.showLoader = true;
                    studentService.deActivateKeycloakAccount(rollNumbers, query, function (err, res) {
                        if (!err) {
                            $scope.showLoader = false;
                            $scope.showSuccessNotification("De-Activated account successfully for " + res.success.length + " students And Failed for " + res.failed.length);
                            $rootScope.getData(true, $rootScope.filter, $rootScope.searchParams.searchField);

                        } else {
                            $scope.showFailureNotification("Failed to De-activate account(s)");
                        }
                    })
                }
            })
        }

