(function () {
    'use strict';
    var App = angular.module('app');
    App.controller('configurationSetupCtrl', configurationSetupCtrl);
    configurationSetupCtrl.$inject = ["$scope", "$timeout", "$rootScope", "ValidationService", "commonService", "configService"];
    function configurationSetupCtrl($scope, $timeout, $rootScope, ValidationService, commonService, configService) {
        $scope.filter = {};

        $scope.$validationOptions = {
            debounce: 1500,
            preValidateFormElements: false,
            isolatedScope: $scope,
        };


        $scope.checkEnter = function (event, roleToAdd) {
            // 13 is the Enter key
            if (event.which != 13) {
                return;
            }

            $scope.addRole(roleToAdd);
        }

        $scope.cloneObject = function (cloneFrom, state, keyToClone) {
            if (!keyToClone) {
                $scope.configurationsData.roles[$scope.selectedRole] = JSON.parse(JSON.stringify($scope.configurationsData.roles[cloneFrom]));
                $scope.roleDetails = JSON.parse(JSON.stringify($scope.configurationsData.roles[cloneFrom]));
                return;
            }

            var actionsForCloneFrom = $scope.configurationsData.roles[cloneFrom].find(function (item) {
                return item.name === state.name
            })

            var actionsForCloneTo = $scope.roleDetails.find(function (item) {
                return item.name === state.name
            })


            actionsForCloneTo[keyToClone] = JSON.parse(JSON.stringify(actionsForCloneFrom[keyToClone]));
        }

        $scope.closeModal = function () {
            $scope.roleDetails = [];
            $scope.newRole = null;
            $scope.showAddRoleBox = false;
        }

        function callPopover() {
            $timeout(function () {
                $('[data-toggle="popover"]').popover();
            }, 500)
        }

        $scope.toggleTUVCertLogo = function () {
            callPopover();
        }

        $scope.setRoleEnvironment = function (role, roleDetails) {
            $scope.roleDetails = roleDetails;
            $scope.selectedRole = role;
            $('#groupTab.nav-tabs a').removeClass('active');
            $('[id="' + role + '-tab"]').toggleClass('active');
        }

        $rootScope.getData = function (isConstructPaginationBar, filters, search) {
            search = search ? search : $rootScope.searchParams.searchField;
            filters = filters ? filters : $rootScope.filter;
            getConfigurations(isConstructPaginationBar, filters, search);
        }

        function getConfigurations(isConstructPaginationBar, filter, search) {
            var options = $rootScope.calcSkipLimitValueForPagination(isConstructPaginationBar);
            var searchQuery = {
                filter: {},
            };

            searchQuery.length = options.limitValue;
            searchQuery.start = options.skipValue;
            searchQuery.order = $scope.sorting;
            delete options.skipValue;
            delete options.limitValue;

            if (search) {
                searchQuery.search = {
                    value: search,
                };
            }

            $rootScope.preloader = true;
            configService.getPaginateRecords(searchQuery, function (error, response) {
                $rootScope.preloader = false;
                if (error) {
                    return commonService.showErrorMessage($scope, 'errorMsg', 'errorMsgContent', "Error while retrieving all configurations details, try again");
                }

                $scope.configurations = [];
                $rootScope.paginationOptions.recordCountForFilter = '';
                $rootScope.paginationOptions.recordsTotal = '';

                if (response.data.length) {
                    $rootScope.paginationOptions.recordCountForFilter = response.recordsFiltered;
                    $scope.configurations = response.data;
                    $rootScope.paginationOptions.recordsTotal = response.recordsTotal;
                    $rootScope.constructPaginationBar()
                }
            });

        }

        $scope.viewConfig = function (id) {
            $scope.showBtn = false;
            $scope.disableSwitch = true;
            $scope.editable = false;
            getData(id);
        }

        function getData(data) {
            $scope.configurationsData = {};

            configService.getConfigDetails(data._id, function (err, res) {
                if (err) {
                    return commonService.showErrorMessage($scope, 'errorMsg', 'errorMsgContent', "Error while retrieving configurations details, try again");
                }

                $scope.configurationsData = JSON.parse(JSON.stringify(res));

                if (data.type === "ACCESSCONTROL") {
                    var keys = Object.keys($scope.configurationsData.roles);
                    $scope.roleDetails = $scope.configurationsData.roles[keys[0]];
                    $scope.selectedRole = keys[0];
                    $scope.totalRoleData = Object.keys($scope.configurationsData.roles).length;
                }

                angular.element("#" + $scope.configurationsData.type).modal('show');

                callPopover();
            })
        }

        commonService.setDefaultSorting('_id', -1);
        commonService.search();
        commonService.sorting();
        commonService.filters();
        commonService.pagination();
        commonService.checkbox();

        $rootScope.getData(true, $rootScope.filter, $rootScope.searchParams.searchField, $rootScope.sorting);


        $scope.getLastModified = function (date) {
            return moment(date).fromNow();
        }

        $scope.editConfig = function (id) {
            new ValidationService().resetForm($scope.brandForm);
            $scope.captchaOptions = {
                confirmText: "",
                originalText: "EDIT"
            };

            $scope.showBtn = true;
            $scope.disableSwitch = false;
            $scope.editable = true;
            getData(id);
        }

        $scope.changeLogo = function (name) {
            $scope.mainHeaderLogo = name;
        }

        $scope.checkObject = function (obj) {
            if (!obj) {
                return 0;
            }

            return Object.keys(obj).length;
        }

        $scope.updateBrand = function () {
            if (!(new ValidationService().checkFormValidity($scope.brandForm))) {
                return;
            }

            $rootScope.preloader = true;
            configService.updateBrand($scope.configurationsData._id, $scope.configurationsData, function (error, response) {
                $rootScope.preloader = false;
                if (error) {
                    $('#BRAND-SCROLL').scrollTop(0);
                    return commonService.showErrorMessage($scope, 'modalErrorMsg', 'modalErrorMsgContent', "Error while updating configurations details, try again");
                }
                angular.element("#" + $scope.configurationsData.type).modal('hide');
                window.location.reload();
            })
        }

        $scope.changeLandingPageValues = function (currentState) {
            $scope.roleDetails.forEach(function (role) {
                if (role.name != currentState.name) {
                    delete role.isLandingPage;
                }
            });
        }

        $scope.updateAccessControl = function () {
            var error = { roles: [], messages: [] };
            $rootScope.showLoader = true;
            var isAllFalse = true;
            var roles = Object.keys($scope.configurationsData.roles);

            for (var i = 0; i < roles.length; i++) {
                for (var j = 0; j < $scope.configurationsData.roles[roles[i]].length; j++) {
                    if ($scope.configurationsData.roles[roles[i]][j].isLandingPage && !$scope.configurationsData.roles[roles[i]][j].isEnabled) {
                        error.isErrored = true;
                        error.roles.push(roles[i]);
                        error.messages.push('Cannot select Landing page which is not Enabled for role ' + roles[i] + ' ');
                    }

                    if ($scope.configurationsData.roles[roles[i]][j].isEnabled) {
                        isAllFalse = false;
                    }
                }

                if (isAllFalse) {
                    error.isErrored = true;
                    error.roles.push(roles[i]);
                    error.messages.push('Must enable atleast one page for role ' + roles[i] + ' ');
                } else {
                    isAllFalse = true;
                }
            }

            if (error.isErrored) {
                $('#BRAND-SCROLL').scrollTop(0);
                commonService.showErrorMessage($scope, 'modalErrorMsg', 'modalErrorMsgContent', error.messages.toString());
                $rootScope.showLoader = false;
                return;
            }


            configService.updateAccessControl($scope.configurationsData._id, $scope.configurationsData, function (error, response) {
                $rootScope.showLoader = false;
                if (error) {
                    $('#BRAND-SCROLL').scrollTop(0);
                    return commonService.showErrorMessage($scope, 'modalErrorMsg', 'modalErrorMsgContent', "Error while updating configurations details, try again");
                }
                angular.element("#" + $scope.configurationsData.type).modal('hide');
                window.location.reload();
            })
        }

        $scope.setRoleAddEnv = function () {
            $('#BRAND-SCROLL').scrollTop(0);
            $scope.showAddRoleBox = true;
        }

        $scope.removeRole = function (roleToDelete, index) {
            if (!roleToDelete) {
                return;
            }

            //after removing a role it should select the previous role in UI.
            var keys = Object.keys($scope.configurationsData.roles);
            $scope.roleDetails = $scope.configurationsData.roles[keys[index - 1]];
            $scope.selectedRole = keys[index - 1];
            $('#groupTab.nav-tabs a').removeClass('active');
            $('[id="' + keys[index - 1] + '-tab"]').toggleClass('active');

            delete $scope.configurationsData.roles[roleToDelete];
        }

        $scope.addRole = function (roleToAdd) {
            if (!roleToAdd) {
                return commonService.showErrorMessage($scope, 'modalErrorMsg', 'modalErrorMsgContent', "Need a name to add Role.");
            }

            var allRoles = Object.keys($scope.configurationsData.roles);
            if (allRoles.includes(roleToAdd)) {
                return commonService.showErrorMessage($scope, 'modalErrorMsg', 'modalErrorMsgContent', "Role name already present");
            }

            //To avoid circular dependency
            var roleSchema = JSON.parse(JSON.stringify($scope.configurationsData.defaultValue));
            $scope.configurationsData.roles[roleToAdd] = roleSchema;

            $scope.roleDetails = $scope.configurationsData.roles[roleToAdd];
            $scope.selectedRole = roleToAdd;

            //after adding new role it should show the new roles Pages in UI.
            setTimeout(function () {
                $('#groupTab.nav-tabs a').removeClass('active');
                $('[id="' + roleToAdd + '-tab"]').toggleClass('active');
            }, 300);

            $scope.showAddRoleBox = false;
        }

        $scope.closeRoleBox = function () {
            $scope.showAddRoleBox = false;
        }

        $scope.attachments = {
            dzOptions: {
                url: "#",
                method: "put",
                parallelUploads: 1,
                acceptedFiles: '.jpeg,.jpg,.png',
                autoProcessQueue: true,
                maxFilesize: 3,
                maxFiles: 1,
                uploadMultiple: false,
                paramName: function () {
                    return "logo";
                },
                init: function () {
                    this.on("addedFile", function (file) {
                        this.removeAllFiles();
                    });
                    this.on("success", function (file) {
                        this.removeAllFiles();
                    });
                    this.on("error", function (file) {
                        this.removeAllFiles();
                    });
                },
                accept: function (file) {
                    if (!$scope.configurationsData.previewUrl) {
                        $scope.configurationsData.previewUrl = {};
                    }

                    $scope.configurationsData.previewUrl[$scope.mainHeaderLogo] = {
                        "fileUrl": URL.createObjectURL(file),
                        "fileName": file.name,
                        "fileType": file.type,
                        "on": new Date()
                    };

                    // BlobService.blobUrlToArrayBuffer($scope.configurationsData.previewUrl[$scope.mainHeaderLogo]).then(function (arrayBuffer) {
                    //     $scope.configurationsData.details[$scope.mainHeaderLogo] = arrayBufferToBase64(arrayBuffer);
                    // }).catch(function (error) {
                    //     console.error("Error:", error);
                    // });

                    fileToArrayBuffer(file).then((arrayBuffer) => {
                        $scope.configurationsData.details[$scope.mainHeaderLogo] = arrayBufferToBase64(arrayBuffer);
                    }).catch((error) => {
                        console.error("Error converting file:", error);
                    });
                }
            },
            dzCallbacks: {
                init: function () {
                    this.on("addedfile", function (file) {
                        this.removeFile(file);
                    });
                },
                "addedfile": function (file) {
                    $(".dz-preview").css('display', 'none');
                    $(".dz-file-preview ").css('display', 'none');
                },
                "removedfile": function (file) {
                },
                "success": function (file, xhr) {
                    file
                    getData($scope.configurationsData._id, true);
                },
                "error": function (file, error) {
                    $('#BRAND-SCROLL').scrollTop(0);
                    commonService.showErrorMessage($scope, 'modalErrorMsg', 'modalErrorMsgContent', error);
                },
                "complete": function (file) {
                }
            },
            dzMethods: {
            }
        };

        function fileToArrayBuffer(file) {
            return new Promise((resolve, reject) => {
                const reader = new FileReader();
                reader.onload = function (event) {
                    resolve(event.target.result);
                };
                reader.onerror = function (error) {
                    reject(error);
                };
                reader.readAsArrayBuffer(file);
            });
        }

        function arrayBufferToBase64(buffer) {
            let binary = '';
            const bytes = new Uint8Array(buffer);
            const len = bytes.byteLength;

            for (let i = 0; i < len; i++) {
                binary += String.fromCharCode(bytes[i]);
            }

            return window.btoa(binary);
        }
    }
})();;
(function () {
    'use strict';
    var App = angular.module('app');
    App.directive('masterDataView', masterDataView);
    masterDataView.$inject = ['$rootScope', '$compile'];
    function masterDataView($rootScope, $compile) {
        return {
            restrict: 'EA',
            templateUrl: 'app/modules/masterData/masterData.html',
            controller: 'masterDataController',
            replace: true,
            scope: true
        };
    }

    App.controller('masterDataController', masterDataController);
    masterDataController.$inject = ['$scope', '$localStorage', '$window', '$timeout', '$rootScope', '$state', '$stateParams', 'studentService', 'lookupService', 'ValidationService'];
    function masterDataController($scope, $localStorage, $window, $timeout, $rootScope, $state, $stateParams, studentService, lookupService, ValidationService) {

        // if (($rootScope.Auth.principal.userRoles) && ($rootScope.Auth.principal.userRoles['STUDENT']) && (!$rootScope.Auth.principal.userRoles['ADMIN'])) {
        //     $state.go('studentprofileview', { rollNumber: $rootScope.Auth.principal.preferred_username });
        //     return;
        // }

        getLookupList();

        $scope.$validationOptions = {
            debounce: 1500,
            preValidateFormElements: false,
            isolatedScope: $scope,
        };

        function getLookupList() {
            lookupService.getAllRecords(function (err, result) {
                if (!err) {
                    $scope.commonData = result.filter(function (res) {
                        return res.tabName === "commonData"
                    })
                    $scope.commonData.forEach(function (element) {
                        setLookupValues(element);
                    });

                    $scope.basicInformation = result.filter(function (res) {
                        return res.tabName === "personalData"
                    })
                    $scope.basicInformation.forEach(function (element) {
                        setLookupValues(element);
                    });

                    $scope.familyInformation = result.filter(function (res) {
                        return res.tabName === "familyData"
                    })
                    $scope.familyInformation.forEach(function (element) {
                        setLookupValues(element);
                    });

                    $scope.academicInformation = result.filter(function (res) {
                        return res.tabName === "academicData"
                    })
                    $scope.academicInformation.forEach(function (element) {
                        setLookupValues(element);
                    });

                    $scope.basicComputerInformation = result.filter(function (res) {
                        return res.tabName === "skillsData"
                    })
                    $scope.basicComputerInformation.forEach(function (element) {
                        setLookupValues(element);
                    });
                    $scope.specialCategories = result.filter(function (res) {
                        return res.tabName === "specialCategories";
                    })
                    $scope.specialCategories.forEach(function (element) {
                        setLookupValues(element);
                    });
                    $scope.noDuesCategories = result.filter(function (res) {
                        return res.tabName === "noDues";
                    })
                    $scope.noDuesCategories.forEach(function (element) {
                        setLookupValues(element);
                    });
                }
            });
        };

        function setLookupValues(element) {
            if (element.values.length) {
                if (element.values.length > 10) {
                    element.format = sort(element.values).slice(0, 10).join(", ");
                    element.format = element.format + " .... ";
                }
                else {
                    element.format = sort(element.values).join(", ");
                }
            }
            return;
        };

        function sort(arrValues) {
            if (arrValues.length > 0) {
                arrValues.sort(function (a, b) {
                    if (a < b) return -1;
                    else if (a > b) return 1;
                    return 0;
                });
            }
            return arrValues;
        };

        // $scope.editLookupModal = function (list) {
        //     lookupService.loadDataFields(list.key, function (err, response) {
        //         if (!err) {
        //             $scope.isReadOnly = list.isReadOnly;
        //             $scope.lookupList = {};
        //             $scope.tempList = {};
        //             $scope.lookupList.key = list.key;
        //             $scope.lookupList.values = [];
        //             $timeout(function () {
        //                 $("#editKeyValueModal").modal('show');
        //                 $scope.lookupList.values = sort(response);
        //                 $scope.tempList.key = list.key;
        //                 $scope.tempList.values = JSON.parse(JSON.stringify($scope.lookupList.values));
        //             }, 200);
        //         }
        //     });
        // };


        $scope.editLookupModal = function (key) {
            $scope.keyValue = {};
            $scope.isReadOnly = key.isReadOnly;
            $scope.isNoEdit = key.isNoEdit;
            $timeout(function () {
                $("#editKeyValueModal").modal('show')
                $scope.keyValue = JSON.parse(JSON.stringify(key));
                $scope.values = JSON.parse(JSON.stringify(key.values));
            }, 200);
        }

        // $scope.isLookupDuplicate = function(){
        //     if (!$scope.keyValue.key.values){
        //         return;
        //     }

        //     var normalizedLookupValues = $scope.keyValue.key.values.map(function (value) {
        //         return value.toUpperCase();
        //     })

        //     var lookupArray = new Set(normalizedLookupValues);
        //     return lookupArray.size != normalizedLookupValues.length;
        // }

        $scope.handleCommaSplit = function (values) {
            if (!values || !values.text) return;

            if (values.text.indexOf(',') !== -1) {

                // Remove original combined tag
                var index = $scope.keyValue.values.indexOf(values);
                if (index > -1) {
                    $scope.keyValue.values.splice(index, 1);
                }

                values.text.split(',').forEach(function (val) {
                    val = val.trim();

                    if (!val) return;

                    // Check duplicate (case-insensitive)
                    var exists = $scope.keyValue.values.some(function (item) {
                        return item.text.toLowerCase() === val.toLowerCase();
                    });

                    if (!exists) {
                        $scope.keyValue.values.push({ text: val });
                    }
                });
            }
        };

        $scope.newCommaSplit = function (values) {
            if (!values || !values.text) return;

            if (values.text.indexOf(',') !== -1) {

                // Remove original combined tag
                var index = $scope.keyValue.newValues.indexOf(values);
                if (index > -1) {
                    $scope.keyValue.newValues.splice(index, 1);
                }

                values.text.split(',').forEach(function (val) {
                    val = val.trim();

                    if (!val) return;

                    // Check duplicate (case-insensitive)
                    var exists = $scope.keyValue.newValues.some(function (item) {
                        return item.text.toLowerCase() === val.toLowerCase();
                    });

                    if (!exists) {
                        $scope.keyValue.newValues.push({ text: val });
                    }
                });
            }
        }


        $scope.updateElementsinLookup = function updateElementsinLookup() {
            if (!new ValidationService().checkFormValidity($scope.dataManagementForm)) {
                return;
            }

            var values = []

            $scope.keyValue.values.forEach(function (item) {
                values.push(item.text)
            })

            if ($scope.keyValue.newValues && $scope.keyValue.newValues.length) {
                $scope.keyValue.newValues.forEach(function (item) {
                    values.push(item.text)
                })
            }

            lookupService.updateElementsinLookup($scope.keyValue.key, values, function (err, res) {
                getLookupList();
                $("#editKeyValueModal").modal('hide');
                if (!err) {
                    $scope.showSuccessNotification("Changes Updated Successfully!");
                    $rootScope.loadLookups($scope.keyValue.key);
                } else {
                    $scope.showFailureNotification("Failed to Update. Please refresh and retry again");
                }
                $("html, body").animate({
                    scrollTop: 0
                }, 500);
            });
        };

        $scope.showSuccessNotification = function (message) {
            $scope.showMessage = message;
            $scope.saveSuccess = true;
            $timeout(function () {
                $scope.saveSuccess = false;
            }, 5000);
        };

        $scope.showFailureNotification = function (message) {
            $scope.showMessage = message;
            $scope.saveFailure = true;
            $timeout(function () {
                $scope.saveFailure = false;
            }, 5000);
        };

        $scope.showMessage = function (message) {
            $scope.showMessageFlag = true;
            $scope.showMessage = message;
            $timeout(function () {
                $scope.showMessageFlag = false;
            }, 10000);
        };

    }
})();;
