        //push the list if student or due is isChecked
        function getSelectedFormatedDues() {
            var list = [];
            var show = false;
            $scope.noDueStudentsList.forEach(function (sectionObj) {
                if (sectionObj.isChecked) {
                    show = true;
                    var newSectionObj = {
                        bulkDueIsCheck: sectionObj.bulkDueIsCheck,
                        department: sectionObj.department,
                        isChecked: sectionObj.isChecked,
                        sectionWiseCount: sectionObj.sectionWiseCount,
                        sectionWiseStudents: [],
                        _id: sectionObj._id
                    };

                    sectionObj.sectionWiseStudents.forEach(function (student) {
                        if (student.isChecked) {
                            var dueItems = student.dueItems.filter(due => due.isDueCheck);
                            student.dueItems = dueItems;
                            newSectionObj.sectionWiseStudents.push(student);
                        }
                    });

                    list.push(newSectionObj);
                } else {
                    var isAdd = false;
                    var newSectionObj = {
                        bulkDueIsCheck: sectionObj.bulkDueIsCheck,
                        department: sectionObj.department,
                        isChecked: sectionObj.isChecked,
                        sectionWiseCount: sectionObj.sectionWiseCount,
                        sectionWiseStudents: [],
                        _id: sectionObj._id
                    };

                    sectionObj.sectionWiseStudents.forEach(function (student) {
                        if (student.isChecked) {
                            isAdd = true;
                            var dueItems = student.dueItems.filter(due => due.isDueCheck);
                            student.dueItems = dueItems;
                            newSectionObj.sectionWiseStudents.push(student);
                        }
                    });
                    if (isAdd) {
                        show = true;
                        list.push(newSectionObj);
                    }
                }
            });

            if (show) {
                $scope.isShowBulkButton = true;
            }

            $scope.noDueStudentsList = list;
            return $scope.noDueStudentsList;
        };

