        function getFiltersList(isTemplate, action) {
            var query = {};

            if ($scope.search.programType) {
                query.programType = $scope.search.programType;
            }

            if ($scope.search.programCategory) {
                query.programCategory = $scope.search.programCategory;
            }

            if ($scope.search.programmeName) {
                query.programmeName = $scope.search.programmeName;
            }

            if ($scope.search.batchYear) {
                query.batchYear = $scope.search.batchYear;
            }

            if ($scope.search.section) {
                query.section = $scope.search.section;
            }

            if ($scope.search.status) {
                query.status = $scope.search.status;
            }

            if ($scope.search.statusReason) {
                query.statusReason = $scope.search.statusReason;
            }

            if ($scope.search.rollNumber) {
                query.rollNumber = $scope.search.rollNumber;
            }

            if (isTemplate == true) {
                query.templateDetails = jobDetails
                query.jobDetails = jobDetails;
            };

            if (tempDetails) {
                query.jobDetails = tempDetails;
            }

            if (action == 'removeStudents') {
                query.action = action;
                query.filter = filter;
            } else if (action == 'addStudents') {
                query.action = action;
                query.filter = filter;
            } else if (action == 'getStudents') {
                query.action = action;
                query.filter = {};
            } else if (action == 'bulkUpdateDue') {
                query.action = action;
                query.filter = {};
            }

            query.jobDetails = jobDetails;

            return query;
        }

