        $scope.bulkSelection = function (departmentIndex) {
            var value = $scope.noDueStudentsList[departmentIndex].isChecked;
            $scope.noDueStudentsList[departmentIndex].sectionWiseStudents.forEach(function (student) {
                if (student) {
                    student.isChecked = value;
                }
            });
            return $scope.noDueStudentsList;
        };

        $scope.bulkDueSelection = function (departmentIndex) {
            var value = $scope.noDueStudentsList[departmentIndex].isChecked
            $scope.noDueStudentsList[departmentIndex].sectionWiseStudents.forEach(function (student) {
                student.dueItems.forEach(function (due, index) {
                    if (due) {
                        due.isDueCheck = value;
                    }
                });
            });
            return $scope.noDueStudentsList;
        };

        $scope.studenDueSelection = function (student) {
            var value = student.isChecked;
            student.dueItems.forEach(function (dues) {
                dues.isDueCheck = value;
            })
        };

        $scope.selectStudentDue = function (student, dues) {
            var value = "";
            value = student.dueItems.some(function (dues) {
                return dues.isDueCheck == true;
            });
            if (value == "") {
                value = false;
            }
            student.isChecked = value;
        };

