(function () {
    'use strict';
    var App = angular.module('app');

    App.controller('noDueStudentViewCtrl', noDueStudentViewCtrl);
    noDueStudentViewCtrl.$inject = ['$scope', '$rootScope', '$timeout', 'studentNoDueService', 'studentService', 'ValidationService'];

    function noDueStudentViewCtrl($scope, $rootScope, $timeout, studentNoDueService, studentService, ValidationService) {

        $scope.studentDueList = [];
        $scope.showLoader = false;
        $scope.downloadButtonShow = false;
        $scope.viewAndEditForm = false;
        $scope.isShowExitForm = "";
        $scope.photoUpload = false;
        $scope.isOneTimeMobileOtp = false;
        $scope.isOneTimeEmailOtp = false;
        $scope.isEmailVerifiCodeSent = false;
        $scope.isMobileVerifiCodeSent = false;
        $scope.isPhotoError = false;

        $scope.getStudentDueList = function () {
            studentNoDueService.getStudentDueList($rootScope.Auth.principal.preferred_username.toUpperCase(), function (err, res) {
                if (!err) {
                    $scope.isShowExitForm = res.isExitFormShow;
                    res.noDueList.forEach(function (data) {
                        formatDueList(data)
                    })
                    $scope.studentDueList = [];
                    res.noDueList.forEach(function (data) {
                        data.dueItems.forEach(function (value) {
                            $scope.studentDueList.push(value);
                        })
                    })
                }
            });
        };

        $scope.getDueOverAllStatus = function () {
            studentNoDueService.getOverAllStatus($rootScope.Auth.principal.preferred_username.toUpperCase(), function (err, res) {
                if (!err) {
                    $scope.overallStatus = res.overallStatus;
                } else {
                    $scope.showFailureNotification("Failed intimated Approver");
                }
            });
        }

        $scope.getExitFormData = function (action) {
            getExitForm(action);
        }

        $scope.getDueOverAllStatus();

        function getExitForm(action) {
            $scope.showLoader = true;
            studentService.getExitFormDetails($rootScope.Auth.principal.preferred_username.toUpperCase(), function (err, res) {
                if (!err) {
                    if (action == 'view') {
                        $('#exitFormDetails').modal('show');
                        $scope.viewAndEditForm = true;
                    }
                    $scope.showLoader = false;
                    var exitFormKeys = Object.keys(res);
                    if (exitFormKeys.length > 2) {
                        exitFormKeys.forEach(function (data) {
                            if (data === 'exitFormStatus') {
                                $scope.exitForm = res.exitFormDetails;
                                $scope.exitFormStatusDetails = res.exitFormStatus;
                                $scope.exitFormViewDetails = res.exitFormDetails;
                            }
                        });
                        if ($scope.exitForm && $scope.exitForm.photo) {
                            $scope.getPhotoUrl($scope.exitForm.photo, "exitFormStudent");
                            if ($scope.exitFormDetails && $scope.exitFormDetails.exitFormStatus === $scope.exitFormStatus["Not Fill"]) {
                                $scope.downloadButtonShow = true;
                            } else {
                                $scope.downloadButtonShow = false;
                            }
                        }
                    }
                } else {
                    $scope.showLoader = false;
                    $scope.showFailureNotification("Can't fetch exitForm Details.");
                }
            });
        };

        getExitForm();

        $scope.setExitForm = function () {
            $('#exitFormDetails').modal('show');
        };

        $scope.triggerDropzoneUpload = function (exitFormStudent) {
            var dropZone = $('.dropzone-click' + exitFormStudent).get(0).dropzone;
            dropZone.hiddenFileInput.click();
        };

        $scope.exitFormStudent = {
            dzOptions: {
                url: "#",
                method: "get",
                parallelUploads: 1,
                acceptedFiles: 'image/jpg,image/jpeg,image/png',
                autoProcessQueue: true,
                maxFilesize: 2,
                maxFiles: 2,
                uploadMultiple: false,
                paramName: function () {
                    return "studentPhoto";
                },
                maxfilesexceeded: function (file) {
                    this.removeAllFiles();
                    this.addFile(file);
                },
                init: function () {
                    $scope.myDropzone = this;
                    this.on("addedfile", function (file) {
                    });
                },
                params: $scope.studentRecord,
                renameFile: function (file) {
                    file.upload.filename = file.name;
                },
                headers: {
                    Authorization: "Bearer " + $rootScope.Auth.token
                },
                accept: function (file) {
                    $('.dropzone-clickexitFormStudent').parent().parent().parent().find('.upload-image-custom-error').hide();
                    $scope.exitFormPhotoUploadLoader = true;
                    $scope.uploadFileToS3(file, "exitFormStudent", function (uploadErr, uploadRes) {
                        $scope.exitFormPhotoUploadLoader = false;
                        if (!uploadErr) {
                            $scope.setDisplayUrl(uploadRes, "exitFormStudent");
                            $scope.getPhotoUrl($scope.uploadedDetails, "exitFormStudent");
                            $scope.exitForm.$dirty = true;
                        } else {
                            $('.dropzone-clickexitFormStudent').parent().parent().parent().find('.upload-image-custom-error').show();
                        }
                    });
                }
            },
            dzCallbacks: {
                init: function () {
                    this.on("addedfile", function (file) {
                    });
                },
                "error": function (file, response) {  // and then can you have your error callback
                    $('.dropzone-clickexitFormStudent').parent().parent().parent().find('.upload-image-custom-error').show();
                    $timeout(function () {
                        $('.dropzone-clickexitFormStudent').parent().parent().parent().find('.upload-image-custom-error').hide();
                    }, 5000);
                },
                "success": function (file, xhr) {
                    $('.dropzone-clickexitFormStudent').parent().parent().parent().find('.upload-image-custom-error').hide();
                },
                "removedfile": function (file) {
                }
            },
            dzMethods: {

            }
        };

        $scope.uploadFileToS3 = function (file, type, callback) {
            var query = {
                batchYear: $scope.studentRecord.batchYear,
                fileName: file.name,
                type: type
            }

            studentService.getUploadUrl(query, function (err, res) {
                if (res && res.signedUrl) {
                    studentService.uploadFilesToS3(res.signedUrl, file, function (error, result) {
                        $scope.exitFormPhotoUploadLoader = false;
                        if (!error) {
                            file.signedRequest = res;
                            callback(null, file);
                            return;
                        } else {
                            callback(error, null);
                            return;
                        }
                    });
                } else {
                    callback("Not able to upload", null);
                    return;
                }
            });
        };

        $scope.setDisplayUrl = function (uploadRes, section) {
            $scope.uploadedDetails = {
                id: uploadRes.signedRequest.filePath,
                contentType: uploadRes.type,
                filename: uploadRes.signedRequest.fileName,
                originalname: uploadRes.name,
                size: uploadRes.size
            };

            if (!$scope.exitForm) {
                $scope.exitForm = {}
            }

            if (!$scope.exitForm.studentPhoto) {
                $scope.exitForm.studentPhoto = {}
            }

            if (!$scope.exitForm.studentPhoto[section]) {
                $scope.exitForm.studentPhoto[section] = $scope.uploadedDetails;
            }
        };

        $scope.getPhotoUrl = function (StudentPhotoUrl, section) {
            studentService.getDownloadUrl(StudentPhotoUrl, function (err, res) {
                if (res && res.signedUrl) {
                    if (section == "exitFormStudent") {
                        $scope.exitFormStudentURL = new URL(res.signedUrl);
                    }
                }
            });
        };

        $scope.getFileFromS3 = function (file, type) {
            var query = file || {};
            studentService.getDownloadUrl(query, function (err, res) {
                if (res && res.signedUrl) {
                    studentService.getFileObjFromS3(res.signedUrl, function (err, res) {
                        if (res) {
                            const blob = new Blob([res], {
                                type: 'image/jpg'
                            });
                            var url = URL.createObjectURL(blob);
                            var newWindow = window.open(url, '_blank');
                            newWindow.document.title = file.originalname;
                        }
                    });
                } else {
                    return;
                }
            });
        };

        $scope.removeFile = function (section, isPhoto) {
            if (isPhoto) {
                delete $scope.exitForm.photo;
                $scope.photoUpload = true;
            } else if (!isPhoto) {
                $scope.exitForm.$dirty = true;
                delete $scope.exitForm.studentPhoto[section];
            }

        };

        $scope.submitExitFormDetails = function () {
            if (new ValidationService().checkFormValidity($scope.exitForms)) {
                if ($scope.exitForm && $scope.exitForm.studentPhoto != undefined) {
                    var exitFormDetails = formatExitFormDetails("create");
                    if ($scope.exitForm.emailVerification && $scope.exitForm.mobileVerification) {
                        $scope.isPhotoError = false;
                        $scope.showLoader = true;
                        studentService.submitExitForm(exitFormDetails, function (err, res) {
                            if (!err) {
                                $scope.exitForm = {};
                                $scope.getStudentDueList();
                                getExitForm();
                                $('#exitFormDetails').modal('hide');
                                $scope.showLoader = false;
                                $scope.showSuccessNotification("Exit form submitted successfully.");
                            } else {
                                $scope.showLoader = false;
                                $scope.showFailureNotification("Can't submit the exit form.");
                            }
                        });
                    } else {
                        $scope.showWarningNotification("Both email id and mobile no must be Verfied.");
                    }
                } else {
                    $scope.isPhotoError = true;
                    $scope.photoMsg = "Field is required"
                }
            }
        };

        $scope.updateMobileVerfication = function () {
            $scope.isOneTimeMobileOtp = true;
            if ($scope.exitForm.mobileVerification) {
                $scope.exitForm.mobileVerification = false;
            }
        }

        $scope.updateEmailVerfication = function () {
            $scope.isOneTimeEmailOtp = true;
            if ($scope.exitForm.emailVerification) {
                $scope.exitForm.emailVerification = false;
            }
        }

        function formatExitFormDetails(action) {

            if (action == "create") {
                if ($scope.exitForm.email && !$scope.exitForm.emailVerification) {
                    $scope.exitForm.emailVerification = false;
                }

                if ($scope.exitForm.mobile && !$scope.exitForm.mobileVerification) {
                    $scope.exitForm.mobileVerification = false;
                }
            }

            var exitFormDetails = {
                email: $scope.exitForm.email,
                emailVerification: $scope.exitForm.emailVerification,
                mobile: $scope.exitForm.mobile,
                mobileVerification: $scope.exitForm.mobileVerification,
                permanentAddress: $scope.exitForm.permanentAddress,
                commAddress: $scope.exitForm.commAddress,
                sameAddress: $scope.exitForm.sameAddress,
                rollNumber: $rootScope.Auth.principal.preferred_username.toUpperCase()
            }

            if ($scope.exitForm && $scope.exitForm.studentPhoto && $scope.exitForm.studentPhoto.exitFormStudent) {
                exitFormDetails['photo'] = $scope.exitForm.studentPhoto.exitFormStudent
            } else if ($scope.exitForm && $scope.exitForm.photo) {
                exitFormDetails['photo'] = $scope.exitForm.photo
            }

            return exitFormDetails;
        }

        $scope.sameAddress = function () {

            if (!$scope.exitForm) {
                $scope.exitForm = {};
            }
            if (!$scope.exitForm.contact) {
                $scope.exitForm.contact = {};
            }
            if (!$scope.exitForm.contact.sameAddress) {
                $scope.exitForm.contact.sameAddress = false;
            }
            if (!$scope.exitForm.contact.sameAddress) {
                $scope.exitForm.contact.sameAddress = true;
            } else if ($scope.exitForm.contact.sameAddress) {
                $scope.exitForm.contact.sameAddress = false;
            }

            if (!$scope.exitForm.commAddress) {
                $scope.exitForm.commAddress = {};
            }

            if ($('#sameAddress').prop('checked')) {
                $scope.exitForm.commAddress.addressLine1 = $scope.exitForm.permanentAddress.addressLine1;
                $scope.exitForm.commAddress.addressLine2 = $scope.exitForm.permanentAddress.addressLine2;
                $scope.exitForm.commAddress.addressLine3 = $scope.exitForm.permanentAddress.addressLine3;
                $scope.exitForm.commAddress.district = $scope.exitForm.permanentAddress.district;
                $scope.exitForm.commAddress.state = $scope.exitForm.permanentAddress.state;
                $scope.exitForm.commAddress.pincode = $scope.exitForm.permanentAddress.pincode;
                $scope.exitForm.commAddress.country = $scope.exitForm.permanentAddress.country;
                $scope.exitForm.commAddress.taluk = $scope.exitForm.permanentAddress.taluk;
                $scope.exitForm.commAddress.city = $scope.exitForm.permanentAddress.city;
                // $scope.clearPincode($scope.exitForm.contact.commAddress.country, 'commAddress', false)
            } else {
                $scope.exitForm.commAddress.addressLine1 = "";
                $scope.exitForm.commAddress.addressLine2 = "";
                $scope.exitForm.commAddress.addressLine3 = "";
                $scope.exitForm.commAddress.district = "";
                $scope.exitForm.commAddress.state = "";
                $scope.exitForm.commAddress.pincode = "";
                $scope.exitForm.commAddress.country = "";
                $scope.exitForm.commAddress.taluk = "";
                $scope.exitForm.commAddress.city = "";
            }
        };

        function getDisplayPicture(displayPicture) {
            var query = displayPicture;
            studentService.getDownloadUrl(query, function (err, res) {
                if (res && res.signedUrl) {
                    $scope.facultyDisplayPicture = new URL(res.signedUrl);
                } else {
                    $scope.facultyDisplayPicture = "img/avatars/noimage-later.png";
                }
            });
        };

        $scope.getApproverDetails = function (facultyId) {
            studentNoDueService.getApproverDetails(facultyId.toUpperCase(), function (err, res) {
                if (!err && res) {
                    $scope.facultyDetails = res;
                    if ($scope.facultyDetails.displayPicture && $scope.facultyDetails.displayPicture.id) {
                        getDisplayPicture($scope.facultyDetails.displayPicture);
                    } else {
                        $scope.facultyDisplayPicture = "img/avatars/noimage-later.png";
                    }
                    $('#viewApproverInfo').modal('show');
                    return;
                } else if (res == "") {
                    $scope.showFailureNotification("No Approver record found.");
                } else if (err && err.data) {
                    $scope.showFailureNotification(err.data);
                } else {
                    $scope.showFailureNotification("Can't fetch Approver record.");
                }
                document.body.scrollTop = document.documentElement.scrollTop = 0;
            });
        };

        function formatDueList(list) {
            var jobId = list.noDuesJobId;
            list.dueItems.forEach(function (item, index) {
                item["noDueJobId"] = jobId;
                if (Array.isArray(item.remark) && item.remark.length > 0) {
                    var remark = item.remark.pop();
                    let result = remark.replace(/[<p></p>]/g, "");
                    item.remark = result
                } else {
                    item.remark = '';
                }
            });
        };

        $scope.getStudentDueList();

        $scope.intimateModel = function (dueItem) {
            $scope.dueToSendApproveRequest = dueItem
            $scope.emailApprover = dueItem.approver;
            $('#confirmIntimateMail').modal('show');
        };

        $scope.intimate = function () {
            let query = {
                facultyId: $scope.dueToSendApproveRequest.approver,
                studentId: $rootScope.Auth.principal.preferred_username,
                dueName: $scope.dueToSendApproveRequest.section,
                studentName: $rootScope.studentRecord.name,
                programName: $rootScope.studentRecord.programmeName,
                batchYear: $rootScope.studentRecord.batchYear,
                noDueJobId: $scope.dueToSendApproveRequest.noDueJobId
            };
            studentNoDueService.intimateFaculty(query, function (err, res) {
                if (!err) {
                    $scope.getStudentDueList();
                    $scope.showSuccessNotification("Successfully intimated the approver.");
                } else {
                    $scope.getStudentDueList();
                    $scope.showFailureNotification("Can't intimate the approver,Try Again.");
                }
            })
        };

        function getEnums() {
            studentNoDueService.getDueEnums(function (err, res) {
                if (!err) {
                    $scope.noDueStatus = res.noDueStatus;
                    $scope.overAllStatus = res.overallStatus;
                    $scope.exitFormStatus = res.exitFormStatus;
                } else {
                    $scope.showFailureNotification("Failed intimated Approver");
                }
            });
        };

        getEnums();

        $scope.printDueList = function () {
            $scope.showLoader = true;
            studentNoDueService.printDueList($rootScope.Auth.principal.preferred_username.toUpperCase(), function (err, response) {
                $scope.showLoader = false;
                if (!err && response) {
                    var fileName = "Student DueList of : " + $rootScope.Auth.principal.preferred_username;
                    var blob = new Blob([response], {
                        type: 'application/pdf'
                    });
                    const pdfUrl = URL.createObjectURL(blob, fileName);
                    window.open(pdfUrl, "_blank");
                }
            });
        };

        $scope.clearPincode = function (val, isClearLocation) {
            if (isClearLocation) {
                clearLocation(isClearLocation);
            }

            if (isClearLocation == 'permanent') {
                if (!$scope.exitForm) {
                    $scope.exitForm = {};
                }

                if ($scope.exitForm && !$scope.exitForm.permanentAddress) {
                    $scope.exitForm["permanentAddress"] = {};
                }

                if ($scope.exitForm && $scope.exitForm.permanentAddress) {
                    $scope.exitForm['permanentAddress']['country'] = val
                }

            } else if (isClearLocation == 'commAddress') {
                if (!$scope.exitForm) {
                    $scope.exitForm = {};
                }

                if ($scope.exitForm && !$scope.exitForm.commAddress) {
                    $scope.exitForm["commAddress"] = {};
                }

                if ($scope.exitForm && $scope.exitForm.commAddress) {
                    $scope.exitForm['commAddress']['country'] = val
                }
            }

            if (!['INDIA', 'India'].includes(val)) {
                $scope.foreigner = true;
            }
            if (['INDIA', 'India'].includes(val)) {
                $scope.foreigner = false;
            }
        };

        $scope.lookUpPincode = function () {
            if ($scope.exitForm.permanentAddress.pincode.length == 6 && ['INDIA', 'India'].includes($scope.exitForm.permanentAddress.country)) {
                studentService.lookUpPincode($scope.exitForm.permanentAddress.pincode, function (err, location) {
                    $scope.exitForm.permanentAddress.district = location.district;
                    $scope.exitForm.permanentAddress.state = location.state;
                    $scope.exitForm.permanentAddress.taluk = location.taluk;
                });
            } else {
                $scope.exitForm.permanentAddress.district = null;
                $scope.exitForm.permanentAddress.state = null;
                $scope.exitForm.permanentAddress.taluk = null;
            }
        };

        $scope.lookUpCommPincode = function () {
            if ($scope.exitForm.commAddress.pincode.length == 6 && ['INDIA', 'India'].includes($scope.exitForm.commAddress.country)) {
                studentService.lookUpPincode($scope.exitForm.commAddress.pincode, function (err, location) {
                    $scope.exitForm.commAddress.district = location.district;
                    $scope.exitForm.commAddress.state = location.state;
                    $scope.exitForm.commAddress.taluk = location.taluk;
                });
            } else {
                $scope.exitForm.commAddress.district = "";
                $scope.exitForm.commAddress.state = "";
                $scope.exitForm.commAddress.taluk = "";
            }
        };

        function clearLocation(addressType) {

            if ($scope.exitForm && $scope.exitForm.sameAddress) {
                var addressTypeList = ['commAddress', 'permanent'];
            } else {
                var addressTypeList = [addressType];
            }

            for (var i = 0; i < addressTypeList.length; i++) {
                var type = addressTypeList[i];
                if ($scope.exitForm && $scope.exitForm[type] && $scope.exitForm[type].pincode) {
                    $scope.exitForm[type].pincode = "";
                }

                if ($scope.exitForm && $scope.exitForm[type] && $scope.exitForm[type].district) {
                    $scope.exitForm[type].district = "";
                }

                if ($scope.exitForm && $scope.exitForm[type] && $scope.exitForm[type].state) {
                    $scope.exitForm[type].state = "";
                }
                if ($scope.exitForm && $scope.exitForm[type] && $scope.exitForm[type].taluk) {
                    $scope.exitForm[type].taluk = "";
                }
            }

        };

        $scope.clearFields = function () {
            $scope.exitFormUserConfCode = {};
            $scope.isEmailVerifiCodeSent = false;
            $scope.isMobileVerifiCodeSent = false;
            $('#exitFormDetails').modal('hide');
            $scope.exitForm = {};
        };

        $scope.openVerifyEmail = function () {
            $scope.exitFormEmailConfCode = generateConfCode();
            studentService.sendConfCodeToEmail($scope.exitForm.email, $scope.exitFormEmailConfCode, "exit form", function (err, res) {
                if (!err) {
                    $scope.isOneTimeEmailOtp = false;
                    $scope.isEmailVerifiCodeSent = true;
                } else {
                    $scope.showFailureNotificationModel("Can't send Verification Code,Try again.");
                }
            });
        };

        $scope.openVerifyMobile = function () {
            $scope.exitFormMobileConfCode = generateConfCode();
            studentService.sendOTPtoMobile($scope.exitForm.mobile.toString(), $scope.exitFormMobileConfCode, function (err, res) {
                if (!err) {
                    $scope.isOneTimeMobileOtp = false;
                    $scope.isMobileVerifiCodeSent = true;
                } else {
                    $scope.showFailureNotificationModel("Can't send Verification Code,Try again.");
                }
            });
        };

        function generateConfCode() {
            var code = Math.floor(1000 + Math.random() * 9000);
            return code;
        }

        $scope.checkMobileOTP = function () {
            if ($scope.exitFormUserConfCode && $scope.exitFormUserConfCode.mobile) {
                if (parseInt($scope.exitFormUserConfCode.mobile) == $scope.exitFormMobileConfCode) {
                    $scope.exitForm.mobileVerification = true;
                    $scope.isMobileVerifiCodeSent = false;
                    $scope.isMobilEntered = false;
                    $scope.showSuccessNotificationModel("Successfully verified mobile number");
                }
                else {
                    $scope.showFailureNotificationModel("Code Doesn't Match.");
                }
            } else {
                $scope.isMobilEntered = true;
            }
        }

        $scope.checkEmailConfCode = function () {
            if ($scope.exitFormUserConfCode && $scope.exitFormUserConfCode.email) {
                if (parseInt($scope.exitFormUserConfCode.email) == $scope.exitFormEmailConfCode) {
                    $scope.exitForm.emailVerification = true;
                    $scope.isEmailVerifiCodeSent = false;
                    $scope.isEmailEntered = false;
                    $scope.showSuccessNotificationModel("Successfully verified email Id");
                }
                else {
                    $scope.showFailureNotificationModel("Code Doesn't Match");
                }
            } else {
                $scope.isEmailEntered = true;
            }

        };

        $scope.showFailureNotification = function (message) {
            $scope.showMessage = message;
            $scope.saveFailure = true;
            $timeout(function () {
                $scope.saveFailure = false;
            }, 10000);
        };

        $scope.showSuccessNotification = function (message) {
            $scope.showMessage = message;
            $scope.saveSuccess = true;
            $timeout(function () {
                $scope.saveSuccess = false;
            }, 10000);
        };

        $scope.showWarningNotification = function (message) {
            $scope.showWarningMessage = message;
            $scope.showWarning = true;
            $timeout(function () {
                $scope.showWarning = false;
            }, 10000);
        };

        $scope.showFailureNotificationModel = function (message) {
            $scope.showMessageModel = message;
            $scope.saveFailureModel = true;
            $timeout(function () {
                $scope.saveFailureModel = false;
            }, 10000);
        };

        $scope.showSuccessNotificationModel = function (message) {
            $scope.showMessageModel = message;
            $scope.saveSuccessModel = true;
            $timeout(function () {
                $scope.saveSuccessModel = false;
            }, 10000);
        };
    }

})();
