    function careerGoalReportService($http) {
        this.getExcelReport = function (filter, callback) {
            var requestPromise = $http({
                method: "post",
                data: { filter: filter },
                headers: { "Content-Type": "application/json" },
                url: "career/report/excel",
                responseType: "arraybuffer",
            });
            requestPromise.then(
                function (response) {
                    callback(null, response.data);
                },
                function (error) {
                    const text = String.fromCharCode.apply(null, Array.from(new Uint8Array(error.data)));
                    error.data = JSON.parse(text);
                    callback(error.data, null);
                }
            );
        };
    }


