    function reportBuilderServices($http) {

        this.queryReports = function (filterQuery, projection, callback) {
            var responsePromise = $http({
                method: 'POST',
                data: JSON.stringify({ filter: filterQuery, projection: projection }),
                headers: { 'Content-Type': 'application/json' },
                url: 'report/builder/fetch',
                timeout: 2 * 60 * 1000,
            });

            responsePromise.then(function (responseData) {
                callback(null, responseData.data);
            }, function (error) {
                callback(error, null);
            });
        };

        this.getFavouriteViewList = function (userId, callback) {
            var responsePromise = $http({
                method: 'post',
                data: JSON.stringify({ userId: userId }),
                headers: { 'Content-Type': 'application/json' },
                url: 'report/builder/fetch/favourite/view/list'
            });

            responsePromise.then(function (responseData) {
                callback(null, responseData.data);
            }, function (error) {
                callback(error, null);
            });
        }

        this.saveFavouriteView = function (filterQuery, projection, userId, favouriteViewName, callback) {
            var responsePromise = $http({
                method: 'post',
                data: JSON.stringify({ query: filterQuery, projection: projection, userId: userId, favouriteViewName: favouriteViewName }),
                headers: { 'Content-Type': 'application/json' },
                url: 'report/builder/save/favourite/view'
            });
            responsePromise.then(function (responseData) {
                callback(null, responseData.data);
            }, function (error) {
                callback(error, null);
            });
        }

        this.updateFavouriteView = function (filterQuery, projection, userId, favouriteViewName, callback) {
            var responsePromise = $http({
                method: 'put',
                data: JSON.stringify({ query: filterQuery, projection: projection, userId: userId, favouriteViewName: favouriteViewName }),
                headers: { 'Content-Type': 'application/json' },
                url: 'report/builder/update/favourite/view'
            });
            responsePromise.then(function (responseData) {
                callback(null, responseData.data);
            }, function (error) {
                callback(error, null);
            });
        }

        this.deleteFavouriteView = function (filter, callback) {
            var responsePromise = $http({
                method: 'delete',
                data: JSON.stringify({ filter: filter }),
                headers: { 'Content-Type': 'application/json' },
                url: 'report/builder/delete/favourite/view'
            });
            responsePromise.then(function (responseData) {
                callback(null, responseData.data);
            }, function (error) {
                callback(error, null);
            });
        }
    }

