        $scope.deleteProcess = function (index) {
            var processBy = $rootScope.Auth.principal.preferred_username;
            var detailsToUpdate = {
                status: "Delete In progress"
            }
            $('#deleteModel').modal('hide');
            importJobService.updateJobDetails($scope.importJobList[index]._id, detailsToUpdate, function (err, resp) {
                if (!err) {
                    $rootScope.searchParams.searchField = "";
                    $scope.getStudentUploads();
                    importJobService.deleteImport($scope.importJobList[index]._id, processBy, function (error, response) {
                        $scope.getStudentUploads();
                        if (error) {
                            $scope.failureNotification("Deleting a bulk upload instance was failed as there is a server issue");
                        } else {
                            $scope.successNotification(response.processName + " bulk import student has been deleted successfully");
                        }
                    })
                }
            });
        }

