(function () {
    'use strict';
    var App = angular.module('app');
    App.directive('basicDir', basicDir);
    basicDir.$inject = ['$rootScope', '$compile'];
    function basicDir($rootScope, $compile) {
        return {
            restrict: 'EA',
            templateUrl: 'app/modules/student-profile/basic.html',
            controller: 'basicCtrl',
            replace: true,
            scope: true,
            link: function (scope, element) {
            }

        };
    }

    App.controller('basicCtrl', basicCtrl);
    basicCtrl.$inject = ['$scope'];
    function basicCtrl($scope) {
        $scope.dateLimit = {
            dateFormat: 'd-m-Y',
            maxDate: 'today'
        };

        $scope.holdersForNewSelectItem = ["motherTongues"];
        if (!$scope.studentRecord.basic) {
            $scope.studentRecord.basic = {};
        }

        $scope.update = function (sectionName, editable, index, formId) {
            $scope.edit.call($scope, sectionName, editable, index, formId);
            if ($scope.recordToUpdate.basic.dob) {
                $scope.recordToUpdate.basic.dob = moment($scope.recordToUpdate.basic.dob, "YYYY-MM-DD").format("DD-MM-YYYY");
            }
        };

        $scope.saveSection = function (sectionName, formId) {
            $scope.saveSectionItem.call($scope, sectionName, formId);
        }

        $scope.preSave = function () {
            if ($scope.recordToUpdate.basic.firstName) {
                $scope.recordToUpdate.basic.firstName = $scope.recordToUpdate.basic.firstName.toUpperCase();
            }
            if ($scope.recordToUpdate.basic.lastName) {
                $scope.recordToUpdate.basic.lastName = $scope.recordToUpdate.basic.lastName.toUpperCase();
            }
            if ($scope.recordToUpdate.basic.firstName && $scope.recordToUpdate.basic.lastName) {
                $scope.recordToUpdate.name = $scope.recordToUpdate.basic.firstName.toUpperCase() + $scope.recordToUpdate.basic.lastName.toUpperCase();
            }
            if ($scope.recordToUpdate.basic.hostelBlockName) {
                $scope.recordToUpdate.basic.hostelBlockName = $scope.recordToUpdate.basic.hostelBlockName.toUpperCase();
            }

            if ($scope.recordToUpdate.basic.dob) {
                $scope.recordToUpdate.basic.dob = moment($scope.recordToUpdate.basic.dob, "DD-MM-YYYY").format("YYYY-MM-DD");
            }
        };

        $scope.$watch("recordToUpdate.basic.dob", function () {
            if ($scope.recordToUpdate.basic) {
                $scope.ageCalculation($scope.recordToUpdate.basic);
            }
        });

        $scope.ageCalculation = function (studentRecord) {
            if ($scope.recordToUpdate.basic.dob) {
                var dob = $scope.recordToUpdate.basic.dob;
                var dobMoment = moment(dob, "DD-MM-YYYY");
                $scope.recordToUpdate.basic.age = moment().diff(dobMoment, "years");
            } else {
                $scope.recordToUpdate.basic.age = undefined;
            }
        };

    }

})();;

