(function () {
    'use strict';
    var App = angular.module('app');
    App.directive('familyDir', familyDir);
    familyDir.$inject = ['$rootScope', '$compile'];
    function familyDir($rootScope, $compile) {
        return {
            restrict: 'EA',
            templateUrl: 'app/modules/student-profile/family.html',
            controller: 'familyCtrl',
            replace: true,
            scope: true
        };
    }

    App.controller('familyCtrl', familyCtrl);
    familyCtrl.$inject = ['$scope', '$rootScope', 'studentService', 'ValidationService', '$timeout'];
    function familyCtrl($scope, $rootScope, studentService, ValidationService, $timeout) {

        $scope.$validationOptions = { debounce: 1500, preValidateFormElements: false, isolatedScope: $scope };
        $scope.item;
        $rootScope.familyMember = [];
        $scope.member = {};
        var beforeUpdateEmail = "";

        $scope.setEnvToUpdate = function (sectionName, editable, familyDetail, formId, objectName) {
            $scope.recordToUpdate.family = {};
            $scope.member = JSON.parse(JSON.stringify(familyDetail));
            beforeUpdateEmail = familyDetail.email;
            $scope.edit.call($scope, sectionName, editable, familyDetail.itemIndex, formId, objectName);
            $scope.editMode = true;
        };

        $scope.saveAnnualIncome = function (formId) {
            if (new ValidationService().checkFormValidity($scope[formId])) {
                var annualIncome = $scope.recordToUpdate.family.annualIncome;
                editFamilyDetails(-1, null, annualIncome);
            }
        };

        // $scope.saveSection = function (sectionName, formId) {
        //     if (new ValidationService().checkFormValidity($scope[formId])) {
        //         if ($scope.item >= 0) {
        //             editFamilyDetails($scope.item, $scope.recordToUpdate.family.members[0], null);
        //         } else {
        //             addFamilyDetails();
        //         }
        //     }
        // };

        $scope.addFamilyDetails = function () {
            if (new ValidationService().checkFormValidity($scope.editFamily)) {
                studentService.addFamilyDetails($scope.studentRecord.rollNumber, $scope.member, function (err, response) {
                    $('.modal').modal('hide');
                    document.body.scrollTop = document.documentElement.scrollTop = 0;
                    if (!err && response) {
                        $rootScope.getStudentRecord();
                        $rootScope.showSuccessNotification();
                    } else {
                        $rootScope.showFailureNotification();
                    }
                });
            }
        };

        $scope.addFamilyMembers = function () {
            $scope.member = {};
            $scope.recordToUpdate.family = {};
            $scope.recordToUpdate.family.members = [];
            $scope.recordToUpdate.family.members.push({ type: "", name: "", contactNo: "", email: "", isAlumni: false, occupation: "", qualification: "" });
        }

        $scope.editFamilyDetails = function () {
            if (!new ValidationService().checkFormValidity($scope.editFamily)) {
                return;
            }

            if (beforeUpdateEmail != $scope.member.email) {
                $scope.member.emailVerification = false
            }

            studentService.updateFamilyDetails($scope.studentRecord.rollNumber, $scope.member, function (err, response) {
                $('.modal').modal('hide');
                document.body.scrollTop = document.documentElement.scrollTop = 0;
                if (!err && response) {
                    $rootScope.getStudentRecord();
                    $rootScope.showSuccessNotification();
                } else {
                    $rootScope.showFailureNotification();
                }
            });
        };
    }

})();;
