(function () {
    'use strict';
    var App = angular.module('app');
    App.directive('languageDir', languageDir);
    languageDir.$inject = ['$rootScope', '$compile'];
    function languageDir($rootScope, $compile) {
        return {
            restrict: 'EA',
            scope: true,
            templateUrl: 'app/modules/student-profile/language.html',
            controller: 'languageCtrl',
            replace: true
        };
    }

    App.controller('languageCtrl', languageCtrl);
    languageCtrl.$inject = ['$scope', '$rootScope', '$timeout'];
    function languageCtrl($scope, $rootScope, $timeout) {

        $scope.isSaveFailure = false;
        $scope.saveSection = function (sectionName, formId) {
            $scope.isEmptyLangError = false;
            checkEmptyLang();

            if ($scope.isEmptyLangError) {
                $scope.isSaveFailure = true;
                $scope.showMessage = "Kindly select language!!"
                $timeout(function () {
                    $scope.isSaveFailure = false;
                }, 8000);
                return;
            }

            if (!$scope.isEmptyLangError) {
                if (checkForSelection()) {
                    $scope.recordToUpdate.languagesKnown.forEach(function (language) {
                        if (language.$$hashKey) {
                            delete language["$$hashKey"];
                        }
                    })
                    $scope.isSaveFailure = false;
                    $rootScope.showLoader = true;
                    $scope.saveSectionItem.call($scope, sectionName, formId);
                    $rootScope.showLoader = false;
                    return;
                }
            }

        };
        $scope.getLangauges = function () {
            if ($scope.recordToUpdate && $scope.recordToUpdate.languagesKnown && $scope.recordToUpdate.languagesKnown.length) {
                var languagesExisted = [];
                $scope.langToPush = [];
                $scope.recordToUpdate.languagesKnown.forEach(function (language) {
                    languagesExisted.push(language.name)
                })
                $rootScope.motherTongues.forEach(function (language) {
                    if (!languagesExisted.includes(language)) {
                        $scope.langToPush.push(language)
                    }
                })
            }
        };

        function checkEmptyLang() {
            if ($scope.recordToUpdate.languagesKnown) {
                return $scope.recordToUpdate.languagesKnown.forEach(function (lang) {
                    if (!lang.name) {
                        $scope.isEmptyLangError = true
                    }
                })
            }
        };

        function checkForSelection() {
            for (var i = 0; i < $scope.recordToUpdate.languagesKnown.length; i++) {
                var language = $scope.recordToUpdate.languagesKnown[i];
                if (!Object.values(language).includes(true)) {
                    $scope.isSaveFailure = true;
                    $scope.showMessage = "Atleast one proficiency must be chosen for the selected language!!!";
                    $timeout(function () {
                        $scope.isSaveFailure = false;
                    }, 5000);
                    return false;
                }
            }
            return true;
        };

        $scope.removeLanguage = function (index) {
            $scope.getLangauges();
            $scope.recordToUpdate.languagesKnown.splice(index, 1);
            if ($scope.recordToUpdate.languagesKnown.length) {
                $scope.languagesInfo.$dirty = true;
            }
        };

        $scope.addLanguage = function () {
            $scope.getLangauges();
            $scope.recordToUpdate.languagesKnown.push({ name: "", read: false, write: false, speak: false});
        }
    }

})();   ;
