(function () {
    'use strict';
    var App = angular.module('app');
    App.directive('scholarshipDir', scholarshipDir);
    scholarshipDir.$inject = ['$rootScope', '$compile'];
    function scholarshipDir($rootScope, $compile) {
        return {
            restrict: 'EA',
            templateUrl: 'app/modules/student-profile/scholarship.html',
            controller: 'scholarshipCtrl',
            replace: true,
            scope: true
        };
    }

    App.controller('scholarshipCtrl', scholarshipCtrl);
    scholarshipCtrl.$inject = ['$stateParams', '$scope', '$rootScope', 'studentService', 'scholarshipServices', 'ValidationService'];
    function scholarshipCtrl($stateParams, $scope, $rootScope, studentService, scholarshipServices, ValidationService) {
        $scope.isArray = true;
        var rollNumber = $stateParams.rollNumber.toUpperCase();
        fetchScholarships();

        $scope.$validationOptions = {
            debounce: 500,
            preValidateFormElements: false,
            isolatedScope: $scope
        };

        function fetchScholarships() {
            scholarshipServices.view(rollNumber, function (err, data) {
                if (err) {
                    // showFailureNotificationCustom("failed To fetch education details");
                    return;
                }
                $scope.studentRecord.scholarship = data;
            })
        }

        $scope.delete = function (details) {
            $scope.title = details.name;
            $scope.detailId = details["_id"];
            $('#confirmDeleteScholarship').modal('show');
        };

        $scope.confirmDelete = function () {
            scholarshipServices.remove($scope.detailId, function (err, res) {
                if (err) {
                    reject("Failed to Remove");
                    return;
                }
                // showSuccessNotificationCustom("Successfully Deleted education");
                fetchScholarships();
            });
        }

        $scope.dateOpts = {
            dateFormat: "d-m-Y",
            allowInput: false,
            maxDate: moment().format("DD-MM-YYYY"),
        };

        $scope.add = function () {
            if (new ValidationService().checkFormValidity($scope.editScholarshipInfo)) {
                $scope.recordToUpdate.scholarship.rollNumber = rollNumber
                scholarshipServices.add($scope.recordToUpdate.scholarship, function (err, data) {
                    if (err) {
                        // showFailureNotificationCustom("failed To Add education details");
                        return;
                    }
                    $scope.errMsg = null;
                    // $rootScope.showSuccessNotification("Successfully Added Competition details");
                    fetchScholarships();
                    $("#scholarshipSectionItemModal").modal('hide');
                })
            }
        }

        $scope.edit = function () {
            if (new ValidationService().checkFormValidity($scope.editScholarshipInfo)) {
                scholarshipServices.edit($scope.recordToUpdate.scholarship._id, $scope.recordToUpdate.scholarship, function (err, data) {
                    if (err) {
                        // showFailureNotificationCustom("failed To Edit education details");
                        return;
                    }
                    $scope.errMsg = null;
                    $rootScope.showSuccessNotification("Successfully Edited Competition details");
                    fetchScholarships();
                    $("#scholarshipSectionItemModal").modal('hide');
                })
            }
        }

        $scope.setEnvironmentAddSectionItem = function () {
            $scope.mode = "ADD";
            $scope.editScholarshipInfo.$setPristine();
            $scope.clearValidation('editScholarshipInfo');
            $scope.recordToUpdate.scholarship = {};
        }

        $scope.setEnvironmentForEditItem = function (data) {
            $scope.mode = "EDIT";
            $scope.editScholarshipInfo.$setPristine();
            $scope.clearValidation('editScholarshipInfo');
            $scope.recordToUpdate.scholarship = JSON.parse(JSON.stringify(data));
            $scope.recordToUpdate.scholarship.receivedDate = $scope.recordToUpdate.scholarship.receivedDate ? moment(data.receivedDate, 'YYYY-MM-DD').format('DD-MM-YYYY') : null;
        };

        $scope.triggerDropzoneUpload = function (certificate) {
            var dropZone = $('.dropzone-click' + certificate).get(0).dropzone;
            dropZone.hiddenFileInput.click();
        };

        $scope.scholarshipCert = {
            dzOptions: {
                url: "#",
                method: "get",
                parallelUploads: 1,
                acceptedFiles: 'image/jpg,image/jpeg,image/png',
                autoProcessQueue: true,
                maxFilesize: 0.5,
                maxFiles: 1,
                uploadMultiple: false,
                paramName: function () {
                    return "scholarshipCert";
                },
                maxfilesexceeded: function (file) {
                    this.removeAllFiles();
                    this.addFile(file);
                },
                init: function () {
                    $scope.myDropzone = this;
                    this.on("addedfile", function (file) {
                    });
                },
                params: $scope.studentRecord,
                renameFile: function (file) {
                    file.upload.filename = file.name;
                },
                headers: {
                    Authorization: "Bearer " + $rootScope.Auth.token
                },
                accept: function (file) {
                    $('.dropzone-clickscholarshipCert').parent().parent().parent().find('.upload-image-custom-error').hide();
                    $scope.scholarshipCertUploadLoader = true;
                    $scope.uploadFileToS3(file, "scholarshipCert", function (uploadErr, uploadRes) {
                        $scope.scholarshipCertUploadLoader = false;
                        if (!uploadErr) {
                            $scope.setCertificateQuery(uploadRes, "scholarshipCert");
                            $scope.getCertUrl($scope.uploadedDetails, "scholarshipCert");
                            $scope.editScholarshipInfo.$dirty = true;
                        } else {
                            $('.dropzone-clickscholarshipCert').parent().parent().parent().find('.upload-image-custom-error').show();
                        }
                    });
                }
            },
            dzCallbacks: {
                init: function () {
                    this.on("addedfile", function (file) {
                    });
                },
                "error": function (file, response) {  // and then can you have your error callback
                    $('.dropzone-clickscholarshipCert').parent().parent().parent().find('.upload-image-custom-error').show();
                    $timeout(function () {
                        $('.dropzone-clickscholarshipCert').parent().parent().parent().find('.upload-image-custom-error').hide();
                    }, 5000);
                },
                "success": function (file, xhr) {
                    $('.dropzone-clickscholarshipCert').parent().parent().parent().find('.upload-image-custom-error').hide();
                },
            },
            dzMethods: {}
        };

        $scope.uploadFileToS3 = function (file, type, callback) {
            var query = {
                batchYear: $scope.studentRecord.batchYear,
                fileName: file.name,
                type: type
            }

            studentService.getUploadUrl(query, function (err, res) {
                if (res && res.signedUrl) {
                    studentService.uploadFilesToS3(res.signedUrl, file, function (error, result) {
                        $scope.offerLetterUploadLoader = false;
                        if (!error) {
                            file.signedRequest = res;
                            callback(null, file);
                            return;
                        } else {
                            callback(error, null);
                            return;
                        }
                    });
                } else {
                    callback("Not able to upload", null);
                    return;
                }
            });
        };

        $scope.setCertificateQuery = function (uploadRes, section) {
            $scope.uploadedDetails = {
                id: uploadRes.signedRequest.filePath,
                contentType: uploadRes.type,
                filename: uploadRes.signedRequest.fileName,
                originalname: uploadRes.name,
                size: uploadRes.size
            };

            if (!$scope.recordToUpdate) {
                $scope.recordToUpdate = {}
            }

            if (!$scope.recordToUpdate.scholarship) {
                $scope.recordToUpdate.scholarship = {}
            }

            if (!$scope.recordToUpdate.scholarship[section]) {
                $scope.recordToUpdate.scholarship[section] = $scope.uploadedDetails;
            }
        };

        $scope.getCertUrl = function (certificate, section) {
            var query = certificate;
            studentService.getDownloadUrl(query, function (err, res) {
                if (res && res.signedUrl) {
                    if (section == "scholarshipCert") {
                        $scope.scholarshipCertURL = new URL(res.signedUrl);
                    }
                }
            });
        };

        $scope.getFileFromS3 = function (file) {
            var query = file || {};

            studentService.getDownloadUrl(query, function (err, res) {
                if (res && res.signedUrl) {
                    studentService.getFileObjFromS3(res.signedUrl, function (err, res) {
                        if (res) {
                            const blob = new Blob([res], {
                                type: 'image/jpg'
                            });
                            var url = URL.createObjectURL(blob);
                            var newWindow = window.open(url, '_blank');
                            newWindow.document.title = file.originalname;
                        }
                    });
                } else {
                    return;
                }
            });
        }

        $scope.removeFile = function (section) {
            $scope.editScholarshipInfo.$dirty = true;
            delete $scope.recordToUpdate.scholarship[section];
        }
    }

})();;
