(function () {
    'use strict';
    var App = angular.module('app');

    App.controller('studentAttendanceCtrl', studentAttendanceCtrl);
    studentAttendanceCtrl.$inject = ['$scope', '$rootScope', '$timeout', 'attendanceServices'];
    function studentAttendanceCtrl($scope, $rootScope, $timeout, attendanceServices) {

        var rollNumber = ($rootScope.Auth.principal.preferred_username).toUpperCase();
        $scope.showLoader = true;

        $scope.currentTime = new Date().toISOString();

        function getStudentAttendanceSummary() {
            attendanceServices.getStudentAttendance(rollNumber, function (err, res) {
                if (!err) {
                    $scope.attendanceSummary = res;
                    $scope.presentPercentage = (res.presentCount / res.earned) * 100;
                    setUpPieChart();
                    // $scope.headers = {};
                    // $scope.isDatesAvailabe = Object.keys($scope.attendanceSummary.attendancesWithDateAndSession).length;
                    // for (var i = 1; i <= res.numOfSessions; i++) {
                    //     $scope.headers['session' + i] = "Session " + i;
                    // }
                    $scope.showLoader = false;
                } else {
                    $scope.showLoader = false;
                    $scope.showFailureNotification(err.data.message || "Can't fetch attendance details");
                }
            })
        }

        getStudentAttendanceSummary();

        $scope.openAbsentDates = function () {
            $scope.showLoader = true;
            attendanceServices.getStudentAbsentDates(rollNumber, function (err, res) {
                if (!err) {
                    $scope.showLoader = false;
                    $('#transactionModal').modal('show');
                    $scope.name = "Absent";
                    $scope.attendanceDetails = res;
                }
            })
        }

        $scope.openPresentDates = function () {
            $scope.showLoader = true;
            attendanceServices.getStudentPresentDates(rollNumber, function (err, res) {
                if (!err) {
                    $scope.showLoader = false;
                    $('#transactionModal').modal('show');
                    $scope.name = "Present";
                    $scope.attendanceDetails = res;
                }
            })
        }

        $scope.convertDate = function (date) {
            return moment(date).format("dddd, MMMM Do YYYY")
        }

        function setUpPieChart() {
            $timeout(function () {
                $('[data-toggle="popover"]').popover();
            }, 500)

            $scope.attendanceSummaryJson = {
                "type": "pie3d",
                "scale": {
                    "size-factor": 0.72
                },
                legend: {
                    layout: "1x2",
                    borderColor: '#f1f1f1',
                    borderWidth: '1px',
                    item: {
                        fontColor: '#000'
                    },
                    margin: 0,
                    shadow: false,
                    "highlight-plot": true,
                    toggleAction: 'remove',
                    x: '50%',
                    y: '5%'
                },
                "plot": {
                    "value-box": {
                        "font-size": 11,
                        "font-weight": "normal",
                        "offset-r": "25%"
                    },
                    valueBox: {
                        placement: 'in',
                        text: '%v'
                    },
                    tooltip: {
                        fontSize: '18',
                        fontFamily: "Open Sans",
                    }
                },

                "series": [{
                    "values": [$scope.attendanceSummary.presentCountTillDate],
                    "text": "Present",
                    'background-color': "#68c9bb",
                }, {
                    "values": [$scope.attendanceSummary.absentCountTillDate],
                    "text": "Absent",
                    'background-color': "#cd727f",
                }]
            };
        }

        $scope.showFailureNotification = function (message) {
            $scope.showMessage = message;
            $scope.saveFailure = true;
            $timeout(function () {
                $scope.saveFailure = false;
            }, 5000);
        };
    }

})();;
