        $scope.viewRegistrationForm = function () {
            studentService.getStudentById(rollNumber, function (err, response) {
                if (!err) {
                    $('#studentWaitModal').modal('hide');
                    $('#completeStudentProfileInfo').modal({
                        backdrop: 'static',
                        keyboard: false
                    });

                    response.basic.dob = moment(response.basic.dob, 'YYYY-MM-DD').format('DD-MM-YYYY');
                    if (response.detailsToBeApproved) {
                        $scope.completeStudentRecord = JSON.parse(JSON.stringify(response.detailsToBeApproved));

                        if (!$scope.completeStudentRecord.languagesKnown || !$scope.completeStudentRecord.languagesKnown.data) {
                            $scope.completeStudentRecord.languagesKnown = { 'data': [] };
                        }

                        if ($scope.studentRecord.basic && $scope.studentRecord.basic.dob) {
                            $scope.studentRecord.basic.dob = moment($scope.studentRecord.basic.dob, 'YYYY-MM-DD').format('DD-MM-YYYY');
                        }

                        if ($scope.completeStudentRecord.community && $scope.completeStudentRecord.community.issuedDate) {
                            $scope.completeStudentRecord.community.issuedDate = moment($scope.completeStudentRecord.community.issuedDate, 'YYYY-MM-DD').format('DD-MM-YYYY');
                        }

                        if ($scope.completeStudentRecord.personal && $scope.completeStudentRecord.personal.visaExpiryDate) {
                            $scope.completeStudentRecord.personal.visaExpiryDate = moment($scope.completeStudentRecord.personal.visaExpiryDate, 'YYYY-MM-DD').format('DD-MM-YYYY');
                        }
                    }

                    $scope.completeStudentProfileForm = null;
                    $scope.isSentForVerification = true;
                }
            })
        }

        function trackRegistrationForm() {
            //this logic gives the names of the errored sections (only mandatory fields in FORM)
            var erroredSection = new Set();
            $scope.completeStudentProfileForm.$validationSummary.forEach(function (error) {
                var element = document.getElementsByName(error.field);
                var attributes = element[0].attributes;
                var classAttribute = attributes.getNamedItem("ng-model");
                var modelNameSplit = classAttribute.value.split('.')
                if (modelNameSplit[0] === 'lang') {
                    erroredSection.add('languagesKnown');
                    return;
                }

                erroredSection.add(modelNameSplit[1]);
            });

            //this logic marks the error/pass badge in UI
            var recordKeys = ['personal', 'family', 'additionalInformation', 'compExam', 'workExperience', 'bankDetails', 'education', 'contact', 'community', 'languagesKnown'];

            recordKeys.forEach(function (key) {
                //below code is to remove  error/pass badge
                if ($scope.completeStudentRecord[key]) {
                    delete $scope.completeStudentRecord[key].isSectionComplete;
                }

                if (!$scope.completeStudentRecord[key] || !$scope.completeStudentRecord[key].isVerified) {

                    if (!$scope.completeStudentRecord[key]) {
                        $scope.completeStudentRecord[key] = {}
                    }

                    if (erroredSection.has(key)) {
                        $scope.completeStudentRecord[key].isSectionComplete = false;
                    } else {
                        $scope.completeStudentRecord[key].isSectionComplete = true;
                    }

                }
            })
        }

        $rootScope.getGuide = function () {
            if ($scope.studentRecord.programType === "RESEARCH") {
                let query = {
                    // "status": "Active",
                    "isGuide": true,
                    "projection": {
                        "_id": 1,
                        "name": "$facultyName",
                        "facultyId": 1
                    }
                };
                remoteServices.getFaculties(query, function (err, res) {
                    if (!err) {
                        $scope.guideName = res;
                    }
                })
            }
        }

