        $scope.getParentDetails = function (parentsList, parentType, field) {

            var res = parentsList.find(function (parent) {
                if (parent.type == parentType) {
                    return true;
                }
            })

            if (res && res[field]) {
                return res[field];
            }

            return null;
        }

