        $scope.saveContactDetails = function (sectionName, formName, otherFormName) {
            $scope.recordToUpdate["contact"] = $scope.studentRecord.contact;
            updateStudentRecordSection(sectionName);
        }

        $scope.saveSectionItem = function (sectionName, formName, otherFormName) {
            var context = this;
            checkForDirtyFields.call(context);


            if (formName != 0) {
                $timeout(function () {
                    if (new ValidationService().checkFormValidity($scope[formName])) {
                        if (context.preSave) {
                            context.preSave();
                        }

                        $rootScope.showLoader = true;
                        if (context.isArray) {
                            if ($scope.sectionMode == "ADD_MODE") {
                                //add new item to the section
                                addStudentRecordSectionArray(sectionName, formName);
                            } else {
                                updateStudentRecordSection(sectionName, formName);
                            }
                        }
                        else {
                            updateStudentRecordSection(sectionName, formName);
                        }
                        $('.modal').modal('hide');
                        document.body.scrollTop = document.documentElement.scrollTop = 0;
                    } else {
                        $rootScope.showMessage();
                        $rootScope.showLoader = false;
                    }
                }, 700)
            }
            else {
                if (otherFormName) {
                    if (new ValidationService().checkFormValidity($scope[otherFormName])) {
                        $rootScope.showLoader = true;
                        if (context.isArray) {
                            if ($scope.sectionState == "ADD_MODE") {
                                //add new item to the section
                                addStudentRecordSectionArray(sectionName, otherFormName);
                            } else {
                                updateStudentRecordSection(sectionName, otherFormName);
                            }
                        }
                        else {
                            updateStudentRecordSection(sectionName, otherFormName);
                        }
                        $('.modal').modal('hide');
                        document.body.scrollTop = document.documentElement.scrollTop = 0;
                    }
                } else {
                    $rootScope.showLoader = true;
                    if (context.isArray) {
                        if ($scope.sectionState == "ADD_MODE") {
                            //add new item to the section
                            addStudentRecordSectionArray(sectionName);
                        } else {
                            updateStudentRecordSection(sectionName);
                        }
                    }
                    else {
                        updateStudentRecordSection(sectionName);
                    }
                    $('.modal').modal('hide');
                    document.body.scrollTop = document.documentElement.scrollTop = 0;
                }
            }
        };

        $scope.deleteSectionItem = function (sectionName, itemIndex) {
            //TODO get confirmation from user before deleting
            var criteria = {
                id: $scope.studentRecord.rollNumber,
                sectionName: sectionName,
                itemIndex: itemIndex,
            }
            studentService.deleteSectionItem(criteria, function (err, response) {
                if (!err) {
                    $rootScope.getStudentRecord();
                    $rootScope.showSuccessNotification();
                }
                else {
                    $rootScope.showLoader = false;
                    $rootScope.showFailureNotification();
                }
            });
        };

        function updateStudentRecordSection(sectionName, formName) {
            var editableSectionIndex = $scope.recordToUpdate[sectionName].itemIndex;
            var criteria = {
                id: $scope.studentRecord.rollNumber,
                sectionName: sectionName,
                studentRecord: $scope.studentRecord
            }
            if (sectionName == 'bankDetails') {
                delete $scope.recordToUpdate[sectionName].confirmAccNo;
            }
            var record = {};
            if (editableSectionIndex >= 0) {
                record = $scope.recordToUpdate[sectionName]
                criteria.itemIndex = editableSectionIndex;
                studentService.updateSectionByIndex(criteria, record, function (err, response) {
                    if (!err) {
                        $rootScope.showLoader = false;
                        $rootScope.getStudentRecord();
                        $rootScope.showSuccessNotification();
                        if (editableSectionIndex >= 0) {
                            //the updated section is an array, overwrite the section item in the given index
                            var indexToUpdate = -1;
                            for (var i = 0; i < $scope.studentRecord[sectionName].length; i++) {
                                if ($scope.studentRecord[sectionName][i].itemIndex == editableSectionIndex) {
                                    indexToUpdate = i;
                                }
                            }
                            $scope.studentRecord[sectionName][indexToUpdate] = $scope.recordToUpdate[sectionName];
                        } else {
                            //the updated section is not an array, overwrite the section details
                            $scope.studentRecord[sectionName] = $scope.recordToUpdate[sectionName];
                        }
                        $scope.unsavedAttachments.splice(0);
                        delete $scope.recordToUpdate[sectionName];

                        $scope.edit(sectionName, false);
                    }
                    else {
                        $rootScope.showLoader = false;
                        $rootScope.showFailureNotification();
                    }
                });
            }
            else {
                record[sectionName] = $scope.recordToUpdate[sectionName];
                studentService.updateStudentSection(criteria, record, function (err, response) {
                    if (!err) {
                        $rootScope.showLoader = false;
                        $rootScope.getStudentRecord();
                        $rootScope.showSuccessNotification();
                        if (editableSectionIndex >= 0) {
                            //the updated section is an array, overwrite the section item in the given index
                            var indexToUpdate = -1;
                            for (var i = 0; i < $scope.studentRecord[sectionName].length; i++) {
                                if ($scope.studentRecord[sectionName][i].itemIndex == editableSectionIndex) {
                                    indexToUpdate = i;
                                }
                            }
                            $scope.studentRecord[sectionName][indexToUpdate] = $scope.recordToUpdate[sectionName];
                        } else {
                            //the updated section is not an array, overwrite the section details
                            $scope.studentRecord[sectionName] = $scope.recordToUpdate[sectionName];
                        }
                        $scope.unsavedAttachments.splice(0);
                        delete $scope.recordToUpdate[sectionName];

                        $scope.edit(sectionName, false);
                    }
                    else {
                        $rootScope.showLoader = false;
                        $rootScope.showFailureNotification();
                    }
                });
            }

        }


        function addStudentRecordSectionArray(sectionName, formName) {
            //include the item index
            var sectionDetails = $scope.studentRecord[sectionName];
            var lastGeneratedItemIndex = 0;
            if (sectionDetails) {
                var secLen = sectionDetails.length;
                if (secLen) {
                    //increment max generated item index by 1 and assign for newly added item
                    lastGeneratedItemIndex = sectionDetails[secLen - 1].itemIndex + 1;
                }
            }
            $scope.recordToUpdate[sectionName].itemIndex = lastGeneratedItemIndex;
            var criteria = {
                id: $scope.studentRecord.rollNumber,
                sectionName: sectionName
            }
            var sectionRecord = JSON.parse(JSON.stringify($scope.recordToUpdate[sectionName]));
            studentService.addStudentSection(criteria, sectionRecord, function (err, response) {
                if (!err) {
                    $rootScope.showLoader = false;
                    $rootScope.getStudentRecord();
                    $rootScope.showSuccessNotification();
                    if (!$scope.studentRecord[sectionName]) {
                        //the updated section is not an array, overwrite the section details
                        $scope.studentRecord[sectionName] = [];
                    }
                    $scope.studentRecord[sectionName].push($scope.recordToUpdate[sectionName]);

                    $scope.unsavedAttachments.splice(0);
                    delete $scope.recordToUpdate[sectionName];

                    $scope.edit(sectionName, false);
                }
                else {
                    $rootScope.showLoader = false;
                    $rootScope.showFailureNotification();
                }
            });
        }

