        $scope.hideShowWithSec = function () {
            $scope.showAlert = false;

            setTimeout(function () {
                $scope.showAlert = true;
                $scope.$apply();
            }, 1000);

            $scope.isResendDisabled = true;
            $scope.resendSeconds = 15;
            if (resendInterval) {
                clearInterval(resendInterval);
                resendInterval = null;
            }

            resendInterval = setInterval(function () {
                $scope.resendSeconds--;
                if ($scope.resendSeconds <= 0) {
                    clearInterval(resendInterval);
                    resendInterval = null;
                    $scope.isResendDisabled = false;
                }
                $scope.$apply();
            }, 1000);
        }

