        $scope.passBookFirstPage = {
            dzOptions: {
                url: "#",
                method: "get",
                parallelUploads: 1,
                acceptedFiles: 'image/jpeg, images/jpg, image/png',
                autoProcessQueue: false,
                uploadMultiple: false,
                addRemoveLinks: true,
                maxFilesize: 0.5,
                paramName: function () {
                    return "passBookFirstPage";
                },
                maxFiles: 1,
                init: function () {
                    $scope.myDropzone = this;
                    this.on("addedfile", function (file) {
                    });
                },
                params: $scope.studentRecord,
                renameFile: function (file) {
                    file.upload.filename = file.name;
                },
                headers: {
                    Authorization: "Bearer " + $rootScope.Auth.token
                },
                accept: function (file) {
                    if (file.size > 512 * 1024) {
                        $scope.showFailureNotification("File size should be less than or equal to 512 KB");
                        this.removeFile(file);
                        return false;
                    }

                    $scope.uploadFileToS3(file, "passBookFirstPage", function (uploadErr, uploadRes) {
                        if (!uploadErr) {

                            $scope.uploadedDetails = {
                                id: uploadRes.signedRequest.filePath,
                                contentType: uploadRes.type,
                                filename: uploadRes.signedRequest.fileName,
                                originalname: uploadRes.name,
                                size: uploadRes.size
                            };

                            studentService.getDownloadUrl($scope.uploadedDetails, function (err, res) {
                                if (res && res.signedUrl) {
                                    $scope.completeStudentRecord.bankDetails.passBookFirstPage = $scope.uploadedDetails;
                                }
                            });

                        } else {
                            $scope.showFailureNotification(uploadErr);
                        }
                    });
                }

            },

            dzCallbacks: {
                init: function () {
                    this.on("addedfile", function (file) {
                    });
                },
                "error": function (file, errMsg) {

                    if (errMsg === "You can't upload files of this type.") {
                        $scope.fileTypeError = true;
                    } else if (errMsg.includes("File is too big")) {
                        $scope.fileSizeError = true;
                    }
                    $timeout(function () {
                        $scope.fileSizeError = false;
                    }, 10000);
                },

                "success": function (file, xhr) {
                },
                "removedfile": function (file) {
                }
            },

            dzMethods: {}
        };

        $scope.uploadFileToS3 = function (file, type, callback) {
            var query = {
                batchYear: $scope.studentRecord.batchYear,
                fileName: file.name,
                type: type
            }

            studentService.getUploadUrl(query, function (err, res) {
                if (res && res.signedUrl) {
                    studentService.uploadFilesToS3(res.signedUrl, file, function (error, result) {
                        if (!error) {
                            file.signedRequest = res;
                            callback(null, file);
                            return;
                        } else {
                            callback(error, null);
                            return;
                        }
                    });
                } else {
                    callback("Not able to upload", null);
                    return;
                }
            });
        };

